import Link from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
import InnerLink from '../../components/InnerLink';
const _not_found = {title: "Unknown", jsx: <><h2 id="magic-ring-not_found-error">Error</h2>
<p>Unable to find the requested magic ring.</p>
</>};
const _dungeon_ring_prisoners = {title: "Dungeon Ring (prisoner's)", jsx: <><h2 id="magic-ring-dungeon_ring_prisoners-dungeon-ring">Dungeon Ring</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 166</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 292</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 8th<br/><strong>Slot</strong> ring; <strong>Price</strong> 250 gp (prisoner's), 16,000 gp (jailer's); <strong>Weight</strong> -</p>
<p>A jailer's dungeon ring is worked gold, set with carnelians. The ring is magically attuned to one or more iron prisoner's dungeon rings. When the wearer of a jailer's ring places a prisoner's ring on a subject, the prisoner cannot remove the ring without the use of a <Link to="/spell/remove_curse">remove curse</Link>, <Link to="/spell/limited_wish">limited wish</Link>, <Link to="/spell/miracle">miracle</Link>, or <Link to="/spell/wish">wish</Link> spell. The wearer of the jailer's ring can also remove a linked prisoner's ring at any time.</p>
<p>The jailer is aware of any wearer of a linked prisoner's ring as per a constant <em>status</em> spell. Additionally, all wearers of linked prisoner's rings count as familiar to the jailer for the purposes of spells such as <em>scrying</em> and <Link to="/spell/teleport">teleport</Link>.</p>
<h3 id="magic-ring-dungeon_ring_prisoners-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/scrying">scrying</Link>, <Link to="/spell/status">status</Link>; <strong>Cost</strong> 125 gp (prisoner's), 8,000 gp (jailer's)</p>
</>};
const _ironbound_ring_minion = {title: "Ironbound Ring (Minion)", jsx: <><h2 id="magic-ring-ironbound_ring_minion-ironbound-ring">Ironbound Ring</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 36</Link><br/><strong>Aura</strong> faint abjuration and enchantment; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 500 gp (Minion), 8,000 gp (Master); <strong>Weight</strong> -</p>
<p>While holding one or more minion's ironbound rings, the wearer of a master's ironbound ring can impart instructions of 50 words or fewer to each minion's ironbound rings. The wearer of a minion's ironbound ring can recall the instructions at will and is aware of any action that would cause him to act against those instructions. The DC of any skill check attempted to force the wearer to abandon, misinterpret, or consciously fail the instructions increases by 5, such as for Bluff checks to trick the wearer or Intimidate checks to interrogate him. The wearer gains a +3 resistance bonus on Will saves to resist spells and effects that would force him to act against the instructions, such as <Link to="/spell/dominate_person">dominate person</Link> and <em>suggestion.</em></p>
<h3 id="magic-ring-ironbound_ring_minion-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/resistance">resistance</Link>, <Link to="/spell/suggestion">suggestion</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _fools_malady = {title: "Fool's Malady", jsx: <><h2 id="magic-ring-fools_malady-fools-malady">Fool's Malady</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 33</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 900 gp; <strong>Weight</strong> -</p>
<p>This simple lead ring is carved with a twisting face. When worn, the ring causes a wearer to develop a single deformity over the course of 1 minute. The exact malformation is determined when the ring is forged and can't be changed. It modifies the wearer's appearance rather than changing it entirely; those familiar with her normal appearance can easily recognize her in the modified form. Many of these rings mimic the symptoms of terrible diseases, while others mimic birth conditions, extensive scarring, or tattoos.</p>
<p>If the creature wearing a fool's malady already has the deformity the ring mimics, the ring instead removes all visual traces of the condition. The ring does not remove any pain or penalties associated with the condition.</p>
<h3 id="magic-ring-fools_malady-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/alter_self">alter self</Link>; <strong>Cost</strong> 450 gp</p>
</>};
const _kyton_ring = {title: "Kyton Ring", jsx: <><h2 id="magic-ring-kyton_ring-kyton-ring">Kyton Ring</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 216</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>This rusty iron ring looks like a twisted chain. On command, the ring can produce a rusty, clanky length of iron chain (hardness 10, 5 hp, break DC 26). The ring can create no more than 100 feet of chain in this way. This total length can be split among many uses, but must be spent in 10-foot increments. When the ring's daily allotment of chain is renewed, any previously conjured chain rusts away. Once per day as a standard action, the user can shoot a chain from the ring as though it were a <Link to="/eq-weapon/grappling_hook">grappling hook</Link>, except the range increment is 50 feet. Whatever length of chain she shoots out counts against ring's daily allotment.</p>
<h3 id="magic-ring-kyton_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/major_creation">major creation</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _ring_of_arcane_signets = {title: "Ring of Arcane Signets", jsx: <><h2 id="magic-ring-ring_of_arcane_signets-ring-of-arcane-signets">Ring of Arcane Signets</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 167</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 292</Link><br/><strong>Aura</strong> faint universal; <strong>CL</strong> 8th<br/><strong>Slot</strong> ring; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>The approximately 1-inch-diameter pentagon of emerald green crystal that dominates this otherwise plain silver ring forms itself into a specific rune, sigil, or similar identifying marker each time a person first puts it on. If the wearer expects this to occur, she can cause the crystal to adopt any shape she wishes. If the wearer does not expect this to occur, the crystal instead molds itself into an image that symbolizes the wearer or some dominant facet of her personality. Once the crystal assumes this initial form, it always takes that form whenever the same wearer puts on the ring. The wearer can, as a standard action, embed this image on any object (as if using <em>arcane mark</em>) simply by pressing the ring against it. The wearer may choose the color and other cosmetic features of the image each time she uses the ring. The brand is otherwise permanent unless removed by <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/erase">erase</Link>, or a more powerful spell.</p>
<h3 id="magic-ring-ring_of_arcane_signets-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/arcane_mark">arcane mark</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _ring_of_inurement = {title: "Ring of Inurement", jsx: <><h2 id="magic-ring-ring_of_inurement-ring-of-inurement">Ring of Inurement</h2>
<p><strong>Sources</strong> <Link to="/source/ire_of_the_storm">Ire of the Storm pg. 51</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> ring; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>This humble ring is crafted from smooth red and blue porcelain and wrapped with threads of copper. Each morning, the ring's wearer must select either hot or cold, and for the next 24 hours the ring of inurement affords basic protection from the selected condition as if she were using <em>endure elements</em> and superficially alters the wearer's clothing to better accommodate her, growing fur linings and extra layers in frigid environs or lightening fabric in response to high temperatures. The ring protects only the wearer who determined its properties for the day, and its protection immediately ends for the day if it is removed.</p>
<h3 id="magic-ring-ring_of_inurement-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/prestidigitation">prestidigitation</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _ring_of_the_faithful_dead = {title: "Ring of the Faithful Dead", jsx: <><h2 id="magic-ring-ring_of_the_faithful_dead-ring-of-the-faithful-dead">Ring of the Faithful Dead</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 42</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>This spiraling silver ring glows briefly when a living creature puts it on. If its wearer of a ring of the faithful dead is slain by a creature with the create spawn ability, the wearer does not rise as an undead creature, even if the ring is later removed. If a corpse is wearing a ring of the faithful dead, any attempts to create an undead creature from the corpse (such as via <Link to="/spell/animate_dead">animate dead</Link>) automatically fail, though simply removing the ring ends this protection.</p>
<h3 id="magic-ring-ring_of_the_faithful_dead-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/sanctify_corpse">sanctify corpse</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _riverclub_ring = {title: "Riverclub Ring", jsx: <><h2 id="magic-ring-riverclub_ring-riverclub-ring">Riverclub Ring</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River pg. 29</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> ring; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>Popular among Riverfolk who prefer to work their waterway unarmed, this simple bronze band can transform into a handy weapon in a pinch. When the wearer of a riverclub ring plunges her hand into at least 1 gallon of water as a move action, she can pull forth a club made of animated water. The weapon maintains the shape, solidity, and statistics of a <Link to="/rule/masterwork_w">masterwork</Link> <Link to="/eq-weapon/club">club</Link> of the wielder's size so long as she holds it, dealing damage as normal, except that it deals 1 additional point of damage against creatures with the fire subtype. The club turns back into a puddle of water again as soon as the wielder loosens her grip around it.</p>
<h3 id="magic-ring-riverclub_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/icicle_dagger">icicle dagger</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _ring_of_serene_contortions = {title: "Ring of Serene Contortions", jsx: <><h2 id="magic-ring-ring_of_serene_contortions-ring-of-serene-contortions">Ring of Serene Contortions</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 259</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 1,200 gp; <strong>Weight</strong> -</p>
<p>This simple copper ring bears the image of a blue enamel hand. It grants the wearer a +2 bonus on <Link to="/skill/escape_artist">Escape Artist</Link> checks. At will, the wearer may create the sound of a peaceful chime, small gong, or temple bell. Once per day, the wearer may also use <em>true strike.</em></p>
<h3 id="magic-ring-ring_of_serene_contortions-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/ghost_sound">ghost sound</Link>, <Link to="/spell/true_strike">true strike</Link>, creator must have 5 ranks in Escape Artist; <strong>Cost</strong> 600 gp</p>
</>};
const _dark_life_ring = {title: "Dark Life Ring", jsx: <><h2 id="magic-ring-dark_life_ring-dark-life-ring">Dark Life Ring</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption pg. 30</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 1,250 gp; <strong>Weight</strong> -</p>
<p>Mortal blacksmiths residing in the Gebbite city of Graydirge created the first dark life rings. Too often had these living unfortunates suffered collateral damage from the negative energy effects used daily in the streets of the undead-ruled city, so they forged these rings in hopes of mitigating at least some of the harm their unliving rulers carelessly inflicted upon them. Before the Blood Lords at Mechitar could punish the insolent smiths of Graydirge, the dark life rings and their imitators made their way into the wider world.</p>
<p>A dark life ring grants its wearer a +2 profane bonus on Will saving throws against <Link to="/ability/channel_negative_energy">channeled negative energy</Link> and <Link to="/main/inflict_spells">inflict spells</Link> (any spell with "inflict" in its name). In addition, anytime the wearer takes damage from channeled negative energy or an inflict spell, she subtracts 5 from the damage taken (calculated after the wearer has rolled her Will save against the effect), to a minimum of 0 points of damage.</p>
<h3 id="magic-ring-dark_life_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/death_ward">death ward</Link>; <strong>Cost</strong> 625 gp</p>
</>};
const _ring_of_resistance = {title: "Ring of Resistance", jsx: <><h2 id="magic-ring-ring_of_resistance-ring-of-resistance">Ring of Resistance</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_123_the_flooded_cathedral">Pathfinder #123: The Flooded Cathedral pg. 44</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 1,500 gp (+1), 6,000 gp (+2), 13,500 gp (+3), 24,000 gp (+4), 37,500 gp (+5); <strong>Weight</strong> -</p>
<p>Protective symbols adorn this magic ring. It functions as a <Link to="/magic-wondrous/cloak_of_resistance">cloak of resistance</Link> with an equivalent bonus.</p>
<h3 id="magic-ring-ring_of_resistance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/resistance">resistance</Link>, creator's caster level must be at least three times the ring's bonus; <strong>Cost</strong> 750 gp (+1), 3,000 gp (+2), 6,750 gp (+3), 12,000 gp (+4), 17,750 gp (+5)</p>
</>};
const _deadeyes_spotter_ring = {title: "Deadeye's Spotter Ring", jsx: <><h2 id="magic-ring-deadeyes_spotter_ring-deadeyes-spotter-ring">Deadeye's Spotter Ring</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 258</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 1,500 gp; <strong>Weight</strong> -</p>
<p>This ring is carved from a single, thick antler and fashioned into the shape of a regal elk's head. The wearer gains a +2 competence bonus on Perception and Survival checks. Once per day, the wearer can use <em>animal messenger.</em></p>
<h3 id="magic-ring-deadeyes_spotter_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/animal_messenger">animal messenger</Link>, creator must have 2 ranks in Perception and Survival; <strong>Cost</strong> 750 gp</p>
</>};
const _ring_of_spell_knowledge = {title: "Ring of Spell Knowledge", jsx: <><h2 id="magic-ring-ring_of_spell_knowledge-ring-of-spell-knowledge">Ring of Spell Knowledge</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 174</Link><br/><strong>Aura</strong> moderate or strong (no school); <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 1,500 gp (type I), 6,000 gp (type II), 13,500 gp (type III), 24,000 gp (type IV); <strong>Weight</strong> -</p>
<p>This ring comes in four types. All of them are useful only to spontaneous arcane spellcasters. Through study, the wearer can gain the knowledge of a single spell in addition to those allotted by her class and level. Type I can hold 1st-level spells only, type II 1st- or 2nd-level spells, type III spells of 3rd level or lower, and type IV up to 4th-level spells.</p>
<p>A ring of spell knowledge is only a storage space; the wearer must still encounter a written, active, or cast version of the spell and succeed at a DC 20 Spellcraft check to teach the spell to the ring. Thereafter, the arcane spellcaster may cast the spell as though she knew the spell and it appeared on her class' spell list.</p>
<p>Arcane spells that do not appear on the wearer's class list are treated as one level higher for all purposes (storage and casting).</p>
<h3 id="magic-ring-ring_of_spell_knowledge-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, creator must be able to cast spells of the spell level to be granted; <strong>Cost</strong> 750 gp (type I), 3,000 gp (type II), 6,750 gp (type III), 12,000 gp (type IV)</p>
</>};
const _ring_of_balanced_grip = {title: "Ring of Balanced Grip", jsx: <><h2 id="magic-ring-ring_of_balanced_grip-ring-of-balanced-grip">Ring of Balanced Grip</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 23</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 1,600 gp; <strong>Weight</strong> -</p>
<p>This sturdy ring allows the user to ignore the nonproficiency penalty for using a particular type of <Link to="/misc/improvised_weapon">improvised weapon</Link>, such as a crowbar or pitchfork, and grants a +1 enhancement bonus on attack rolls with that item as though it were a <Link to="/rule/masterwork_weapons">masterwork weapon</Link>.</p>
<h3 id="magic-ring-ring_of_balanced_grip-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/masterwork_transformation">masterwork transformation</Link>; <strong>Cost</strong> 800 gp</p>
</>};
const _ring_of_starlight = {title: "Ring of Starlight", jsx: <><h2 id="magic-ring-ring_of_starlight-ring-of-starlight">Ring of Starlight</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 12</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 1st<br/><strong>Slot</strong> ring; <strong>Price</strong> 1,600 gp; <strong>Weight</strong> -</p>
<p>This smooth mithral ring glimmers with light, and a close look reveals the reflection of a starry night sky within the silvery metal. The wearer of a ring of starlight can cause portions of her body or items in her possession to glow with colorful light, as per <em>faerie fire,</em> by waving the hand adorned with the ring over the item or body part as a swift action. This glow lasts for 1 hour, until dismissed as a free action, or until the ring is removed. This duration need not be used all at once, but must be used in 10-minute increments. (Each time an increment of duration is used, the wearer can choose the portion of her body or item in her possession that glows.) In addition, wearing the ring allows the caster to use <em>dancing lights</em> on command three times per day as a standard action.</p>
<h3 id="magic-ring-ring_of_starlight-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/dancing_lights">dancing lights</Link>, <Link to="/spell/faerie_fire">faerie fire</Link>; <strong>Cost</strong> 800 gp</p>
</>};
const _ring_of_protection = {title: "Ring of Protection", jsx: <><h2 id="magic-ring-ring_of_protection-ring-of-protection">Ring of Protection</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 172</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 2,000 gp (+1), 8,000 gp (+2), 18,000 gp (+3), 32,000 gp (+4), 50,000 gp (+5); <strong>Weight</strong> -</p>
<p>This ring offers continual magical protection in the form of a deflection bonus of +1 to +5 to AC.</p>
<h3 id="magic-ring-ring_of_protection-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>, caster must be of a level at least three times higher than the bonus of the ring; <strong>Cost</strong> 1,000 gp (+1), 4,000 gp (+2), 9,000 gp (+3), 16,000 gp (+4), 25,000 gp (+5)</p>
</>};
const _bloodletting_thimble = {title: "Bloodletting Thimble", jsx: <><h2 id="magic-ring-bloodletting_thimble-bloodletting-thimble">Bloodletting Thimble</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 237</Link>, <Link to="/source/blood_of_the_night">Blood of the Night pg. 31</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> -</p>
<p>This platinum thimble, intricately crafted in the shape of an animal claw, is worn on one finger. A <Link to="/template/vampire">vampire</Link> wearer can use the thimble to inflict a tiny wound as part of the use of a blood drain, energy drain, or drain chi ability; use of the thimble in this way isn't an action. This wound deals no additional damage, but it turns the target's pain to pleasure. The target must succeed at a DC 14 Will save or become <Link to="/misc/fascinated">fascinated</Link> by the wearer and make no attempt to resist the draining on that round and the following 2 rounds. At the end of this time, the creature's senses return and it can react accordingly.</p>
<h3 id="magic-ring-bloodletting_thimble-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/enthrall">enthrall</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _ring_of_lingering_blood_magic = {title: "Ring of Lingering Blood Magic", jsx: <><h2 id="magic-ring-ring_of_lingering_blood_magic-ring-of-lingering-blood-magic">Ring of Lingering Blood Magic</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 217</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> -</p>
<p>When the wearer of this ring is <Link to="/class/bloodrager">bloodraging</Link>, he can expend 1 round of bloodrage to extend the duration of a beneficial spell affecting him with a duration of 1 round per level or greater by 2 rounds. This is a free action the wearer can take once per round.</p>
<h3 id="magic-ring-ring_of_lingering_blood_magic-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/endurance">Endurance</Link>, <Link to="/feat/extend_spell">Extend Spell</Link>, <Link to="/feat/forge_ring">Forge Ring</Link>, creator must have the bloodrage class feature; <strong>Cost</strong> 1,000 gp</p>
</>};
const _ring_of_the_grasping_grave = {title: "Ring of the Grasping Grave", jsx: <><h2 id="magic-ring-ring_of_the_grasping_grave-ring-of-the-grasping-grave">Ring of the Grasping Grave</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 176</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 1st<br/><strong>Slot</strong> ring; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> -</p>
<p>The wearer of this ring can make a melee touch attack against an undead creature no more than one size category larger than himself, cutting off that creature from undying energy. The wearer never suffers any ill effects that might normally occur from coming into physical contact with an undead creature touched in this way. On a successful hit, the undead cannot be healed or aided by the effects of negative energy for 1d4 rounds. During this duration, positive energy affects the undead creature normally.</p>
<h3 id="magic-ring-ring_of_the_grasping_grave-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/sculpt_corpse">sculpt corpse</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _ring_of_feather_falling = {title: "Ring of Feather Falling", jsx: <><h2 id="magic-ring-ring_of_feather_falling-ring-of-feather-falling">Ring of Feather Falling</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 170</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> ring; <strong>Price</strong> 2,200 gp; <strong>Weight</strong> -</p>
<p>This ring is crafted with a feather pattern all around its edge. It acts exactly like a <em>feather fall</em> spell, and activates immediately if the wearer falls more than 5 feet.</p>
<h3 id="magic-ring-ring_of_feather_falling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/feather_fall">feather fall</Link>; <strong>Cost</strong> 1,100 gp</p>
</>};
const _ring_of_climbing = {title: "Ring of Climbing", jsx: <><h2 id="magic-ring-ring_of_climbing-ring-of-climbing">Ring of Climbing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 168</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> -</p>
<p>This magic ring has the deceptively simple appearance of a plain leather cord that wraps securely around a finger. The ring continually grants the wearer a +5 competence bonus on <Link to="/skill/climb">Climb</Link> checks.</p>
<h3 id="magic-ring-ring_of_climbing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, creator must have 5 ranks in the Climb skill; <strong>Cost</strong> 1,250 gp</p>
</>};
const _ring_of_jumping = {title: "Ring of Jumping", jsx: <><h2 id="magic-ring-ring_of_jumping-ring-of-jumping">Ring of Jumping</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 172</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 2nd<br/><strong>Slot</strong> ring; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> -</p>
<p>This ring continually allows the wearer to leap about, providing a +5 competence bonus on all her <Link to="/skill/acrobatics">Acrobatics</Link> checks made to make high or long jumps.</p>
<h3 id="magic-ring-ring_of_jumping-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, creator must have 5 ranks in Acrobatics; <strong>Cost</strong> 1,250 gp</p>
</>};
const _ring_of_sustenance = {title: "Ring of Sustenance", jsx: <><h2 id="magic-ring-ring_of_sustenance-ring-of-sustenance">Ring of Sustenance</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 175</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> -</p>
<p>This ring continually provides its wearer with life-sustaining nourishment. The ring also refreshes the body and mind; its wearer only needs to sleep 2 hours per day to gain the benefit of 8 hours of sleep. This allows a spellcaster that requires rest to prepare spells to do so after only 2 hours, but does not allow a spellcaster to prepare spells more than once per day. The ring must be worn for a full week before it begins to work. If it is removed, the owner must wear it for another week to reattune it to himself.</p>
<h3 id="magic-ring-ring_of_sustenance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/create_food_and_water">create food and water</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _ring_of_swimming = {title: "Ring of Swimming", jsx: <><h2 id="magic-ring-ring_of_swimming-ring-of-swimming">Ring of Swimming</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 175</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 2nd<br/><strong>Slot</strong> ring; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> -</p>
<p>This silver ring usually has fish-like designs and motifs etched into the band. It continually grants the wearer a +5 competence bonus on <Link to="/skill/swim">Swim</Link> checks.</p>
<h3 id="magic-ring-ring_of_swimming-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, creator must have 5 ranks in Swim; <strong>Cost</strong> 1,250 gp</p>
</>};
const _droskars_guiding_ring = {title: "Droskar's Guiding Ring", jsx: <><h2 id="magic-ring-droskars_guiding_ring-droskars-guiding-ring">Droskar's Guiding Ring</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 258</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 56</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 2,600 gp; <strong>Weight</strong> -</p>
<p>This gold ring is misshapen and uncomfortable to wear for long periods of time; inscribed on it is a crude symbol of a fire burning under an arch. Once per day, the wearer may use <em>charm person.</em> If <Link to="/faith/droskar">Droskar</Link> is the wearer's patron deity, any time the wearer crafts a magic item, she may choose to pay half of the item's construction cost instead of the full cost. The wearer spends time working on the item normally, but at the time of completion there is a 50% chance that the item turns out nonmagical and worthless. For example, if creating a magic bracer that normally costs 1,000 gp to craft, the wearer may craft it for only 500 gp, but there is a 50% chance the wearer's shortcuts and cheap materials result in a valueless, non-functional item.</p>
<h3 id="magic-ring-droskars_guiding_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/charm_person">charm person</Link>, <Link to="/spell/fabricate">fabricate</Link>; <strong>Cost</strong> 1,300 gp</p>
</>};
const _ring_of_natural_attunement_leshy = {title: "Ring of Natural Attunement (Leshy)", jsx: <><h2 id="magic-ring-ring_of_natural_attunement_leshy-ring-of-natural-attunement-leshy">Ring of Natural Attunement (Leshy)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 217</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 2,800 gp; <strong>Weight</strong> -</p>
<p>This ring is made of thin but strong vines braided together in an elegant weave. If the wearer can cast <em>summon nature's ally</em> spells, the wearer adds <Link to="/monster/leaf_leshy">leaf leshy</Link> to the 1st-level list of monsters he can summon with those spells, adds <Link to="/monster/gourd_leshy">gourd leshy</Link> to the 2nd-level list, adds <Link to="/monster/fungus_leshy">fungus leshy</Link> the 3rd-level list, and adds <Link to="/monster/seaweed_leshy">seaweed leshy</Link> to the 4th-level list. Also, once per day on command the wearer can use this ring to summon a <em>leaf leshy,</em> as if by the <em>summon nature's ally I</em> spell.</p>
<h3 id="magic-ring-ring_of_natural_attunement_leshy-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/plant_growth">plant growth</Link>, <Link to="/spell/summon_natures_ally_i">summon nature's ally I</Link>; <strong>Cost</strong> 1,400 gp</p>
</>};
const _knight_inheritors_ring = {title: "Knight-Inheritor's Ring", jsx: <><h2 id="magic-ring-knight_inheritors_ring-knight-inheritors-ring">Knight-Inheritor's Ring</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_103_the_hellfire_compact">Pathfinder #103: The Hellfire Compact pg. 73</Link>, <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 258</Link><br/><strong>Aura</strong> faint enchantment and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> -</p>
<p>This simple gold band is engraved with the holy symbol of <Link to="/faith/iomedae">Iomedae</Link>. It functions as a <Link to="/magic-ring/ring_of_protection_1">ring of protection +1</Link>. In addition, the wearer can cast <em>bless weapon</em> and <em>wartrain mount</em> each once per day. At will, the wearer can make himself presentable as if using <em>prestidigitation</em> to clean up his clothing, skin, hair, and armor.</p>
<h3 id="magic-ring-knight_inheritors_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/bless_weapon">bless weapon</Link>, <Link to="/spell/prestidigitation">prestidigitation</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>, <Link to="/spell/wartrain_mount">wartrain mount</Link>, creator must be at least 3rd level; <strong>Cost</strong> 1,500 gp</p>
</>};
const _profane_seal_signet = {title: "Profane Seal Signet", jsx: <><h2 id="magic-ring-profane_seal_signet-profane-seal-signet">Profane Seal Signet</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 259</Link><br/><strong>Aura</strong> faint abjuration, enchantment, and universal; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> -</p>
<p>This ring is made of red gold with a single ruby cut into a pentagon shape. It functions as a <Link to="/magic-ring/ring_of_protection_1">ring of protection +1</Link>. In addition, the wearer may use <em>arcane mark</em> at will, but only on objects and willing creatures. Once per day, the wearer may use <em>wrath.</em></p>
<h3 id="magic-ring-profane_seal_signet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/arcane_mark">arcane mark</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>, <Link to="/spell/wrath">wrath</Link>, creator must be at least 3rd level; <strong>Cost</strong> 1,500 gp</p>
</>};
const _ring_of_austere_majesty = {title: "Ring of Austere Majesty", jsx: <><h2 id="magic-ring-ring_of_austere_majesty-ring-of-austere-majesty">Ring of Austere Majesty</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 19</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> -</p>
<p>A dozen tiny gemstones line the outer edges of this golden ring. As long as one or more creatures can see it, the ring grants its wearer a +2 circumstance bonus on Diplomacy and Intimidate checks to influence those creatures. In addition, the wearer can allow a willing creature to inspect the ring as a full-round action. If she does, for the following 3 rounds the creature and the wearer can speak while the ring's power obfuscates the details of the conversation. To every other creature able to hear the creature and the wearer's words during this time, the conversation sounds like a continued back-and-forth exchange of exaltations about the ring's artistry.</p>
<h3 id="magic-ring-ring_of_austere_majesty-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/aphasia">aphasia</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _ring_of_ferocious_action = {title: "Ring of Ferocious Action", jsx: <><h2 id="magic-ring-ring_of_ferocious_action-ring-of-ferocious-action">Ring of Ferocious Action</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 170</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 58</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> -</p>
<p>This ring allows its wearer to persevere through physical or mental trauma that hampers his actions. Once per day, when the wearer gains the <Link to="/misc/staggered">staggered</Link> condition from an enemy's attack, she can ignore that condition for up to 5 rounds. This does not prevent her from gaining the staggered condition again, and it does not protect her if she gained the staggered condition multiple times.</p>
<h3 id="magic-ring-ring_of_ferocious_action-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/haste">haste</Link>, <Link to="/spell/stabilize">stabilize</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _ring_of_powerful_blood_magic = {title: "Ring of Powerful Blood Magic", jsx: <><h2 id="magic-ring-ring_of_powerful_blood_magic-ring-of-powerful-blood-magic">Ring of Powerful Blood Magic</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 218</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> -</p>
<p>When the wearer of this ring is <Link to="/class/bloodrager">bloodraging</Link> and casts a spell, as a swift action he can increase the save DC of the spell by 1. The wearer can do this a maximum of three times per day. This has no effect on spells that do not require saving throws.</p>
<h3 id="magic-ring-ring_of_powerful_blood_magic-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/feat/spell_focus">Spell Focus</Link>, creator must have the bloodrage class feature; <strong>Cost</strong> 1,500 gp</p>
</>};
const _tyrants_friend = {title: "Tyrant's Friend", jsx: <><h2 id="magic-ring-tyrants_friend-tyrants-friend">Tyrant's Friend</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 54</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> -</p>
<p>A slender copper band, a tyrant's friend is thin enough to be hidden beneath another ring (although it still counts against the limit of magic rings a character can wear). The ring grows noticeably warmer whenever the hand wearing it touches a poisoned or poisonous object or creature (including containers holding poison), warning the wearer of potential danger.</p>
<h3 id="magic-ring-tyrants_friend-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/detect_poison">detect poison</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _ring_of_eloquence = {title: "Ring of Eloquence", jsx: <><h2 id="magic-ring-ring_of_eloquence-ring-of-eloquence">Ring of Eloquence</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 217</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> -</p>
<p>Fine etchings spell out the alphabets of four languages around the inside of this finely crafted silver band. The wearer gains the ability to speak and understand the four languages whose alphabets are inscribed on the ring. Normally the languages are Common, Dwarven, Elven, and Gnome. Less often, such rings are attuned to Giant, Goblin, Orc, and Undercommon, and rings with different sets of languages might also exist. The wearer retains the ability to speak in these languages even if she assumes a form normally unable to do so (such as a <Link to="/class/druid">druid</Link> wild shaped into a wolf).</p>
<p>The ring also makes it easier for the wearer to find the correct words to express herself, granting a +2 competence bonus on Bluff, Diplomacy, Intimidate, and Perform (oratory) checks. Also, if the wearer is <Link to="/misc/deafened">deafened</Link> and attempts to cast a spell with a verbal component, the chance of spell failure is reduced to 10%.</p>
<h3 id="magic-ring-ring_of_eloquence-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/comprehend_languages">comprehend languages</Link>; <strong>Cost</strong> 1,750 gp</p>
</>};
const _ring_of_stairs_and_stars = {title: "Ring of Stairs and Stars", jsx: <><h2 id="magic-ring-ring_of_stairs_and_stars-ring-of-stairs-and-stars">Ring of Stairs and Stars</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 259</Link><br/><strong>Aura</strong> faint evocation, illusion, and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 3,820 gp; <strong>Weight</strong> -</p>
<p>A stair-step pattern of stars wraps around the outside of this dark blue ring. In addition to the powers of a <Link to="/magic-ring/ring_of_feather_falling">ring of feather falling</Link>, a ring of stairs and stars allows the wearer to use <em>magic missile</em> once per day, with the missiles taking the shape of shooting stars. As a standard action, the wearer may create an illusory butterfly that flits about within the wearer's square for 1 minute before fading away.</p>
<h3 id="magic-ring-ring_of_stairs_and_stars-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/feather_fall">feather fall</Link>, <Link to="/spell/magic_missile">magic missile</Link>, <Link to="/spell/silent_image">silent image</Link>; <strong>Cost</strong> 1,910 gp</p>
</>};
const _ring_of_ancestral_blood_magic = {title: "Ring of Ancestral Blood Magic", jsx: <><h2 id="magic-ring-ring_of_ancestral_blood_magic-ring-of-ancestral-blood-magic">Ring of Ancestral Blood Magic</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 216</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> ring; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> -</p>
<p>While the wearer is <Link to="/class/bloodrager">bloodraging</Link>, he can cast a bonus spell gained from his bloodrager bloodline without expending a spell slot. He can do this three times per day, and must expend a number of rounds of bloodrage equal to the level of the spell to be cast. The wearer must meet all the other requirements for spellcasting.</p>
<h3 id="magic-ring-ring_of_ancestral_blood_magic-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/endurance">Endurance</Link>, <Link to="/feat/extend_spell">Extend Spell</Link>, <Link to="/feat/forge_ring">Forge Ring</Link>, creator must have the bloodrage class feature; <strong>Cost</strong> 2,000 gp</p>
</>};
const _ring_of_counterspells = {title: "Ring of Counterspells", jsx: <><h2 id="magic-ring-ring_of_counterspells-ring-of-counterspells">Ring of Counterspells</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 168</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> -</p>
<p>Upon first examination, this ring seems to be a <Link to="/magic-ring/ring_of_spell_storing">ring of spell storing</Link>. However, while it allows a single spell of 1st through 6th level to be cast into it, that spell cannot be cast out of the ring again. Instead, should that spell ever be cast upon the wearer, the spell is immediately countered, as a <Link to="/rule/counterspells">counterspell</Link> action, requiring no action (or even knowledge) on the wearer's part. Once so used, the spell cast within the ring is gone. A new spell (or the same one as before) may be placed into it again.</p>
<h3 id="magic-ring-ring_of_counterspells-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/imbue_with_spell_ability">imbue with spell ability</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _ring_of_planar_focus = {title: "Ring of Planar Focus", jsx: <><h2 id="magic-ring-ring_of_planar_focus-ring-of-planar-focus">Ring of Planar Focus</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 49</Link><br/><strong>Aura</strong> strong divination; <strong>CL</strong> 15th<br/><strong>Slot</strong> ring; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> -</p>
<p>This large silver ring has a massive setting for a cloudy white crystal about an inch in diameter. Once per week as a standard action, the wearer can tap the ring with a forked rod attuned to a specific plane (the focus for a <Link to="/spell/plane_shift">plane shift</Link> spell). When tapped, the crystal transforms into a rough topographical map of the plane in question for 1 minute. The wearer can manipulate the crystal to focus on a single specific location within the plane, although the topographical elements remain rough and display only large or well-known features around the desired location. If the wearer has been to that location personally, she can focus the crystal on the location in 1 full round. Otherwise, she can attempt a DC 15 Knowledge (planes) check to focus on a location of her choice as a full-round action. This location must be a public or well-known area, such as a public plaza in the Common Quarter in the City of Brass. Obscure locations (such as <Link to="/faith/calistria">Calistria's</Link> private Garden of Hidden Fruits) or locations controlled by a divinity cannot be focused on - in all cases, the GM has final say on whether a region can be focused upon.</p>
<p>If the wearer casts <em>plane shift</em> to travel to the focused location while the map is active, she arrives without error at the site, rather than 5d% miles away. Once a ring of planar focus is used to aid a casting of <em>plane shift,</em> it becomes inactive for 24 hours.</p>
<h3 id="magic-ring-ring_of_planar_focus-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/discern_location">discern location</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _ring_of_seven_lovely_colors = {title: "Ring of Seven Lovely Colors", jsx: <><h2 id="magic-ring-ring_of_seven_lovely_colors-ring-of-seven-lovely-colors">Ring of Seven Lovely Colors</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 259</Link><br/><strong>Aura</strong> faint abjuration and illusion; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> -</p>
<p>This golden ring, set with seven brightly colored gems, functions as a <Link to="/magic-ring/ring_of_protection_1">ring of protection +1</Link>. In addition, seven times per day, the wearer can use <em>beast shape IV</em> to transform into a songbird for 10 minutes (use statistics for a <Link to="/monster/raven">raven</Link>).</p>
<h3 id="magic-ring-ring_of_seven_lovely_colors-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/beast_shape_iv">beast shape IV</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>, creator must be at least 3rd level; <strong>Cost</strong> 2,000 gp</p>
</>};
const _saltspray_ring = {title: "Saltspray Ring", jsx: <><h2 id="magic-ring-saltspray_ring-saltspray-ring">Saltspray Ring</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_121_the_lost_outpost">Pathfinder #121: The Lost Outpost pg. 54</Link><br/><strong>Aura</strong> faint conjuration and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> -</p>
<p>This <Link to="/eq-material/mithral">mithral</Link> ring is engraved with a pattern of rolling waves that encircles the entire band. The saltspray ring is immune to rust, both from natural oxidation and rust caused by magical effects.</p>
<p>Upon command, the ring causes a thick vapor to continuously surround its owner as per <em>obscuring mist,</em> except the mist has a 10-foot radius from the wearer and the area of effect moves with the wearer. This mist is exceedingly wet and extinguishes all nonmagical fires within its area. Magical fires and creatures with the fire subtype are not dispelled or adversely affected by the mist, though such creatures find being in the fog to be an uncomfortable experience. The mist does not permit aquatic creatures without the amphibious special quality to breathe out of water, but creatures that must remain wet or suffer a negative effect or condition have that requirement satisfied by the ring's effect. This effect can be dismissed as a standard action. The ring has no effect whatsoever underwater.</p>
<h3 id="magic-ring-saltspray_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/obscuring_mist">obscuring mist</Link>, <Link to="/spell/quench">quench</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _red_hound_ring = {title: "Red Hound Ring", jsx: <><h2 id="magic-ring-red_hound_ring-red-hound-ring">Red Hound Ring</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 259</Link><br/><strong>Aura</strong> faint abjuration, conjuration, and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 4,700 gp; <strong>Weight</strong> -</p>
<p>This white gold ring is engraved with the images of a mastiff and a thundercloud. It functions as a <Link to="/magic-ring/ring_of_protection_1">ring of protection +1</Link>. In addition, once per day, the wearer may use <em>summon monster I</em> to summon a red mastiff (use statistics for a celestial dog). Additionally, once per day the wearer may use <em>beast shape I</em> to transform into a Small red mastiff.</p>
<h3 id="magic-ring-red_hound_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>, <Link to="/spell/summon_monster_i">summon monster I</Link>, creator must be at least 3rd level; <strong>Cost</strong> 2,350 gp</p>
</>};
const _ring_of_delayed_doom = {title: "Ring of Delayed Doom", jsx: <><h2 id="magic-ring-ring_of_delayed_doom-ring-of-delayed-doom">Ring of Delayed Doom</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 292</Link>, <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 169</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 5,000 gp (1 stone), 10,000 gp (2 stones), 15,000 gp (3 stones), 20,000 gp (4 stones), 25,000 gp (5 stones), 30,000 gp (6 stones), 35,000 gp (7 stones), 40,000 gp (8 stones), 45,000 gp (9 stones); <strong>Weight</strong> -</p>
<p>This band has nine garnets embedded along its exterior. Whenever the wearer's mind or body first becomes subject to any harmful effect that allows a saving throw to resist or mitigate it, he may, as an immediate action, choose to delay the onset of that effect for 1 minute, after he fails the saving throw but before its effects occur. This activation causes one of the garnets to turn to powder. When that minute passes, the wearer may continue to delay the onset of this harmful effect an additional minute as an immediate action by willing the ring to do so, which destroys another garnet, thus repeating the cycle for another minute. The delayed harmful effect occurs when the wearer falls unconscious, when the ring is removed, or 1 minute after the last time the ring's power activated; rounds spent delaying the effect do not count toward the effect's duration (for example, a curse that lasts 5 rounds takes effect for a full 5 rounds, even if the wearer delayed its effect several minutes). Effects that protect against or negate the harmful effect work normally while it is delayed, for example, <Link to="/spell/neutralize_poison">neutralize poison</Link> cast on the wearer while he delays the effect of a poisonous bite removes the poison effect.</p>
<h3 id="magic-ring-ring_of_delayed_doom-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/heal">heal</Link>, <Link to="/spell/time_stop">time stop</Link>; <strong>Cost</strong> 22,500 gp</p>
</>};
const _gluttonous_feasting_ring = {title: "Gluttonous Feasting Ring", jsx: <><h2 id="magic-ring-gluttonous_feasting_ring-gluttonous-feasting-ring">Gluttonous Feasting Ring</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 258</Link><br/><strong>Aura</strong> faint necromancy and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> -</p>
<p>This ring is carved from the flat part of a human skull and inscribed along the edge with images of skeletons at a banquet. Any food the wearer eats or drinks is automatically cleansed as if by <em>purify food and drink.</em> Once per day after eating an extravagant meal (typically one worth at least 10 gp), the wearer gains the benefit of <em>false life.</em></p>
<h3 id="magic-ring-gluttonous_feasting_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/false_life">false life</Link>, <Link to="/spell/purify_food_and_drink">purify food and drink</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _ring_of_maniacal_devices = {title: "Ring of Maniacal Devices", jsx: <><h2 id="magic-ring-ring_of_maniacal_devices-ring-of-maniacal-devices">Ring of Maniacal Devices</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 172</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 292</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> -</p>
<p>This elaborately decorated ring is crafted with the design of a fierce dragon wrapped greedily around a shining gemstone. It grants the wearer a +5 competence bonus on all <Link to="/skill/craft">Craft (traps)</Link> and <Link to="/skill/disable_device">Disable Device</Link> checks. Even if he has no ranks in these skills, the wearer may make Craft (traps) and Disable Device checks as if he were trained in them.</p>
<h3 id="magic-ring-ring_of_maniacal_devices-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, creator must have 5 ranks in the relevant skill; <strong>Cost</strong> 2,500 gp</p>
</>};
const _ring_of_rat_fangs = {title: "Ring of Rat Fangs", jsx: <><h2 id="magic-ring-ring_of_rat_fangs-ring-of-rat-fangs">Ring of Rat Fangs</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 172</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 155</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> -</p>
<p>This bone ring is the shape of an elongated rat biting its own tail. The wearer gains a bite attack as a primary <Link to="/umr/natural_attack">natural attack</Link>. This attack deals 1d4 points of piercing damage for a Medium wearer or 1d3 points of damage for a Small wearer. After about a week of wearing the ring, the wearer's appearance becomes more rat-like, though she still looks like a member of her original race (for example, a human might gain prominent teeth).</p>
<h3 id="magic-ring-ring_of_rat_fangs-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/magic_fang">magic fang</Link>, <Link to="/spell/polymorph">polymorph</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _glorious_flame_ring = {title: "Glorious Flame Ring", jsx: <><h2 id="magic-ring-glorious_flame_ring-glorious-flame-ring">Glorious Flame Ring</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 258</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 5,400 gp; <strong>Weight</strong> -</p>
<p>This richly colored, burnished brass ring appears to be crimson red, sunset orange, or golden yellow depending on how it is held. Clerics of <Link to="/faith/sarenrae">Sarenrae</Link> prize glorious flame rings as facets through which they may channel their deity's divine will. Once per day, the wearer may speak the ring's command word to create a 5-foot-radius <Link to="/misc/burst">burst</Link> of flame centered on herself. This burst of flame deals 1d6 points of damage to any adjacent creatures (Reflex DC 14 halves), though the wearer is safe from this effect.</p>
<p>If the wearer is capable of <Link to="/ability/channel_positive_energy">channeling positive energy</Link>, she may as a standard action expend one use of channeled energy to activate the ring's burst of flame, even if she has already spoken the ring's command word for the day. If the wearer also has the Selective Channeling feat, she may select a number of allies equal to her Charisma modifier to exclude from the burst of flame; these allies are not affected by the flame. This effect is otherwise identical to creating the ring's burst of flame by speaking the command word.</p>
<h3 id="magic-ring-glorious_flame_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/feat/selective_channeling">Selective Channeling</Link>, <Link to="/spell/elemental_aura">elemental aura</Link> (fire), creator must be able to channel positive energy; <strong>Cost</strong> 2,700 gp</p>
</>};
const _ring_of_vengeful_blood_magic = {title: "Ring of Vengeful Blood Magic", jsx: <><h2 id="magic-ring-ring_of_vengeful_blood_magic-ring-of-vengeful-blood-magic">Ring of Vengeful Blood Magic</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 220</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 5,400 gp; <strong>Weight</strong> -</p>
<p>This claw ring is made of red metal tinged with orange, and a long nail made of obsidian extends from the tip. It allows its wearer to cast a spell as an attack of opportunity. Three time per day, if the wearer is <Link to="/class/bloodrager">bloodraging</Link> and a foe provokes an attack of opportunity from him, the wearer can cast a spell with a casting time of 1 standard action or less as the attack of opportunity. The spell must target the creature that provoked the attack or include it in the spell's area, and must be no higher than 3rd level. This counts as one of the wearer's attacks of opportunity for the round; casting this spell does not itself provoke an attack of opportunity.</p>
<h3 id="magic-ring-ring_of_vengeful_blood_magic-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/combat_reflexes">Combat Reflexes</Link>, <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/feat/quicken_spell">Quicken Spell</Link>; <strong>Cost</strong> 17,500 gp</p>
</>};
const _communique_rings = {title: "Communique Rings", jsx: <><h2 id="magic-ring-communique_rings-communique-rings">Communique Rings</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 241</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> ring; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>Created in pairs, these simple golden rings allow for short-range communication between the wearers. The listed and cost are for both rings. As long as the wearers are within 1 mile of one another, they can communicate by whispering, causing the other ring to whisper the words to the recipient. Words spoken into or recited by a communique ring can be heard by nearby creatures if the wearer speaks too loudly. A communique ring transmits sound only while worn, and a wearer can remove the ring if she needs to be silent. Only magical silence or distance will block this communication, and wearers can speak through walls and other obstructions normally. The rings pick up only sound directly spoken into them by the wearer with the intent to transmit, not ambient sounds or the voices of other creatures.</p>
<h3 id="magic-ring-communique_rings-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/message">message</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _ring_of_far_strike = {title: "Ring of Far Strike", jsx: <><h2 id="magic-ring-ring_of_far_strike-ring-of-far-strike">Ring of Far Strike</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 29</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> ring; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>This unassuming black ring changes color to a silver pearlescent sheen when held near a fire. Once per day as a standard action, the wearer can make a melee weapon attack or unarmed strike attack against any opponent within 30 feet. The wearer must be otherwise capable of performing the attack to use this ability.</p>
<h3 id="magic-ring-ring_of_far_strike-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/mage_hand">mage hand</Link>, <Link to="/spell/spectral_hand">spectral hand</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _ring_of_return = {title: "Ring of Return", jsx: <><h2 id="magic-ring-ring_of_return-ring-of-return">Ring of Return</h2>
<p><strong>Sources</strong> <Link to="/source/qadira_jewel_of_the_east">Qadira, Jewel of the East pg. 9</Link>, <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 173</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> ring; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>The imperial intelligence agency, the Hatharat, entrusts rings of return to agents within Taldor and other hostile regions. When a transport command word is spoken (a standard action), a ring of return whisks the wearer to the nearest imperial administration building within Kelesh's borders, as if via <em>greater teleport.</em> If anyone attempts to remove a ring of return from the wearer's finger without speaking a removal command word (a standard action that provokes an attack of opportunity), the attempt triggers the effect, transporting both the wearer and the person attempting to remove the ring. A successful DC 20 Will save allows a character to resist the teleportation, but in any event, a ring of return can be used only once; after its single charge is expended, it becomes an ordinary, nonmagical ring.</p>
<h3 id="magic-ring-ring_of_return-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/greater_teleport">greater teleport</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _ring_of_sacred_mistletoe = {title: "Ring of Sacred Mistletoe", jsx: <><h2 id="magic-ring-ring_of_sacred_mistletoe-ring-of-sacred-mistletoe">Ring of Sacred Mistletoe</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 173</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> ring; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>This tiny ring of living mistletoe coils about the wearer's finger of its own accord. The wearer gains a +2 competence bonus on <Link to="/skill/handle_animal">Handle Animal</Link>, <Link to="/skill/knowledge_nature">Knowledge (nature)</Link>, and <Link to="/ability/wild_empathy">wild empathy</Link> checks, and a wearer with the <Link to="/ability/woodland_stride">woodland stride</Link> ability can move effortlessly, without harm or impediment, even through magically created or manipulated plants. This does not allow the wearer to move through solid objects or creatures.</p>
<p>Furthermore, the wearer can use <em>shillelagh</em> once per day.</p>
<h3 id="magic-ring-ring_of_sacred_mistletoe-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/pass_without_trace">pass without trace</Link>, <Link to="/spell/shillelagh">shillelagh</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _ring_of_sundering_metals = {title: "Ring of Sundering Metals", jsx: <><h2 id="magic-ring-ring_of_sundering_metals-ring-of-sundering-metals">Ring of Sundering Metals</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 259</Link><br/><strong>Aura</strong> faint abjuration and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>This iron ring's head is shaped like a gilded anvil. In addition to the usual powers of a <Link to="/magic-ring/ring_of_ferocious_action">ring of ferocious action</Link>, the wearer can expend 1 charge from a ring of sundering metals to magically imbue a single wielded metal melee weapon with cold iron or silver. For 1 minute, the imbued weapon can bypass either DR/cold iron or DR/silver.</p>
<h3 id="magic-ring-ring_of_sundering_metals-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/haste">haste</Link>, <Link to="/spell/magic_weapon">magic weapon</Link>, <Link to="/spell/stabilize">stabilize</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _ring_of_swarming_stabs = {title: "Ring of Swarming Stabs", jsx: <><h2 id="magic-ring-ring_of_swarming_stabs-ring-of-swarming-stabs">Ring of Swarming Stabs</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 175</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 155</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>This ring is crafted of hardened leather strips, into which bits of fur, feathers, bone, and ivory have been woven. Twice per day, when the wearer is <Link to="/rule/flanking">flanking</Link> an opponent, he can as a swift action deal an additional 1d6 points of damage on a successful melee attack against that opponent. This is a <Link to="/ability/sneak_attack">sneak attack</Link> for any effects that reduce or negate such damage.</p>
<h3 id="magic-ring-ring_of_swarming_stabs-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/guidance">guidance</Link>, creator must be able to sneak attack; <strong>Cost</strong> 3,000 gp</p>
</>};
const _ring_of_unquenchable_passions = {title: "Ring of Unquenchable Passions", jsx: <><h2 id="magic-ring-ring_of_unquenchable_passions-ring-of-unquenchable-passions">Ring of Unquenchable Passions</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 259</Link><br/><strong>Aura</strong> faint abjuration and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 6,500 gp; <strong>Weight</strong> -</p>
<p>This gold ring bears three dagger-shaped marks. It functions as a <Link to="/magic-ring/ring_of_protection_1">ring of protection +1</Link>. In addition, it grants a +5 competence bonus on <Link to="/skill/acrobatics">Acrobatics</Link> checks and a +2 resistance bonus on saving throws against disease.</p>
<h3 id="magic-ring-ring_of_unquenchable_passions-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/resistance">resistance</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>, creator must have 5 ranks in Acrobatics, creator must be at least 3rd level; <strong>Cost</strong> 3,250 gp</p>
</>};
const _ring_of_grit_mastery = {title: "Ring of Grit Mastery", jsx: <><h2 id="magic-ring-ring_of_grit_mastery-ring-of-grit-mastery">Ring of Grit Mastery</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 171</Link><br/><strong>Aura</strong> faint abjuration and evocation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 6,840 gp; <strong>Weight</strong> -</p>
<p>This ring is made out of fused firearm bullets, making it a chunky but overall impressive ring. Twice per day, as a free action, when the wearer regains grit, she can choose to store it in the ring of grit mastery instead of regaining the grit point. She can store up to 2 grit points within the ring in this way. She can spend the grit points stored in the ring either of the following ways.</p>
<p>Once per day, without the need to take an action to do so, the wearer can spend 1 grit point stored in the ring to grant herself a +2 insight bonus to initiative.</p>
<p>Once per day, as a standard action, the wearer of the ring can spend 2 grit points stored within the ring to activate a <em>bullet shield</em> as the spell.</p>
<p>Any grit points stored in the ring disappear at the start of each day.</p>
<h3 id="magic-ring-ring_of_grit_mastery-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/anticipate_peril">anticipate peril</Link>, <Link to="/spell/bullet_shield">bullet shield</Link>, creator must have the grit class feature; <strong>Cost</strong> 3,420 gp</p>
</>};
const _ring_of_summoning_affinity_archon = {title: "Ring of Summoning Affinity (Archon)", jsx: <><h2 id="magic-ring-ring_of_summoning_affinity_archon-ring-of-summoning-affinity-archon">Ring of Summoning Affinity (Archon)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 218</Link><br/><strong>Aura</strong> faint conjuration [good, law]; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 7,000 gp; <strong>Weight</strong> -</p>
<p>This ring is made of hammered steel. If the wearer can cast <em>summon monster</em> spells, the wearer adds <Link to="/monster/harbinger_archon">harbingers</Link> to the 3rd-level list of monsters he can summon with those spells, adds <Link to="/monster/legion_archon">legion archon</Link> to the 6th-level list, and adds <Link to="/monster/shield_archon">shield archon</Link> to the 7th-level list. Also, once per day on command the wearer can use this ring to summon a harbinger, as if by the <Link to="/spell/summon_monster_iii">summon monster III</Link> spell.</p>
<h3 id="magic-ring-ring_of_summoning_affinity_archon-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>, creator must be neutral good; <strong>Cost</strong> 3,500 gp</p>
</>};
const _ring_of_summoning_affinity_angel = {title: "Ring of Summoning Affinity (Angel)", jsx: <><h2 id="magic-ring-ring_of_summoning_affinity_angel-ring-of-summoning-affinity-angel">Ring of Summoning Affinity (Angel)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 218</Link><br/><strong>Aura</strong> faint conjuration [good]; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 7,200 gp; <strong>Weight</strong> -</p>
<p>This ring is cut from transparent crystal. If the wearer can cast <em>summon monster</em> spells, the wearer adds <Link to="/monster/cassisian">cassisian</Link> to the 3rd-level list of monsters she can summon with those spells, adds <Link to="/monster/movanic_deva">movanic deva</Link> to the 7th-level list, and adds <Link to="/monster/monadic_deva">monadic deva</Link> to the 8th-level list. Also, once per day on command the wearer can use this ring to summon a cassisian, as if by the <Link to="/spell/summon_monster_iii">summon monster III</Link> spell.</p>
<h3 id="magic-ring-ring_of_summoning_affinity_angel-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>, creator must be good; <strong>Cost</strong> 3,600 gp</p>
</>};
const _ring_of_summoning_affinity_protean = {title: "Ring of Summoning Affinity (Protean)", jsx: <><h2 id="magic-ring-ring_of_summoning_affinity_protean-ring-of-summoning-affinity-protean">Ring of Summoning Affinity (Protean)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 219</Link><br/><strong>Aura</strong> faint conjuration [chaos]; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 7,200 gp; <strong>Weight</strong> -</p>
<p>This ring is made from an opalescent material that is never the same color twice. If the wearer can cast <em>summon monster</em> spells, the wearer adds <Link to="/monster/voidworm">voidworm</Link> to the 3rd-level list of monsters she can summon with those spells, adds <Link to="/monster/naunet">naunet</Link> to the 6th-level list, and adds <Link to="/monster/imentesh">imentesh</Link> to the 9th-level list. Also, once per day on command the wearer can use this ring to summon a voidworm, as if by the <Link to="/spell/summon_monster_iii">summon monster III</Link> spell.</p>
<h3 id="magic-ring-ring_of_summoning_affinity_protean-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>, creator must be chaotic neutral; <strong>Cost</strong> 3,600 gp</p>
</>};
const _ring_of_summoning_affinity_kyton = {title: "Ring of Summoning Affinity (Kyton)", jsx: <><h2 id="magic-ring-ring_of_summoning_affinity_kyton-ring-of-summoning-affinity-kyton">Ring of Summoning Affinity (Kyton)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 219</Link><br/><strong>Aura</strong> faint conjuration [evil, law]; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 7,300 gp; <strong>Weight</strong> -</p>
<p>This iron ring has several sharp barbs. If the wearer can cast <em>summon monster</em> spells, the wearer adds <Link to="/monster/augur">augur</Link> to the 3rd-level list of monsters he can summon with those spells, adds <Link to="/monster/sacristan">sacristan</Link> to the 7th-level list, and adds <Link to="/monster/interlocutor">interlocutor</Link> to the 9th-level list. Also, once per day on command the wearer can use this ring to summon an augur, as if by the <Link to="/spell/summon_monster_iii">summon monster III</Link> spell.</p>
<h3 id="magic-ring-ring_of_summoning_affinity_kyton-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>, creator must be lawful evil; <strong>Cost</strong> 3,650 gp</p>
</>};
const _ring_of_summoning_affinity_asura = {title: "Ring of Summoning Affinity (Asura)", jsx: <><h2 id="magic-ring-ring_of_summoning_affinity_asura-ring-of-summoning-affinity-asura">Ring of Summoning Affinity (Asura)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 218</Link><br/><strong>Aura</strong> faint conjuration [evil, law]; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 7,600 gp; <strong>Weight</strong> -</p>
<p>This ring is made of intricately marked brass. If the wearer can cast <em>summon monster</em> spells, the wearer adds <Link to="/monster/tripurasura">tripurasura</Link> to the 3rd-level list of monsters he can summon with those spells, adds <Link to="/monster/adhukait">adhukait</Link> to the 6th-level list, adds <Link to="/monster/upasunda">upasunda</Link> to the 7th-level list, and adds <Link to="/monster/aghasura">aghasura</Link> to the 8th-level list. Also, once per day on command the wearer can use this ring to summon a tripurasura, as if by the <Link to="/spell/summon_monster_iii">summon monster III</Link> spell.</p>
<h3 id="magic-ring-ring_of_summoning_affinity_asura-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>, creator must be lawful evil; <strong>Cost</strong> 3,800 gp</p>
</>};
const _ring_of_summoning_affinity_psychopomp = {title: "Ring of Summoning Affinity (Psychopomp)", jsx: <><h2 id="magic-ring-ring_of_summoning_affinity_psychopomp-ring-of-summoning-affinity-psychopomp">Ring of Summoning Affinity (Psychopomp)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 219</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 7,600 gp; <strong>Weight</strong> -</p>
<p>This silver ring is marked with a skull emblem. If the wearer can cast <em>summon monster</em> spells, the wearer adds <Link to="/monster/nosoi">nosoi</Link> to the 3rd-level list of monsters he can summon with those spells, adds <Link to="/monster/catrina">catrina</Link> to the 4th-level list, adds <Link to="/monster/vanth">vanth</Link> to the 6th-level list, and adds <Link to="/monster/morrigna">morrigna</Link> to the 9th-level list. Also, once per day on command the wearer can use this ring to summon a nosoi, as if by the <Link to="/spell/summon_monster_iii">summon monster III</Link> spell.</p>
<h3 id="magic-ring-ring_of_summoning_affinity_psychopomp-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>, creator must be neutral with no other alignment components; <strong>Cost</strong> 3,800 gp</p>
</>};
const _ring_of_summoning_affinity_agathion = {title: "Ring of Summoning Affinity (Agathion)", jsx: <><h2 id="magic-ring-ring_of_summoning_affinity_agathion-ring-of-summoning-affinity-agathion">Ring of Summoning Affinity (Agathion)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 218</Link><br/><strong>Aura</strong> faint conjuration [good]; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 7,700 gp; <strong>Weight</strong> -</p>
<p>This ring is forged from electrum and inlaid with runes. If the wearer can cast <em>summon monster</em> spells, the wearer adds <Link to="/monster/silvanshee">silvanshee</Link> to the 3rd-level list of monsters she can summon with those spells, adds <Link to="/monster/vulpinal">vulpinal</Link> to the 5th-level list, adds <Link to="/monster/avoral">avoral</Link> to the 7th-level list, and adds <Link to="/monster/leonal">leonal</Link> to the 8th-level list. Also, once per day on command the wearer can use this ring to summon a silvanshee, as if by the <Link to="/spell/summon_monster_iii">summon monster III</Link> spell.</p>
<h3 id="magic-ring-ring_of_summoning_affinity_agathion-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>, creator must be neutral good; <strong>Cost</strong> 3,850 gp</p>
</>};
const _ring_of_culturemeld = {title: "Ring of Culturemeld", jsx: <><h2 id="magic-ring-ring_of_culturemeld-ring-of-culturemeld">Ring of Culturemeld</h2>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion pg. 5</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 7,800 gp; <strong>Weight</strong> -</p>
<p>This ornately carved <Link to="/spell/ironwood">ironwood</Link> ring is sometimes gifted to half-elves leaving their elven communities so as to ease transition into human culture. A ring of culturemeld slightly alters the wearer's words to be more appropriate to the listener's culture and expectations, granting the wearer a +5 competence bonus on language-based Diplomacy checks.</p>
<p>If worn by a half-elf, a ring of culturemeld grants the wearer the ability to speak and understand an additional language dependent on the local area. If the wearer spends 1 day in a settlement the size of a village or larger, the ring becomes attuned to any dominant language spoken there other than Common (such as Hallit, Skald, or Vudrani). After the ring is attuned, the wearer gains that language as a bonus language (if she didn't already know it), though she can only speak and understand it. After 4 more days of attunement, the wearer gains the ability to read the language as well, though not the ability to write that language, and gains a +5 competence bonus on opposed Sense Motive checks against speakers of the attuned language. These benefits expire once the wearer has been out of contact with people who speak the attuned language for longer than 1 day or when the ring becomes attuned to a new language.</p>
<h3 id="magic-ring-ring_of_culturemeld-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/comprehend_languages">comprehend languages</Link>; <strong>Cost</strong> 3,900 gp</p>
</>};
const _ring_of_natural_attunement_kami = {title: "Ring of Natural Attunement (Kami)", jsx: <><h2 id="magic-ring-ring_of_natural_attunement_kami-ring-of-natural-attunement-kami">Ring of Natural Attunement (Kami)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 217</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 7,800 gp; <strong>Weight</strong> -</p>
<p>This ring carved from a single piece of cherry wood bears an inscription written in Tien. If the wearer can cast <em>summon nature's ally</em> spells, the wearer adds <Link to="/monster/shikigami">shikigami</Link> to the 3rd-level list of monsters he can summon with those spells, adds <Link to="/monster/kodama">kodama</Link> to the 5th-level list, adds <Link to="/monster/zuishin">zuishin</Link> to the 7th-level list, and adds <Link to="/monster/toshigami">toshigami</Link> to the 9th-level list. Also, once per day on command the wearer can use this ring to summon a shikigami, as if by the <em>summon nature's ally III</em> spell.</p>
<h3 id="magic-ring-ring_of_natural_attunement_kami-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/commune_with_nature">commune with nature</Link>, <Link to="/spell/summon_natures_ally_iii">summon nature's ally III</Link>; <strong>Cost</strong> 3,900 gp</p>
</>};
const _ring_of_summoning_affinity_aeon = {title: "Ring of Summoning Affinity (Aeon)", jsx: <><h2 id="magic-ring-ring_of_summoning_affinity_aeon-ring-of-summoning-affinity-aeon">Ring of Summoning Affinity (Aeon)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 218</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 7,800 gp; <strong>Weight</strong> -</p>
<p>This ring is forged from black iron and shining silver. If the wearer can cast <em>summon monster</em> spells, he adds <Link to="/monster/paracletus">paracletus</Link> to the 3rd-level list of monsters he can summon, adds <Link to="/monster/theletos">theletos</Link> to the 6th-level list, and adds <Link to="/monster/akhana">akhana</Link> to the 9th-level list. Also, once per day the wearer summon a paracletus, as if by the <Link to="/spell/summon_monster_iii">summon monster III</Link> spell.</p>
<h3 id="magic-ring-ring_of_summoning_affinity_aeon-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>, creator must be neutral with no other alignment components; <strong>Cost</strong> 3,900 gp</p>
</>};
const _ring_of_the_godless = {title: "Ring of the Godless", jsx: <><h2 id="magic-ring-ring_of_the_godless-ring-of-the-godless">Ring of the Godless</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands pg. 29</Link><br/><strong>Aura</strong> faint abjuration and divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,000 gp (+1), 17,000 gp (+2), 27,000 gp (+3), 38,000 gp (+4), 50,000 gp (+5); <strong>Weight</strong> -</p>
<p>These rings are said to have first been forged in Rahadoum by the Council of Elders to help root out the hidden faithful and other practitioners of the divine. A ring of the godless grants a luck bonus on saving throws against divine spells. This bonus does not apply to spell-like or supernatural abilities unless they are class abilities of a divine spellcasting class, such as <Link to="/ability/channel_energy">channel energy</Link> or <Link to="/ability/domains">domain</Link> powers, or unless they are used by a creature that has been called, created, or summoned by divine magic. The wearer's spell resistance (if any) increases by an amount equal to the ring's luck bonus, though this increase applies only against divine spells (and spell-like abilities as described above).</p>
<p>A ring of the godless also allows the wearer to use <em>detect magic</em> at will, though it detects only divine magic. In addition, the wearer can use a specialized form of <em>arcane sight</em> a number of times per day equal to the ring's luck bonus. This ability can be activated as a swift action, its effect lasts until the end of the wearer's turn, and it detects only divine magic or divine spellcasting ability.</p>
<h3 id="magic-ring-ring_of_the_godless-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/arcane_sight">arcane sight</Link>, <Link to="/spell/detect_magic">detect magic</Link>, <Link to="/spell/spell_resistance">spell resistance</Link>, creator cannot be a divine spellcaster, creator must be of a level at least three times higher than the bonus of the ring; <strong>Cost</strong> 4,000 gp (+1), 8,500 gp (+2), 13,500 gp (+3), 19,000 gp (+4), 25,000 gp (+5)</p>
</>};
const _maintenance_overseers_ring = {title: "Maintenance Overseer's Ring", jsx: <><h2 id="magic-ring-maintenance_overseers_ring-maintenance-overseers-ring">Maintenance Overseer's Ring</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 15</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 4th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>This tarnished signet is marked as belonging to a specific city no smaller than a large town, though it functions in any settlement of at least that size. After spending 5 days in a settlement with the maintenance overseer's ring equipped, its wearer learns a great deal about the schematics of any sewers, tunnels, basements, and passages beneath the settlement. This knowledge is not necessarily absolute, but allows the wearer to act as though trained in <Link to="/skill/knowledge_dungeoneering">Knowledge (dungeoneering)</Link> when answering questions about the settlement's underground with a +5 bonus on all such checks.</p>
<p>A maintenance overseer's ring also grants the wearer an automatic <Link to="/skill/perception">Perception</Link> check to notice secret doors within 10 feet in any area beneath street level of a city to which the ring is attuned. A wearer who already receives a Perception check to perceive a secret door (such as a <Link to="/race/dwarf">dwarf</Link> using stonecunning) rolls her Perception check twice and takes the better result.</p>
<h3 id="magic-ring-maintenance_overseers_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/create_treasure_map">create treasure map</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _ring_of_forcefangs = {title: "Ring of Forcefangs", jsx: <><h2 id="magic-ring-ring_of_forcefangs-ring-of-forcefangs">Ring of Forcefangs</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 171</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 292</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>This band negates any force spell or force spell-like ability targeted at the wearer. Doing so gives the ring a number of charges equal to the spell level of the incoming force effect. The ring can hold a maximum of 9 charges. If an incoming force attack would charge the ring beyond this limit, the ring does not negate the attack or gain charges, and the attack affects the wearer normally. On command, the wearer can use the ring's charges to cast <em>magic missile,</em> unleashing one missile (1d4+1 force damage) per charge but no more than five missiles per round.</p>
<h3 id="magic-ring-ring_of_forcefangs-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/feat/heighten_spell">Heighten Spell</Link>, <Link to="/spell/magic_missile">magic missile</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _ring_of_heroes = {title: "Ring of Heroes", jsx: <><h2 id="magic-ring-ring_of_heroes-ring-of-heroes">Ring of Heroes</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 325</Link><br/><strong>Aura</strong> moderate (no school); <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>Sculpted in the shape of two noble looking bronze lions charging toward a centrally placed garnet, this ring grants the wearer the Luck of Heroes feat. The ring must be worn for 24 hours before it takes effect. The wearer can also call upon the ring's power to gain a hero point that must be used immediately, although this causes the ring to lose its powers permanently.</p>
<h3 id="magic-ring-ring_of_heroes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/feat/luck_of_heroes">Luck of Heroes</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _ring_of_mind_shielding = {title: "Ring of Mind Shielding", jsx: <><h2 id="magic-ring-ring_of_mind_shielding-ring-of-mind-shielding">Ring of Mind Shielding</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 172</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>This ring is usually of fine workmanship and wrought from heavy gold. The wearer is continually immune to <Link to="/spell/detect_thoughts">detect thoughts</Link>, <Link to="/spell/discern_lies">discern lies</Link>, and any attempt to magically discern her alignment.</p>
<h3 id="magic-ring-ring_of_mind_shielding-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/nondetection">nondetection</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _ring_of_strength_sapping = {title: "Ring of Strength Sapping", jsx: <><h2 id="magic-ring-ring_of_strength_sapping-ring-of-strength-sapping">Ring of Strength Sapping</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 174</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>This ring is made of black steel and is eerily cold to the touch. Once per day as a swift action, when the wearer hits a living creature with an unarmed attack, the target must succeed at a DC 20 Fortitude saving throw or take 1d4 point of <Link to="/rule/strength_damage">Strength damage</Link> in addition to the attack's normal damage. If the target of the attack takes any Strength damage from this attack, the ring's wearer gains a +2 enhancement bonus to her Strength for 1 minute.</p>
<h3 id="magic-ring-ring_of_strength_sapping-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/ray_of_enfeeblement">ray of enfeeblement</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _ring_of_the_beast = {title: "Ring of the Beast", jsx: <><h2 id="magic-ring-ring_of_the_beast-ring-of-the-beast">Ring of the Beast</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 53</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>Three types of rings of the beast exist; all three appear as yellowed bone carved in the shapes of wild beasts devouring their own tails. The type of beast depicted on each ring depends on the ring's nature, but could be a wolf (ring of the relentless beast), a rhinoceros (ring of the savage beast), or a tiger (ring of the swift beast). Once per day, a ring of the beast can be activated as a standard action to unleash the primal spirit hidden inside even the most peaceful creatures. When the ring is activated, the wearer gains a bonus to a single physical attribute and a penalty to a single mental attribute for 10 minutes, as determined by the type of ring. A ring of the relentless beast grants a +4 enhancement bonus to Constitution and a -2 penalty to Charisma. A ring of the savage beast grants a +4 enhancement bonus to Strength and a -2 penalty to Intelligence. A ring of the swift beast grants a +4 enhancement bonus to Dexterity and a -2 penalty to Wisdom. As long as the effects of this ring are active, the wearer also gains a +2 enhancement bonus to his natural armor bonus.</p>
<h3 id="magic-ring-ring_of_the_beast-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/barkskin">barkskin</Link> and either <Link to="/spell/bears_endurance">bear's endurance</Link> (ring of the relentless beast), <Link to="/spell/bulls_strength">bull's strength</Link> (ring of the savage beast), or <Link to="/spell/cats_grace">cat's grace</Link> (ring of the swift beast); <strong>Cost</strong> 4,000 gp</p>
</>};
const _society_ring = {title: "Society Ring", jsx: <><h2 id="magic-ring-society_ring-society-ring">Society Ring</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 201</Link><br/><strong>Aura</strong> faint abjuration, divination, illusion, and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>The flat bezel of this signet ring is typically set with a semiprecious gem. If the wearer of the ring is successfully inducted into a group or organization through an initiation ritual, the ring becomes attuned to that organization and wearer. A suitable initiation ritual takes at least 10 minutes and at the very least involves a pledge of allegiance to the group or organization, but it can take a variety of forms. The crest or symbol of the organization appears engraved on the gem, and the ring becomes invisible (as per <em>invisibility</em>) and hidden from scrying effects (as per <em>obscure object</em>) to all except those who also wear society rings attuned to the same organization (referred to below as "similar rings"). Creatures that are capable of seeing invisible objects, such as via <Link to="/spell/see_invisibility">see invisibility</Link>, can still perceive a society ring.</p>
<p>Once attuned, the society ring's wearer can communicate with wearers of similar rings within 150 feet (as per <em>message</em>). It also grants +10 competence bonuses on Bluff checks to pass secret messages to members of the attuned organization and Sense Motive checks to receive secret messages from them. In addition, if the wearer touches his society ring to a similar ring, for the following hour, the wearer can sense the direction and distance to that ring, as well as any conditions affecting its wearer (as per <em>status</em>). Only one ring at a time can be linked in this way; if the wearer touches his ring to another similar ring within the duration of the effect, the status effect switches to the most recently touched ring.</p>
<p>If a society ring is worn or carried by a creature other than the attuned wearer, the ring silently alerts attuned ring wearers from the same organization within 1 mile (as per <em>alarm</em>), does not display the crest or symbol of the attuned organization, and glows with a red aura visible only to wearers of similar rings. A new owner can end this effect by becoming initiated into any organization, at which point the ring attunes to the new wearer and organization.</p>
<h3 id="magic-ring-society_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/alarm">alarm</Link>, <Link to="/spell/hidden_speech">hidden speech</Link>, <Link to="/spell/invisibility">invisibility</Link>, <Link to="/spell/message">message</Link>, <Link to="/spell/obscure_object">obscure object</Link>, <Link to="/spell/status">status</Link>, creator must have at least 10 ranks in both Bluff and Sense Motive; <strong>Cost</strong> 4,000 gp</p>
</>};
const _soultether_ring = {title: "Soultether Ring", jsx: <><h2 id="magic-ring-soultether_ring-soultether-ring">Soultether Ring</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 49</Link><br/><strong>Aura</strong> strong necromancy; <strong>CL</strong> 17th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>When the wearer of this delicate platinum ring dies, his soul remains adrift in the River of Souls and does not proceed to its final judgment in the Boneyard. Until the soultether ring is removed from the corpse, the time limit for restoring the creature to life via spells such as <Link to="/spell/raise_dead">raise dead</Link> or <Link to="/spell/resurrection">resurrection</Link> is suspended. This ring has no effect if it is placed upon a corpse; it must be worn at the time the creature dies to tether its soul. <Link to="/family/psychopomp">Psychopomps</Link> and other followers of <Link to="/faith/pharasma">Pharasma</Link> consider soultether rings to be sacrilegious, and the creatures destroy the rings whenever possible.</p>
<h3 id="magic-ring-soultether_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>; <Link to="/spell/soul_bind">soul bind</Link> or <Link to="/spell/true_resurrection">true resurrection</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _ring_of_summoning_affinity_inevitable = {title: "Ring of Summoning Affinity (Inevitable)", jsx: <><h2 id="magic-ring-ring_of_summoning_affinity_inevitable-ring-of-summoning-affinity-inevitable">Ring of Summoning Affinity (Inevitable)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 219</Link><br/><strong>Aura</strong> faint conjuration [law]; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,100 gp; <strong>Weight</strong> -</p>
<p>This ring resembles a gear or cog. If the wearer can cast <em>summon monster</em> spells, the wearer adds <Link to="/monster/arbiter">arbiter</Link> to the 3rd-level list of monsters she can summon with those spells, adds <Link to="/monster/zelekhut">zelekhut</Link> to the 7th-level list, adds <Link to="/monster/kolyarut">kolyarut</Link> to the 8th-level list, and adds <Link to="/monster/marut">marut</Link> to the 9th-level list. Also, once per day on command the wearer can use this ring to summon an arbiter, as if by the <Link to="/spell/summon_monster_iii">summon monster III</Link> spell.</p>
<h3 id="magic-ring-ring_of_summoning_affinity_inevitable-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>, creator must be lawful neutral; <strong>Cost</strong> 4,050 gp</p>
</>};
const _band_of_toxic_nullification = {title: "Band of Toxic Nullification", jsx: <><h2 id="magic-ring-band_of_toxic_nullification-band-of-toxic-nullification">Band of Toxic Nullification</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 30</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,500 gp; <strong>Weight</strong> -</p>
<p>This platinum band has a smoky quartz set neatly into it. Once per day, the wearer can speak a command word and place the quartz on her skin as a full-round action to siphon a single dose of poison from her body and into the quartz, rendering the poison inert. This effect can be used only after the wearer has been poisoned.</p>
<h3 id="magic-ring-band_of_toxic_nullification-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/absorb_toxicity">absorb toxicity</Link>; <strong>Cost</strong> 4,250 gp</p>
</>};
const _contract_rings = {title: "Contract Rings", jsx: <><h2 id="magic-ring-contract_rings-contract-rings">Contract Rings</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions pg. 29</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,500 gp; <strong>Weight</strong> -</p>
<p>Contract rings are crafted in pairs (the price is for both rings), establishing a connection between the wearers. Each wearer must wear their ring for 24 hours before they begin to work. Contract rings grant a +10 competence bonus on <Link to="/skill/sense_motive">Sense Motive</Link> checks made against the other wearer, and creatures wearing linked contract rings can understand each other's language.</p>
<p>Once per day, Contract rings can seal a contract. The two wearers join hands and willingly state what each is agreeing to. Once both agree, each wearer accepts a <em>lesser geas</em> (no save) to fulfill the terms of the contract. This function does not occur if either character is under a mind-affecting effect or threat that forces her agreement. This compulsion lasts 7 days, starting immediately. While the <em>lesser geas</em> remains in effect, neither wearer can remove her ring, and neither ring can establish another <em>lesser geas.</em> If either ring is destroyed, the effects of any active <em>lesser geas</em> remain for both creatures, but the surviving ring becomes non-functional once the <em>lesser geas</em> expires until the missing ring is repaired or replaced. If one wearer's <em>lesser geas</em> is broken, the other wearer's is removed.</p>
<h3 id="magic-ring-contract_rings-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>, <Link to="/spell/lesser_geas">lesser geas</Link>, <Link to="/spell/share_language">share language</Link>; <strong>Cost</strong> 4,250 gp</p>
</>};
const _ring_of_force_shield = {title: "Ring of Force Shield", jsx: <><h2 id="magic-ring-ring_of_force_shield-ring-of-force-shield">Ring of Force Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 171</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,500 gp; <strong>Weight</strong> -</p>
<p>This ring generates a shield-sized (and shield-shaped) wall of force that stays with the ring and can be wielded by the wearer as if it were a <Link to="/eq-armor/heavy_shield">heavy shield</Link> (+2 AC). This special creation has no armor check penalty or arcane spell failure chance since it is weightless and encumbrance-free. It can be activated and deactivated at will as a free action.</p>
<h3 id="magic-ring-ring_of_force_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/wall_of_force">wall of force</Link>; <strong>Cost</strong> 4,250 gp</p>
</>};
const _ring_of_summoning_affinity_qlippoth = {title: "Ring of Summoning Affinity (Qlippoth)", jsx: <><h2 id="magic-ring-ring_of_summoning_affinity_qlippoth-ring-of-summoning-affinity-qlippoth">Ring of Summoning Affinity (Qlippoth)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 220</Link><br/><strong>Aura</strong> faint conjuration [chaos, evil]; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,600 gp; <strong>Weight</strong> -</p>
<p>This ring has an odd, disquieting texture that always reveals greater layers of complexity the more closely it is examined. If the wearer can cast <em>summon monster</em> spells, the wearer adds <Link to="/monster/cythnigot">cythnigot</Link> to the 3rd-level list of monsters he can summon with those spells, adds <Link to="/monster/shoggti">shoggti</Link> to the 6th-level list, adds <Link to="/monster/nyogoth">nyogoth</Link> to the 7th-level list, adds <Link to="/monster/chernobue">chernobue</Link> to the 8th-level list, and adds <Link to="/monster/augnagar">augnagar</Link> to the 9th-level list. Also, once per day on command the wearer can use this ring to summon a cythnigot, as if by the <Link to="/spell/summon_monster_iii">summon monster III</Link> spell.</p>
<h3 id="magic-ring-ring_of_summoning_affinity_qlippoth-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>, creator must be chaotic evil; <strong>Cost</strong> 4,300 gp</p>
</>};
const _ring_of_the_ram = {title: "Ring of the Ram", jsx: <><h2 id="magic-ring-ring_of_the_ram-ring-of-the-ram">Ring of the Ram</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 176</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,600 gp; <strong>Weight</strong> -</p>
<p>A ring of the ram has a setting crafted to resemble a ram's head. The wearer can command the ring to give forth a ram-like force, manifested by a vaguely discernible shape that resembles the head of a ram or a goat. This force strikes a single target, dealing 1d6 points of damage if 1 charge is expended, 2d6 points if 2 charges are used, or 3d6 points if 3 charges (the maximum) are used. Treat this as a ranged attack with a 50-foot maximum range and no penalties for distance.</p>
<p>The force of the blow is considerable, and those struck by the ring are subject to a <Link to="/rule/bull_rush">bull rush</Link> if within 30 feet of the ring wearer. The ram is Large and uses the ring's caster level as its base attack bonus, with a Strength of 25. This gives the ram a Combat Maneuver Bonus of +17. The ram gains a +1 bonus on the bull rush attempt if 2 charges are expended, or +2 if 3 charges are expended.</p>
<p>In addition to its attack mode, the ring of the ram also has the power to open doors as if it were a character with a Strength score of 25. This usage expends 1 charge. If 2 charges are expended, the effect is equivalent to a character with a Strength score of 27. If 3 charges are expended, the effect is that of a character with Strength score of 29. A newly created ring has 50 charges. When all the charges are expended, the ring becomes a nonmagical item.</p>
<h3 id="magic-ring-ring_of_the_ram-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/telekinesis">telekinesis</Link>; <strong>Cost</strong> 4,300 gp</p>
</>};
const _scholars_ring = {title: "Scholar's Ring", jsx: <><h2 id="magic-ring-scholars_ring-scholars-ring">Scholar's Ring</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 177</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 8,700 gp; <strong>Weight</strong> -</p>
<p>A scholar's ring grants complete understanding of any written text or spoken language, even one that the wearer has never encountered before (as the <em>comprehend languages</em> spell), as well as a +5 competence bonus on <Link to="/skill/knowledge_history">Knowledge (history)</Link> checks.</p>
<p>In addition, once every 5 days the wearer can invoke a <em>legend lore</em> spell related to a subject that she has been studying in the previous week, if she has attempted a Knowledge (history) check aided by the ring.</p>
<h3 id="magic-ring-scholars_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/comprehend_languages">comprehend languages</Link>, <Link to="/spell/legend_lore">legend lore</Link>; <strong>Cost</strong> 4,350 gp</p>
</>};
const _ring_of_protected_life = {title: "Ring of Protected Life", jsx: <><h2 id="magic-ring-ring_of_protected_life-ring-of-protected-life">Ring of Protected Life</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook pg. 29</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This silver ring features arboreal motifs, and is set with a small but brilliant sapphire. If the wearer has the <Link to="/ability/channel_energy">channel energy</Link> class feature, the radius of his channeled energy increases by 5 feet. Additionally, when the wearer channels energy, he may choose to exempt one creature from the effects of his channeling. If the wearer has the Selective Channeling feat, the ring of protected life increases the number of creatures he may normally exempt by one. Finally, once per day the wearer may channel energy as a swift action that does not provoke attacks of opportunity; doing so renders the ring of protected life inert for 24 hours, during which time it does not confer any benefits.</p>
<h3 id="magic-ring-ring_of_protected_life-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/feat/selective_channeling">Selective Channeling</Link>, creator must have the channel energy class feature; <strong>Cost</strong> 4,500 gp</p>
</>};
const _rings_of_friend_finding = {title: "Rings of Friend-Finding", jsx: <><h2 id="magic-ring-rings_of_friend_finding-rings-of-friend-finding">Rings of Friend-Finding</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions pg. 29</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> -</p>
<p>These specialized rings are sold in pairs and help allies find one another. Each of the wearers must wear the rings for 24 hours before they function, after which each wearer can activate her ring of friend-finding as a standard action, enabling her to determine the direction, distance, and general condition of the wearer of the other ring as a <em>status</em> spell.</p>
<h3 id="magic-ring-rings_of_friend_finding-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>, <Link to="/spell/status">status</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _ring_of_summoning_affinity_div = {title: "Ring of Summoning Affinity (Div)", jsx: <><h2 id="magic-ring-ring_of_summoning_affinity_div-ring-of-summoning-affinity-div">Ring of Summoning Affinity (Div)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 219</Link><br/><strong>Aura</strong> faint conjuration [chaos, evil]; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 9,100 gp; <strong>Weight</strong> -</p>
<p>This ring is shaped to resemble a snake consuming its own tail. If the wearer can cast <em>summon monster</em> spells, the wearer adds <Link to="/monster/doru">doru</Link> to the 3rd-level list of monsters he can summon with those spells, adds <Link to="/monster/aghash">aghash</Link> to the 4th-level list, adds <Link to="/monster/pairaka">pairaka</Link> to the 6th-level list, adds <Link to="/monster/ghawwas">ghawwas</Link> to the 7th-level list, adds <Link to="/monster/shira">shira</Link> to the 8th-level list, and adds <Link to="/monster/sepid">sepid</Link> to the 9th-level list. Also, once per day on command the wearer can use this ring to summon a doru, as if by the <Link to="/spell/summon_monster_iii">summon monster III</Link> spell.</p>
<h3 id="magic-ring-ring_of_summoning_affinity_div-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>, creator must be chaotic evil; <strong>Cost</strong> 4,550 gp</p>
</>};
const _band_of_efficacious_death = {title: "Band of Efficacious Death", jsx: <><h2 id="magic-ring-band_of_efficacious_death-band-of-efficacious-death">Band of Efficacious Death</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 28</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 9,250 gp; <strong>Weight</strong> -</p>
<p>This golden ring is set with a large, almost gaudy onyx that can open to reveal a hidden compartment with just enough room for a single dose of powdered poison. This ring provides a +2 competence bonus on <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks to conceal this poison on the wearer's body. In addition, the ring contains four charges that recharge each day. When drawing a poison from the band of efficacious death, the wearer can tap the onyx up to four times to increase the frequency of the poison by 1 increment per tap. For example, if the poison's frequency were 1/round for 2 rounds, by touching the onyx once, the frequency would become 1/round for 3 rounds.</p>
<h3 id="magic-ring-band_of_efficacious_death-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/pernicious_poison">pernicious poison</Link>; <strong>Cost</strong> 4,625 gp</p>
</>};
const _splendorous_ring = {title: "Splendorous Ring", jsx: <><h2 id="magic-ring-splendorous_ring-splendorous-ring">Splendorous Ring</h2>
<p><strong>Sources</strong> <Link to="/source/chronicle_of_the_righteous">Chronicle of the Righteous pg. 53</Link></p>
<p><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 9,900 gp; <strong>Weight</strong> -</p>
<p>A splendorous ring is composed of six white and yellow gemstones faceted in a platinum band. Three times per day, the wearer of a splendorous ring can twist the ring to cloak himself in an aura of glory. He appears both radiant and terrible, glowing with the might of the heavens. Anyone within 10 feet of the ring when it is activated must succeed at a DC 13 Will save or be <Link to="/misc/fascinated">fascinated</Link> by the wearer's form as if affected by <em>hypnotic pattern.</em> 2d4+3 Hit Dice worth of creatures are affected in this way.</p>
<p>The fascinating effect of the ring lasts for 3 rounds. During that time and for 5 rounds after, the ring's wearer gains a +2 sacred bonus on any Charisma checks or Charisma-based skill checks to influence any good-aligned creatures affected by the ring's hypnotic pattern effect, and a -2 penalty on any Charisma checks or Charisma-based skill checks to influence any evil-aligned creatures affected by the hypnotic pattern effect.</p>
<h3 id="magic-ring-splendorous_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/hypnotic_pattern">hypnotic pattern</Link>, creator must be good-aligned; <strong>Cost</strong> 4,950 gp</p>
</>};
const _ring_of_revelation_lesser = {title: "Ring of Revelation (lesser)", jsx: <><h2 id="magic-ring-ring_of_revelation_lesser-ring-of-revelation">Ring of Revelation</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 173</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 293</Link><br/><strong>Aura</strong> moderate varies; <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 10,000 gp (lesser), 16,000 gp (greater), 24,000 gp (superior); <strong>Weight</strong> -</p>
<p>A ring of revelation is a divine item attuned to a particular oracular mystery and containing a revelation associated with that mystery (see the <Link to="/class/oracle">oracle</Link> class description). While wearing the ring, an oracle has access to that revelation and may use it as if she had it as a normal class feature. The oracle must have the appropriate mystery to use the ring, and must meet the level requirements (if any) of the revelation itself; for example, a ring of revelation (combat healer) is only usable by an oracle of at least 7th level with the <Link to="/mystery/battle">battle</Link> mystery. If the oracle already has that revelation and the revelation gives an ability with a limited number of uses per day, the oracle can use that ability one additional time per day. The ring has no effect if worn by a non-oracle, and <Link to="/skill/use_magic_device">Use Magic Device</Link> doesn't allow a character to gain a revelation from this ring.</p>
<p>A lesser ring of revelation contains a revelation that has no level prerequisite or a prerequisite that is less than 6th level. A greater ring of revelation contains a revelation that requires the oracle to be 7th level or higher. A superior ring of revelation contains a revelation that requires the oracle to be 11th level or higher.</p>
<h3 id="magic-ring-ring_of_revelation_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, creator must be an oracle with the desired revelation; <strong>Cost</strong> 5,000 gp (lesser), 8,000 gp (greater), 12,000 gp (superior)</p>
</>};
const _ring_of_climbing_improved = {title: "Ring of Climbing (improved)", jsx: <><h2 id="magic-ring-ring_of_climbing_improved-ring-of-climbing-improved">Ring of Climbing (improved)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 168</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>This ring functions as a <Link to="/magic-ring/ring_of_climbing">ring of climbing</Link>, except it grants a +10 competence bonus on its wearer's Climb checks.</p>
<h3 id="magic-ring-ring_of_climbing_improved-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, creator must have 10 ranks in the Climb skill; <strong>Cost</strong> 5,000 gp</p>
</>};
const _ring_of_curing = {title: "Ring of Curing", jsx: <><h2 id="magic-ring-ring_of_curing-ring-of-curing">Ring of Curing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 168</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> ring; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>This simple copper ring is a boon to those who spend their lives healing others. Whenever the wearer of a ring of curing casts a conjuration spell of the healing subschool, all maximums to the level-dependent healing provided by that spell increase by 2. For example, <Link to="/spell/cure_light_wounds">cure light wounds</Link> would provide a maximum healing of 1d8 + 7 (at 7th caster level), while <Link to="/spell/heal">heal</Link> would cure a maximum of 170 points of damage. This ring does not increase the wearer's actual caster level, nor the amount of level-dependent healing provided by any such spell.</p>
<h3 id="magic-ring-ring_of_curing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/feat/heighten_spell">Heighten Spell</Link>, <Link to="/spell/consecrate">consecrate</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _ring_of_foe_focus = {title: "Ring of Foe Focus", jsx: <><h2 id="magic-ring-ring_of_foe_focus-ring-of-foe-focus">Ring of Foe Focus</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 170</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>This ring of jagged steel gives the impression that it was salvaged from a suit of armor and then crudely bent into a circle. The wearer of the ring can, at will, designate any one opponent she can see as a particularly dangerous foe. She gains a +2 bonus to her AC and saving throws against attacks made by that opponent until she designates a new enemy.</p>
<h3 id="magic-ring-ring_of_foe_focus-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/shield">shield</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _ring_of_jumping_improved = {title: "Ring of Jumping (improved)", jsx: <><h2 id="magic-ring-ring_of_jumping_improved-ring-of-jumping-improved">Ring of Jumping (improved)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 172</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>This ring functions as a <Link to="/magic-ring/ring_of_jumping">ring of jumping</Link>, except it grants the wearer a +10 competence bonus all her <Link to="/skill/acrobatics">Acrobatics</Link> checks made to make high or long jumps.</p>
<h3 id="magic-ring-ring_of_jumping_improved-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, creator must have 10 ranks in Acrobatics; <strong>Cost</strong> 5,000 gp</p>
</>};
const _ring_of_ki_mastery = {title: "Ring of Ki Mastery", jsx: <><h2 id="magic-ring-ring_of_ki_mastery-ring-of-ki-mastery">Ring of Ki Mastery</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 172</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>This ring is half onyx and half clear-white crystal, magically fused together and hardened to the strength of steel. It allows a wearer with a ki pool to store up to 2 ki points in the ring as a swift action. These points remain in the ring until used. The wearer can use the ki points normally, or can gain the following benefits when he has ki points stored in the ring.</p>
<p>As long as there is at least one ki point stored in the ring, the wearer gains a +2 bonus to CMD against <Link to="/rule/grapple">grapple</Link>, <Link to="/rule/reposition">reposition</Link>, and <Link to="/rule/trip">trip</Link> attempts.</p>
<p>As long as there are at least 2 ki points stored in the ring, the wearer reduces the number of ki points needed to use a ninja trick or ki ability by 1 (minimum 1 ki point).</p>
<h3 id="magic-ring-ring_of_ki_mastery-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/ki_leech">ki leech</Link>, the creator must be able to use ki; <strong>Cost</strong> 5,000 gp</p>
</>};
const _ring_of_seven_virtues = {title: "Ring of Seven Virtues", jsx: <><h2 id="magic-ring-ring_of_seven_virtues-ring-of-seven-virtues">Ring of Seven Virtues</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_39_the_city_of_seven_spears">Pathfinder #39: The City of Seven Spears pg. 56</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>This bronze band is covered in geometric shapes and studded with tiny pearls. The wearer of the ring gains a constant <em>endure elements</em> effect and a +5 competence bonus on <Link to="/skill/survival">Survival</Link> checks made in jungles. In Saventh-Yhi, the wearer also enjoys the active benefits of one of that city's seven spears for as long as she is in that spear's district. The wearer loses the benefits of a particular spear if she leaves that spear's district, but gains new active benefits if she enters a new spear's district. The ring's wearer can only gain the benefits of a single spear at any one time.</p>
<h3 id="magic-ring-ring_of_seven_virtues-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/feat/self_sufficient">Self-Sufficient</Link>, <Link to="/spell/endure_elements">endure elements</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _ring_of_swimming_improved = {title: "Ring of Swimming (improved)", jsx: <><h2 id="magic-ring-ring_of_swimming_improved-ring-of-swimming-improved">Ring of Swimming (improved)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 175</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>As a <Link to="/magic-ring/ring_of_swimming">ring of swimming</Link>, except it grants a +10 competence bonus on its wearer's Swim checks.</p>
<h3 id="magic-ring-ring_of_swimming_improved-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, creator must have 10 ranks in Swim; <strong>Cost</strong> 5,000 gp</p>
</>};
const _ring_of_summoning_affinity_daemon = {title: "Ring of Summoning Affinity (Daemon)", jsx: <><h2 id="magic-ring-ring_of_summoning_affinity_daemon-ring-of-summoning-affinity-daemon">Ring of Summoning Affinity (Daemon)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 219</Link><br/><strong>Aura</strong> faint conjuration [evil]; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 10,600 gp; <strong>Weight</strong> -</p>
<p>This ring is carved from bone. If the wearer can cast <em>summon monster</em> spells, the wearer adds <Link to="/monster/cacodaemon">cacodaemon</Link> to the 3rd-level list of monsters she can summon with those spells, adds <Link to="/monster/ceustodaemon">ceustodaemon</Link> to the 5th-level list, adds <Link to="/monster/hydrodaemon">hydrodaemon</Link> to the 6th-level list, adds <Link to="/monster/leukodaemon">leukodaemon</Link> and <Link to="/monster/piscodaemon">piscodaemon</Link> to the 7th-level list, adds <Link to="/monster/derghodaemon">derghodaemon</Link> and <Link to="/monster/meladaemon">meladaemon</Link> to the 8th level list, and adds <Link to="/monster/thanadaemon">thanadaemon</Link> to the 9th-level list. Also, once per day on command the wearer can use this ring to summon a cacodaemon, as if by the <Link to="/spell/summon_monster_iii">summon monster III</Link> spell.</p>
<h3 id="magic-ring-ring_of_summoning_affinity_daemon-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>, creator must be neutral evil; <strong>Cost</strong> 5,300 gp</p>
</>};
const _ring_of_animal_friendship = {title: "Ring of Animal Friendship", jsx: <><h2 id="magic-ring-ring_of_animal_friendship-ring-of-animal-friendship">Ring of Animal Friendship</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 166</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 10,800 gp; <strong>Weight</strong> -</p>
<p>A ring of animal friendship always bears some sort of animal-like design in its craftsmanship. On command, this ring affects an animal as if the wearer had cast <em>charm animal,</em> causing the animal to regard the wearer as a trusted friend.</p>
<h3 id="magic-ring-ring_of_animal_friendship-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/charm_animal">charm animal</Link>; <strong>Cost</strong> 5,400 gp</p>
</>};
const _ring_of_the_iron_skull = {title: "Ring of the Iron Skull", jsx: <><h2 id="magic-ring-ring_of_the_iron_skull-ring-of-the-iron-skull">Ring of the Iron Skull</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_57_tempest_rising">Pathfinder #57: Tempest Rising pg. 59</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 10,800 gp; <strong>Weight</strong> -</p>
<p>Crudely cut amethysts and a single engraved skull decorate the band of this thick iron ring. The ring grants its wearer a +5 competence bonus on Appraise checks to determine the most valuable item in a treasure hoard and a +5 competence bonus on Heal checks to ascertain details of a dead creature's demise. Once per day as a standard action, the wearer can touch the ring to a corpse or piece of a corpse to learn the dead creature's name, gender, race, and profession or role, as well as the manner of the creature's death. The wearer also becomes aware of the location of other pieces of the corpse if they're within 1,200 feet. If the body part comes from a creature that's still alive or undead, the wearer gains no information. The ring of the iron skull must be worn for 24 hours before it starts to function for the wearer.</p>
<h3 id="magic-ring-ring_of_the_iron_skull-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/blood_biography">blood biography</Link>, <Link to="/spell/locate_object">locate object</Link>; <strong>Cost</strong> 5,400 gp</p>
</>};
const _ring_of_transposition = {title: "Ring of Transposition", jsx: <><h2 id="magic-ring-ring_of_transposition-ring-of-transposition">Ring of Transposition</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 176</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> ring; <strong>Price</strong> 10,800 gp; <strong>Weight</strong> -</p>
<p>On command, the wearer of this ring can touch it to another ring, magical or mundane, and bind it to the ring of transposition. Once per day, the wearer of the ring of transposition can speak a command word to exchange places with the creature wearing the bonded ring, which must be within 800 feet, as though using a <em>dimension door</em> spell against a willing target. In the process, the ring of transposition trades places with the ring on the other creature's hand, and the bond between the rings is broken. The bonding property of the ring of transposition can be used as often as desired, breaking any existing bond each time it is used. An existing bond can be broken by a successful <Link to="/spell/dispel">dispel</Link> check against the caster level of the ring.</p>
<h3 id="magic-ring-ring_of_transposition-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/dimension_door">dimension door</Link>; <strong>Cost</strong> 5,400 gp</p>
</>};
const _holdout_ring = {title: "Holdout Ring", jsx: <><h2 id="magic-ring-holdout_ring-holdout-ring">Holdout Ring</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 59</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> -</p>
<p>Made of aged bronze and steel, this ring looks like it should have a gem set in it, but instead has an empty circular hole. The hole in the ring holds a single <Link to="/eq-weapon/firearm_bullet">firearm bullet</Link>; if one is placed inside (as a full-round action), it merges seamlessly into the ring. While a bullet is merged into the ring, the wielder can fire the bullet as though she were using a +1 <Link to="/eq-weapon/pistol">pistol</Link> that can't misfire. Once the bullet has been fired from the ring, a new bullet can't be placed inside for 24 hours.</p>
<p>Each holdout ring is created with two +1 ammunition special abilities and one +2 ammunition special ability. If the wearer has the grit class feature, she can expend grit (maximum 4 grit points) to imbue bullets merged with the gun with one or more of these abilities. Imbuing a bullet with a +1 special ability costs 1 grit point; imbuing one with a +2 special ability costs 2 grit points. Each ring's special abilities are established upon the item's creation and can't be changed. If a special ability has multiple versions, as does <Link to="/magic-enh/bane">bane</Link>, the specific version must be set at that time (e.g., dragon bane). A typical holdout ring has the <Link to="/magic-enh/flaming">flaming</Link>, <Link to="/magic-enh/seeking">seeking</Link>, and <Link to="/magic-enh/shocking_burst">shocking burst</Link> special abilities.</p>
<h3 id="magic-ring-holdout_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/magic_weapon">magic weapon</Link>, <Link to="/spell/telekinesis">telekinesis</Link>, creator must meet the requirements for the ammunition special abilities that can be imbued by the ring; <strong>Cost</strong> 5,500 gp</p>
</>};
const _ring_of_tactical_precision = {title: "Ring of Tactical Precision", jsx: <><h2 id="magic-ring-ring_of_tactical_precision-ring-of-tactical-precision">Ring of Tactical Precision</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 175</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> -</p>
<p>This steel ring is inlaid with <Link to="/eq-material/adamantine">adamantine</Link> swords and shields. The wearer gains a +5 competence bonus on <Link to="/skill/profession">Profession (soldier)</Link> checks, and anytime the wearer gives or receives a numeric bonus from a <Link to="/main/teamwork_feat">teamwork feat</Link> or the <Link to="/rule/aid_another_2">aid another</Link> action, that bonus increase by +1. By wearing the ring for 1 hour, a creature may imbue it with a teamwork feat he knows for 24 hours. During this time, any creature wearing the ring may use that feat when cooperating with the creature that imbued it, but not with other creatures even if they possess the same teamwork feat. If the ring is imbued with a new teamwork feat, it replaces the previous feat.</p>
<h3 id="magic-ring-ring_of_tactical_precision-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, creator must have 5 ranks of Profession (soldier) and at least one teamwork feat; <strong>Cost</strong> 5,500 gp</p>
</>};
const _ring_of_the_sophisticate = {title: "Ring of the Sophisticate", jsx: <><h2 id="magic-ring-ring_of_the_sophisticate-ring-of-the-sophisticate">Ring of the Sophisticate</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 176</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 48</Link><br/><strong>Aura</strong> moderate transmutation and divination; <strong>CL</strong> 8th<br/><strong>Slot</strong> ring; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> -</p>
<p>Often worn on the little finger, this ring grants its wearer a +4 competence bonus on Sense Motive and Knowledge (local) checks. Also, once per day on command, the wearer can use the ring to cast either <em>locate creature</em> or <em>locate object</em> (the wearer's choice). Furthermore, on command and at will, the wearer can instantly know the direction from herself to the nearest tavern, pub, or similar watering hole as long as that establishment is in a settlement whose population is equivalent to that of a village or greater and that is within 20 miles of the wearer.</p>
<h3 id="magic-ring-ring_of_the_sophisticate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/know_direction">know direction</Link>, <Link to="/spell/locate_creature">locate creature</Link>, <Link to="/spell/locate_object">locate object</Link>, creator must have at least 4 ranks in both Sense Motive and Knowledge (local); <strong>Cost</strong> 5,500 gp</p>
</>};
const _decoy_ring = {title: "Decoy Ring", jsx: <><h2 id="magic-ring-decoy_ring-decoy-ring">Decoy Ring</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 166</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>This ring is a thick loop of mirror-like metal. Whenever the wearer of this ring takes the <Link to="/rule/withdraw">withdraw</Link> action or becomes <Link to="/misc/helpless">helpless</Link> (including falling unconscious), it instantly makes her invisible for 3 rounds and creates four illusory duplicates that either run off in opposite directions or perform other plausible actions that could draw enemy attention away from her. The duplicates last for 3 rounds before disappearing, but they instantly pop out of existence if struck by an attack (AC 10) and can be disbelieved (Will DC 19). Allies of the wearer always know her true location and can freely provide aid or assistance to her.</p>
<h3 id="magic-ring-decoy_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/mislead">mislead</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _ring_of_energy_resistance = {title: "Ring of Energy Resistance", jsx: <><h2 id="magic-ring-ring_of_energy_resistance-ring-of-energy-resistance">Ring of Energy Resistance</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 170</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 12,000 gp (minor), 28,000 gp (major), 44,000 gp (greater); <strong>Weight</strong> -</p>
<p>Rings of this type come in a wide variety of designs and colorations, typically related to the types of energy they defend against. These rings continually protect their wearers from damage from one type of energy - acid, cold, electricity, fire, or sonic (chosen by the creator of the item; determine randomly if found as part of a treasure hoard). Each time the wearer would normally take such damage, subtract the ring's resistance value from the damage dealt.</p>
<p>A minor ring of energy resistance grants 10 points of resistance. A major ring of energy resistance grants 20 points of resistance. A greater ring of energy resistance grants 30 points of resistance.</p>
<h3 id="magic-ring-ring_of_energy_resistance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/resist_energy">resist energy</Link>; <strong>Cost</strong> 6,000 gp (minor), 14,000 gp (major), 22,000 gp (greater)</p>
</>};
const _ring_of_blood_calling = {title: "Ring of Blood Calling", jsx: <><h2 id="magic-ring-ring_of_blood_calling-ring-of-blood-calling">Ring of Blood Calling</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_106_for_queen_and_empire">Pathfinder #106: For Queen and Empire pg. 18</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>This iron ring is set with a polished bloodstone. When created, a ring of blood calling creates a link between a single mortal creature devoted to <Link to="/faith/asmodeus">Asmodeus</Link> and a specific <Link to="/family/devil">devil</Link> with no more than 12 Hit Dice who willingly agrees to be bound by the item. Once per day as a standard action, the ring's wearer can place a drop of his own blood on the ring's gem (provoking attacks of opportunity) to immediately call the devil linked to the ring to any space within 30 feet. While the wearer does not control the devil, most wearers make agreements with the devil linked to the ring for protection or some other service when called. The called devil remains for 1 hour, or the wearer can <Link to="/misc/dismiss">dismiss</Link> the devil as a free action.</p>
<p>If the devil linked to the ring is killed, the ring crumbles to dust. If wearer linked to the ring is killed, a new wearer can summon the linked devil, but can compel the devil to perform only one service, as per <em>planar binding,</em> which severs the devil's link to the ring when the task is completed unless the new wearer makes his own deal with the devil, reestablishing the link between the wearer, the devil, and the ring.</p>
<p>Nicolo Alazario's ring of blood calling is linked to a <Link to="/monster/bone_devil">bone devil</Link> named Xanthut. If Nicolo is killed, the PCs will need to make their own arrangements with Xanthut to link themselves to the ring to call the devil.</p>
<h3 id="magic-ring-ring_of_blood_calling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_binding">planar binding</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _ring_of_craft_magic = {title: "Ring of Craft Magic", jsx: <><h2 id="magic-ring-ring_of_craft_magic-ring-of-craft-magic">Ring of Craft Magic</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 168</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 38</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>A <em>ring of craft magic</em> always bears some sort of tool-like design in its craftsmanship. The wearer of the ring sees spells as similar to crafts, and vice versa. The wearer may make a <Link to="/skill/craft">Craft</Link> check in place of a <Link to="/skill/spellcraft">Spellcraft</Link> check to identify an item that could be created with that Craft skill. The wearer may also expend a spell slot or prepared spell to gain an enhancement bonus equal to the level of the expended spell on a single Craft (any) or <Link to="/skill/profession_any">Profession (any)</Link> check (regardless of the amount of time needed to make the check).</p>
<h3 id="magic-ring-ring_of_craft_magic-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, creator must have the obsession racial trait; <strong>Cost</strong> 6,000 gp</p>
</>};
const _ring_of_ectoplasmic_invigoration = {title: "Ring of Ectoplasmic Invigoration", jsx: <><h2 id="magic-ring-ring_of_ectoplasmic_invigoration-ring-of-ectoplasmic-invigoration">Ring of Ectoplasmic Invigoration</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 169</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 6th<br/><strong>Slot</strong> ring; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>A <Link to="/class/summoner">summoner</Link> wearing a ring of ectoplasmic invigoration can use his maker's call class feature to absorb his eidolon (dismissing it in the process) instead of bringing it to his side. He gains 2 temporary hit points per Hit Die of the eidolon and the benefits of a <Link to="/spell/lesser_restoration">lesser restoration</Link> spell. The eidolon must still be within range of his maker's call ability. Any temporary hit points gained fade after 1 hour or when the eidolon is summoned again. A wearer with the transposition ability can transport himself to the eidolon's square (still absorbing and dismissing it) rather than calling the eidolon to him.</p>
<h3 id="magic-ring-ring_of_ectoplasmic_invigoration-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, the creator must be able to summon an eidolon and have the maker's call class feature; <strong>Cost</strong> 6,000 gp</p>
</>};
const _ring_of_immolation = {title: "Ring of Immolation", jsx: <><h2 id="magic-ring-ring_of_immolation-ring-of-immolation">Ring of Immolation</h2>
<p><strong>Sources</strong> <Link to="/source/curse_of_the_crimson_throne">Curse of the Crimson Throne pg. 435</Link>, <Link to="/source/pathfinder_11_skeletons_of_scarwall">Pathfinder #11: Skeletons of Scarwall pg. 42</Link><br/><strong>Aura</strong> moderate evocation (fire); <strong>CL</strong> 10th<br/><strong>Slot</strong> ring; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>A ring of immolation is made of pumice and hardened ash but is as strong as metal. As a free action, the wearer can activate the ring to create a <em>fire shield</em> (warm) on himself. The wearer of a ring of immolation can activate a <em>fire shield</em> on himself for up to 10 rounds each day (these rounds need not be used consecutively). If the wearer would take magical cold damage and any rounds of duration remain, the ring automatically activates for 1 round and protects the wearer from the cold damage as per <em>fire shield.</em></p>
<h3 id="magic-ring-ring_of_immolation-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/fire_shield">fire shield</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _ring_of_retreat = {title: "Ring of Retreat", jsx: <><h2 id="magic-ring-ring_of_retreat-ring-of-retreat">Ring of Retreat</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 115</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 12th<br/><strong>Slot</strong> ring; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>Each of these silver-and-gemstone rings is attuned to a specific <Link to="/magic-artifact/aiudara">aiudara</Link>, or elf gate. The ring must be created at the aiudara in question, and its gemstone always matches the gate's portal-key. On command once per week, the ring teleports its wearer back to that gate, as per <em>word of recall.</em> Theoretically, a ring of retreat could be crafted instead to transport the wearer to a specific site of import, such as a temple or stronghold, but to date, these rings have been crafted only with elf gates in mind.</p>
<h3 id="magic-ring-ring_of_retreat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/word_of_recall">word of recall</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _ring_of_the_troglodyte = {title: "Ring of the Troglodyte", jsx: <><h2 id="magic-ring-ring_of_the_troglodyte-ring-of-the-troglodyte">Ring of the Troglodyte</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 176</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>Two times per day on command, the wearer of this ring can produce a horrific smell affecting all living creatures other than the wearer within a 10-foot radius. Once created, the smell remains, centered on the wearer, until she dismisses it as a free action. This is a poison effect.</p>
<p>Any creature affected by the disgusting aroma produced by the ring must succeed at a DC 14 Fortitude saving throw when it starts its turn in the ring's stench radius. Those that fail a saving throw become <Link to="/misc/sickened">sickened</Link> for 1 round. If they are already sickened, they become <Link to="/misc/nauseated">nauseated</Link> for 1 round instead.</p>
<h3 id="magic-ring-ring_of_the_troglodyte-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/stinking_cloud">stinking cloud</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _steelhand_circle = {title: "Steelhand Circle", jsx: <><h2 id="magic-ring-steelhand_circle-steelhand-circle">Steelhand Circle</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 177</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> ring; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>When this ring is worn, the wielder's skin attains a barely perceptible sheen. In practical terms, the wearer ignores the first 5 points of an object's hardness when performing a <Link to="/rule/sunder">sunder</Link> combat maneuver or when <Link to="/rule/smashing_an_object">smashing an object</Link>. She also does not take the standard -4 penalty for making a combat maneuver check to <Link to="/rule/disarm">disarm</Link> while unarmed.</p>
<p>Additionally, the ring's wearer can focus all of the ring's power, possibly repelling a devastating blow. Once per day, when a critical hit or <Link to="/ability/sneak_attack">sneak attack</Link> is scored on the wearer, there is a 50% chance that the critical hit or sneak attack is negated and damage is instead rolled normally. Using this ability is an immediate action, and the wearer must decide to use it before the critical hit or sneak attack damage is rolled.</p>
<h3 id="magic-ring-steelhand_circle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/stone_fist">stone fist</Link>, <Link to="/spell/stoneskin">stoneskin</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _ring_of_chameleon_power = {title: "Ring of Chameleon Power", jsx: <><h2 id="magic-ring-ring_of_chameleon_power-ring-of-chameleon-power">Ring of Chameleon Power</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 168</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 12,700 gp; <strong>Weight</strong> -</p>
<p>As a free action, the wearer of this ring can gain the ability to magically blend in with her surroundings. This provides a +10 competence bonus on her Stealth checks. As a standard action, she can also use the spell <em>disguise self</em> as often as she wants.</p>
<h3 id="magic-ring-ring_of_chameleon_power-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/invisibility">invisibility</Link>; <strong>Cost</strong> 6,350 gp</p>
</>};
const _ring_of_natural_attunement_drake = {title: "Ring of Natural Attunement (Drake)", jsx: <><h2 id="magic-ring-ring_of_natural_attunement_drake-ring-of-natural-attunement-drake">Ring of Natural Attunement (Drake)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 217</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 12,880 gp; <strong>Weight</strong> -</p>
<p>This coiling band is made of jade carved into the shape of a sea drake. If the wearer can cast <em>summon nature's ally</em> spells, the wearer adds <Link to="/monster/forest_drake">forest drake</Link> and <Link to="/monster/shadow_drake">shadow drake</Link> to the 4th-level list of monsters he can summon with those spells, adds <Link to="/monster/flame_drake">flame drake</Link> to the 5th-level list, adds <Link to="/monster/frost_drake">frost drake</Link> to the 6th-level list, and adds <Link to="/monster/desert_drake">desert drake</Link> to the 9th-level list. Also, once per day on command the wearer can use this ring to summon a shadow drake, as if by the <em>summon nature's ally IV</em> spell.</p>
<h3 id="magic-ring-ring_of_natural_attunement_drake-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/greater_magic_fang">greater magic fang</Link>, <Link to="/spell/summon_natures_ally_iv">summon nature's ally IV</Link>; <strong>Cost</strong> 6,440 gp</p>
</>};
const _ghost_battling_ring = {title: "Ghost Battling Ring", jsx: <><h2 id="magic-ring-ghost_battling_ring-ghost-battling-ring">Ghost Battling Ring</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 258</Link><br/><strong>Aura</strong> faint illusion, necromancy, and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 13,000 gp; <strong>Weight</strong> -</p>
<p>This silver ring is engraved with a skull flanked by twin hourglasses. It functions as a <Link to="/magic-ring/ring_of_the_grasping_grave">ring of the grasping grave</Link>. In addition, the wearer can use <em>ghostly disguise</em> and <em>haste</em> each once per day.</p>
<h3 id="magic-ring-ghost_battling_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/ghostly_disguise">ghostly disguise</Link>, <Link to="/spell/haste">haste</Link>, <Link to="/spell/sculpt_corpse">sculpt corpse</Link>; <strong>Cost</strong> 6,500 gp</p>
</>};
const _ring_of_rulership = {title: "Ring of Rulership", jsx: <><h2 id="magic-ring-ring_of_rulership-ring-of-rulership">Ring of Rulership</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 153</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 12th<br/><strong>Slot</strong> ring; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> -</p>
<p>This garish signet ring is worth 1,500 gp for its materials and workmanship alone. Like the user of a <Link to="/magic-rod/rod_of_rulership">rod of rulership</Link>, the ring's wearer can command the fealty of creatures, but only if she is a member by blood of the family whose symbol is displayed on the ring and only if those creatures are citizens or vassals of the family's holdings (though it works on disaffected, disloyal, and even traitorous subjects). On command, the wearer can use the ring to target a single humanoid creature within 50 feet that meets those qualifications. This effect is automatically successful if the creature has an Intelligence of 9 or lower. A creature with a higher Intelligence must succeed a DC 14 Will save or obey the ring's wearer's commands as if she were its absolute sovereign; a successful save renders that creature immune to that ring's effects for 24 hours. This is a mind-affecting enchantment (compulsion) effect and counts as 3rd-level spell for the purpose of <Link to="/spell/break_enchantment">break enchantment</Link>. If the ring's wielder gives a command that is contrary to the nature of a ruled creature, that creature receives another saving throw to shake off the effect. Even if the ruled creature fails the saving throw and remains ruled, it can still refuse that particular command. The GM is the final arbiter of what constitutes a command that is contrary to the nature of a ruled creature, and for most creatures, if the ring's wearer coopts their every moment, the creature can attempt a save every day.</p>
<p>A creature is ruled until one of the following happens: it shakes off the effect after being given a command against its nature, an outside source (such as <em>break enchantment</em>) removes the compulsion, the wearer removes the ring of rulership, the wearer commands the ring to release the creature (a standard action that need not take place in the creature's presence), or another member of the ruler's family rules the creature using a different ring of rulership, whichever comes first.</p>
<p>The power of the ring can rule no more than three creatures at a time; to rule a new creature, the ring's wearer must first release one of the three ruled creatures.</p>
<h3 id="magic-ring-ring_of_rulership-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/mass_suggestion">mass suggestion</Link>; <strong>Cost</strong> 7,750 gp</p>
</>};
const _ring_of_the_sea_strider = {title: "Ring of the Sea Strider", jsx: <><h2 id="magic-ring-ring_of_the_sea_strider-ring-of-the-sea-strider">Ring of the Sea Strider</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 176</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> -</p>
<p>This ring is made of a single piece of deep blue crystal. The ring grants its wearer a swim speed of 30 feet, as well as +8 racial bonus on <Link to="/skill/swim">Swim</Link> checks for having a swim speed. Furthermore, once per day as a swift action, as long as the wearer is in contact with liquid, he can use <em>dimension door</em> as the spell, but its starting and ending points must be connected by a contagious mass of liquid.</p>
<h3 id="magic-ring-ring_of_the_sea_strider-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/dimension_door">dimension door</Link>, <Link to="/spell/touch_of_the_sea">touch of the sea</Link>; <strong>Cost</strong> 7,000 gp</p>
</>};
const _duxotars_signet = {title: "Duxotar's Signet", jsx: <><h2 id="magic-ring-duxotars_signet-duxotars-signet">Duxotar's Signet</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_108_hell_comes_to_westcrown">Pathfinder #108: Hell Comes to Westcrown pg. 38</Link><br/><strong>Aura</strong> moderate abjuration and illusion; <strong>CL</strong> 6th<br/><strong>Slot</strong> ring; <strong>Price</strong> 14,500 gp; <strong>Weight</strong> -</p>
<p>This ornate <Link to="/magic-ring/ring_of_protection_2">ring of protection +2</Link> is emblazoned with the winged Eye of Aroden in ruby and jet. The wearer of a duxotar's signet projects an air of commanding authority that affects large groups; the wearer does not treat crowds as difficult terrain and gains a +5 competence bonus on Diplomacy or Intimidate checks to direct or influence crowds. The wearer can also cast <em>magic mouth</em> at will, but the message trigger must be "upon seeing a creature wearing the Eye of Aroden" (which triggers the <em>magic mouth</em> for any dottari in uniform).</p>
<h3 id="magic-ring-duxotars_signet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/magic_mouth">magic mouth</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>; <strong>Cost</strong> 7,750 gp</p>
</>};
const _ophidian_coil = {title: "Ophidian Coil", jsx: <><h2 id="magic-ring-ophidian_coil-ophidian-coil">Ophidian Coil</h2>
<p><strong>Sources</strong> <Link to="/source/down_the_blighted_path">Down the Blighted Path pg. 62</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> -</p>
<p>This small wooden ring resembles a serpent with tiny gemstone eyes coiling around the wearer's finger. If worn for 24 hours, it causes its wearer to manifest many serpentine traits. The wearer's skin develops a faint, diamond-shaped pattern, and the pupils of her eyes elongate. The wearer grows a pair of fangs, gaining a bite attack as a primary <Link to="/umr/natural_attack">natural attack</Link> that deals 1d4 points of piercing damage for a Medium wearer or 1d3 points of damage for a Small wearer.</p>
<p>Three times per day as a free action, the wearer of the ring may cause her fangs to drip with venom, making her bite attack poisonous for 1 round. The save DC of this poison is equal to 10 + 1/2 the wearer's Hit Dice + the wearer's Constitution modifier, but otherwise acts as <Link to="/eq-poison/black_adder_venom">black adder venom</Link>. If the wearer rolls a natural 1 on an attack with her poisonous bite, she is exposed to the poison.</p>
<p>Once per day as a standard action, the wearer may command her tongue to lengthen and become forked for 1 minute, gaining the <Link to="/umr/scent">scent</Link> special ability. While this ability is active, the wearer has a 20% chance of failure when casting any spell with a verbal component, as the tongue makes it difficult to speak.</p>
<p>The ring makes its wearer more sensitive to cold. She takes a -2 penalty to saves against spells with the cold descriptor and the effects of <Link to="/rule/cold">cold weather</Link>. Additionally, if the wearer is successfully affected by a spell with the cold descriptor, she is <Link to="/spell/slow">slowed</Link> for 1 round.</p>
<h3 id="magic-ring-ophidian_coil-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>, <Link to="/spell/poison">poison</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _ring_of_adept_maneuvers = {title: "Ring of Adept Maneuvers", jsx: <><h2 id="magic-ring-ring_of_adept_maneuvers-ring-of-adept-maneuvers">Ring of Adept Maneuvers</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 62</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> -</p>
<p>This variant ring of ki mastery is made of a lock of hair held together by small bands to form a ring. The ring allows a wearer with a ki pool to store up to 2 ki points in the ring as a swift action. These points remain in the ring until used. The wearer can use the ki points normally, but gains the following benefits when ki points are stored in the ring.</p>
<p>As long as at least 1 ki point is stored in the ring, the wearer gains a +2 bonus on combat maneuver checks to bull rush, disarm, or trip opponents.</p>
<p>If at least 2 ki points are stored in the ring, the wearer takes only a -1 penalty on attack rolls when making a flurry of blows instead of a -2 penalty.</p>
<h3 id="magic-ring-ring_of_adept_maneuvers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/ki_leech">ki leech</Link>, the creator must have the ki pool class feature; <strong>Cost</strong> 7,500 gp</p>
</>};
const _ring_of_resilience = {title: "Ring of Resilience", jsx: <><h2 id="magic-ring-ring_of_resilience-ring-of-resilience">Ring of Resilience</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 218</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> ring; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> -</p>
<p>This tarnished copper band sheds its patina when worn by anyone with panache or grit. Whenever the wearer regains a panache or grit point through her actions (not just a daily refresh), she can try to end a single ongoing condition affecting her, attempting a new saving throw against the original DC. The effect must be one that allowed a saving throw, can be removed by either <Link to="/spell/dispel_magic">dispel magic</Link> or <Link to="/spell/heal">heal</Link>, and be an effect against which the wearer failed her initial saving throw. If the wearer succeeds at the new save, the effect is removed even if succeeding at the save would normally have other consequences, and even if the effect normally requires multiple saves to remove. If the effect allowed more than one type of saving throw, use the type and DC for the first saving throw the wearer failed for the effect. The wearer can use the ring only once for each ongoing condition. As the wearer must regain a panache or grit point to reroll a save, the ring provides no benefit if she hasn't used any grit or panache.</p>
<h3 id="magic-ring-ring_of_resilience-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/restoration">restoration</Link>, creator must be a grit or panache user; <strong>Cost</strong> 7,500 gp</p>
</>};
const _ring_of_retribution = {title: "Ring of Retribution", jsx: <><h2 id="magic-ring-ring_of_retribution-ring-of-retribution">Ring of Retribution</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 173</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 292</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 13th<br/><strong>Slot</strong> ring; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> -</p>
<p>Once per day, the wearer of this charred bone ring may, as an immediate action, cause it to detonate in a 30-foot-radius <Link to="/misc/burst">burst</Link> that deals 10d6 points of fire damage (Reflex DC 14 half). If the wearer is killed by the detonation, all magical equipment he carries must also save or take fire damage, and all nonmagical equipment takes this damage with no saving throw. This explosion never destroys the ring.</p>
<h3 id="magic-ring-ring_of_retribution-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/feat/quicken_spell">Quicken Spell</Link>, <Link to="/spell/fireball">fireball</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _ring_of_the_cacodaemon = {title: "Ring of the Cacodaemon", jsx: <><h2 id="magic-ring-ring_of_the_cacodaemon-ring-of-the-cacodaemon">Ring of the Cacodaemon</h2>
<p><strong>Sources</strong> <Link to="/source/book_of_the_damned">Book of the Damned pg. 197</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 8th<br/><strong>Slot</strong> ring; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> -</p>
<p>Sculpted into the intricate form of a golden <Link to="/monster/cacodaemon">cacodaemon</Link>, this ring features a decorative wide-open mouth and can hold a <Link to="/spell/create_soul_gem">soul gem</Link> braced between its horns. The ring allows its wearer to tap into the residual memories of the mangled soul it contains. Once per day, the wearer can interrogate the soul in the gem, as per <em>speak with dead,</em> except the soul answers telepathically. Once per day, the bearer can project the soul's last tormented moments before it was consumed and bound, creating a cone of terror as per <em>fear.</em></p>
<h3 id="magic-ring-ring_of_the_cacodaemon-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fear">fear</Link>, <Link to="/spell/speak_with_dead">speak with dead</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _ring_of_water_walking = {title: "Ring of Water Walking", jsx: <><h2 id="magic-ring-ring_of_water_walking-ring-of-water-walking">Ring of Water Walking</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 177</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> -</p>
<p>This ring is often made of coral or bluish metal decorated with motifs depicting rolling waves of water. The ring allows the wearer to continually utilize the effects of the spell <em>water walk.</em></p>
<h3 id="magic-ring-ring_of_water_walking-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/water_walk">water walk</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _scavengers_ring = {title: "Scavenger's Ring", jsx: <><h2 id="magic-ring-scavengers_ring-scavengers-ring">Scavenger's Ring</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 9</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> -</p>
<p>This polished iron band allows the wearer to walk along the ocean floor as easily as on dry land. The wearer of a scavenger's ring sinks to the bottom of any large body of water at a rate of 30 feet per round. Once on the body of water's floor, the wearer can move and act as though she were on land, allowing her to jump, roll, attack, and run as normal, although she cannot swim (nor can she control her ascent or descent underwater) as long as she wears the ring. As soon as the wearer removes the ring, she may swim as normal and is subject to all the normal penalties associated with <Link to="/rule/underwater_combat">underwater action</Link>. A scavenger's ring does not confer the ability to breathe while underwater.</p>
<h3 id="magic-ring-scavengers_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/freedom_of_movement">freedom of movement</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _heavenly_aegis_ring = {title: "Heavenly Aegis Ring", jsx: <><h2 id="magic-ring-heavenly_aegis_ring-heavenly-aegis-ring">Heavenly Aegis Ring</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 216</Link><br/><strong>Aura</strong> moderate evocation [good]; <strong>CL</strong> 10th<br/><strong>Slot</strong> ring; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> -</p>
<p>The surface of this silver ring never tarnishes, but when an evil creature is wearing it, its luster diminishes. Whenever the wearer takes the <Link to="/misc/total_defense">total defense</Link> action, he can activate the ring, creating a <em>magic circle against evil</em> effect centered on him. This effect lasts 10 rounds per day, though the rounds don't need to be spent consecutively. Once activated, the effect expends rounds until the user ends it as a move action or the rounds run out.</p>
<p>As a standard action while the <em>magic circle</em> is active, the wearer can release the protective circle's energy as a violent blast. This functions as <em>holy smite</em> centered on the wearer, but the wearer can exclude a 10-foot-radius area from the center of the affected area. Releasing the energy expends all the ring's remaining rounds and can be done only if at least 5 rounds remain.</p>
<p>The ring's power renews each day at dawn.</p>
<h3 id="magic-ring-heavenly_aegis_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/holy_smite">holy smite</Link>, <Link to="/spell/magic_circle_against_evil">magic circle against evil</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _ring_of_perfect_sizing = {title: "Ring of Perfect Sizing", jsx: <><h2 id="magic-ring-ring_of_perfect_sizing-ring-of-perfect-sizing">Ring of Perfect Sizing</h2>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook pg. 33</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> -</p>
<p>This lustrous gold ring is highly malleable and always fits perfectly. After being worn for 24 hours, the ring allows the wearer to resize one weapon or suit of armor to her size. The ring can affect any item that is no more than two size categories too big or too small and that weighs no more than 125 pounds. The size change lasts until 1 round after the item leaves the wearer's possession. A new item can be resized after it has been in the wearer's possession for 24 hours, causing the previously resized item to return to its normal size. The resizing otherwise functions as the <em>resize item</em> spell.</p>
<h3 id="magic-ring-ring_of_perfect_sizing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/resize_item">resize item</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _sigil_of_kraggodan = {title: "Sigil of Kraggodan", jsx: <><h2 id="magic-ring-sigil_of_kraggodan-sigil-of-kraggodan">Sigil of Kraggodan</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_118_siege_of_stone">Pathfinder #118: Siege of Stone pg. 41</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> ring; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> -</p>
<p>This <Link to="/eq-material/adamantine">adamantine</Link> band is capped with a stone sigil of the first clan to settle the Sky Citadel of Kraggodan. This ring is keyed to interact with several devices and traps within the vaults - storehouses of ancient history and family wealth - of the Sky Citadel. The ring grants its wearer acid resistance 10. Three times per day as a swift action, the wearer can make himself undetectable by crafted and magical traps and creatures of the construct type for the following minute. This functions like <Link to="/spell/greater_invisibility">greater invisibility</Link> within these limits and also prevents the character's weight or presence from triggering traps.</p>
<h3 id="magic-ring-sigil_of_kraggodan-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/sanctuary">sanctuary</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _ring_of_entropy_and_order = {title: "Ring of Entropy and Order", jsx: <><h2 id="magic-ring-ring_of_entropy_and_order-ring-of-entropy-and-order">Ring of Entropy and Order</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 49</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> ring; <strong>Price</strong> 16,200 gp; <strong>Weight</strong> -</p>
<p>This gold ring resembles tiny angel wings folded around a clear crystal. Once per day, the wearer can target herself with a <em>protection from chaos</em> or <em>protection from law</em> effect that lasts for 10 minutes. However, if the wearer uses the ring of entropy and order to gain <em>protection from chaos</em> while on a plane with the mildly chaos-aligned or strongly chaos-aligned trait, or to gain <em>protection from law</em> while on a plane with the mildly law-aligned or strongly law-aligned trait, the effect instead lasts for 1 hour. If the wearer fails a saving throw against a charm or compulsion effect while on a plane with the mildly chaos-aligned, mildly law-aligned, strongly chaos-aligned, or strongly law-aligned traits, she can activate the effect as an immediate action.</p>
<h3 id="magic-ring-ring_of_entropy_and_order-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/contingency">contingency</Link>, <Link to="/spell/protection_from_chaos">protection from chaos</Link>, <Link to="/spell/protection_from_law">protection from law</Link>; <strong>Cost</strong> 8,100 gp</p>
</>};
const _ring_of_inner_fortitude_minor = {title: "Ring of Inner Fortitude (minor)", jsx: <><h2 id="magic-ring-ring_of_inner_fortitude_minor-ring-of-inner-fortitude">Ring of Inner Fortitude</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 171</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 18,000 gp (minor), 42,000 gp (major), 66,000 gp (greater); <strong>Weight</strong> -</p>
<p>Alternating diamonds and rubies stud this band of white gold. A minor ring of fortitude reduces <Link to="/rule/ability_damage">ability damage</Link> or temporary ability penalties the wearer takes by 2 points and ability <Link to="/rule/drain">drain</Link> by 1 point. If an effect targets multiple ability scores (for example, <Link to="/misc/exhaustion">exhaustion</Link>, <Link to="/misc/fatigue">fatigue</Link>, or <Link to="/spell/touch_of_idiocy">touch of idiocy</Link>), the ring reduces the damage, drain, or penalty for all ability scores.</p>
<p>A major ring of inner fortitude reduces ability damage or temporary penalties by 4 points and reduces ability drain by 2 points.</p>
<p>A greater ring of inner fortitude reduces ability damage or temporary penalties by 6 points and reduces ability drain by 3 points.</p>
<p>Wearing a ring of inner fortitude ring does not make the wearer immune to conditions such as fatigued or exhausted even if the wearer ignores all ability damage, drain, or penalties from the condition. If the ring prevents any damage, drain, or penalty that are associated with a beneficial effect, it also negates the beneficial effect.</p>
<h3 id="magic-ring-ring_of_inner_fortitude_minor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/restoration">restoration</Link>; <strong>Cost</strong> 9,000 gp (minor), 21,000 gp (major), 33,000 gp (greater)</p>
</>};
const _ring_of_spell_storing_minor = {title: "Ring of Spell Storing (minor)", jsx: <><h2 id="magic-ring-ring_of_spell_storing_minor-ring-of-spell-storing-minor">Ring of Spell Storing (minor)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 174</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> -</p>
<p>As the <Link to="/magic-ring/ring_of_spell_storing">ring of spell storing</Link>, except it holds up to 3 levels of spells.</p>
<h3 id="magic-ring-ring_of_spell_storing_minor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/imbue_with_spell_ability">imbue with spell ability</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _ring_of_stony_flesh = {title: "Ring of Stony Flesh", jsx: <><h2 id="magic-ring-ring_of_stony_flesh-ring-of-stony-flesh">Ring of Stony Flesh</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_83_the_slave_trenches_of_hakotep">Pathfinder #83: The Slave Trenches of Hakotep pg. 63</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> -</p>
<p>A ring of stony flesh gives the wearer's skin the appearance of flexible stone. Once per day, the wearer can expend a charge as a standard action to gain the benefits of <em>stoneskin.</em> While under this effect, the wearer gains the <Link to="/umr/earth_glide">earth glide</Link> ability, allowing her to move through unworked stone or earth as easily as a fish swims through water. The wearer cannot move through stone composed of multiple blocks - such as the walls of a tomb or castle - with this ability, only through solid masses of stone. In addition, a ring of stony flesh automatically nullifies any petrification effect that targets the wearer by expending 2 charges, provided the ring has at least 2 charges remaining. The ring's protection effect activates before the wearer attempts a saving throw against the petrification attempt. A ring of stony flesh has 10 charges when created.</p>
<h3 id="magic-ring-ring_of_stony_flesh-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/stone_to_flesh">stone to flesh</Link>, <Link to="/spell/stoneskin">stoneskin</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _rings_of_bondage = {title: "Rings of Bondage", jsx: <><h2 id="magic-ring-rings_of_bondage-rings-of-bondage">Rings of Bondage</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 242</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 18,200 gp; <strong>Weight</strong> -</p>
<p>These rings are forged in pairs, establishing a mental connection between the two creatures wearing them, designating one as the master and the other as the servant. The listed and cost are for both rings. Creatures wearing rings of bondage can understand one another's speech. The wearer of the master ring gains a +6 competence bonus on <Link to="/skill/sense_motive">Sense Motive</Link> checks against the servant and is continuously aware of the location and general condition of the wearer of the servant ring, as the <em>status</em> spell.</p>
<p>In addition, once per day, the wearer of the master ring of bondage can impose her will upon the wearer of the servant ring, compelling the servant to perform or refrain from an action as if subjected to a <em>lesser geas</em> (Will DC 16 negates). Alternatively, this effect can be executed as a contract between the wearers: as long as the wearer of the master ring is a valid target for <em>lesser geas,</em> she can accept a <em>lesser geas</em> dictated by the wearer of the servant ring. In such an event, neither wearer is entitled to a saving throw and both are compelled by the <em>lesser geas</em> to fulfill the terms of the agreement. If the wearer of the servant ring is unwilling to agree to such a contract, she can always select a <em>lesser geas</em> such as "remove the <em>lesser geas</em> from me."</p>
<p>As long as a <em>lesser geas</em> imposed by a ring of bondage remains in effect, neither ring can be removed. If either ring is destroyed, the effects of the <em>lesser geas</em> remain in place, but the surviving ring can't create a new <em>lesser geas</em> until the missing ring is repaired or replaced. If a mutual <em>lesser geas</em> is accepted and one <em>lesser geas</em> is ended, both <em>lesser geas</em> effects end simultaneously.</p>
<p>A target can have a ring of bondage forcibly placed on its finger, but only if that creature is <Link to="/misc/helpless">helpless</Link>.</p>
<h3 id="magic-ring-rings_of_bondage-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>, <Link to="/spell/lesser_geas">lesser geas</Link>, <Link to="/spell/sanctuary">sanctuary</Link>, <Link to="/spell/share_language">share language</Link>, <Link to="/spell/status">status</Link>; <strong>Cost</strong> 9,100 gp</p>
</>};
const _ring_of_energy_shroud = {title: "Ring of Energy Shroud", jsx: <><h2 id="magic-ring-ring_of_energy_shroud-ring-of-energy-shroud">Ring of Energy Shroud</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 170</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> ring; <strong>Price</strong> 19,500 gp; <strong>Weight</strong> -</p>
<p>A ring of energy shroud always appears to be glass or crystal in construction, tinted in a red, green, blue, or yellow hue. Closer inspection reveals a small band of metal within the glass or crystal. Treasured by frontline fighters and anyone with a trusted evoker ally, rings of energy shroud normally function as a <Link to="/magic-ring/minor_ring_of_energy_resistance">minor ring of energy resistance</Link>. However, once per day as an immediate action, the ring's wearer can negate the damage of an incoming acid, cold, electricity, or fire energy effect for himself (but not for other creatures affected by the spell or effect), transforming that damage into a shroud of energy that wreathes the wearer's body acting as if under the effects of the <em>elemental aura</em> spell. The <em>elemental aura</em> effect has the same energy type of the damage negated.</p>
<h3 id="magic-ring-ring_of_energy_shroud-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/elemental_aura">elemental aura</Link>, <Link to="/spell/resist_energy">resist energy</Link>; <strong>Cost</strong> 9,750 gp</p>
</>};
const _nethysian_ring_of_minor_spell_storing = {title: "Nethysian Ring of Minor Spell Storing", jsx: <><h2 id="magic-ring-nethysian_ring_of_minor_spell_storing-nethysian-ring-of-minor-spell-storing">Nethysian Ring of Minor Spell Storing</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 259</Link><br/><strong>Aura</strong> moderate abjuration and transmutation [chaotic, evil, good, lawful]; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> -</p>
<p>This ring is made of several metals hammered together into a mottled pattern, with Nethys's holy symbol stamped on one end. It functions as a <Link to="/magic-ring/minor_ring_of_spell_storing">minor ring of spell storing</Link>, except domain spells from <Link to="/faith/nethys">Nethys's domains</Link> count as 1 spell level lower (minimum 1st level) for the purpose of storing them in the ring.</p>
<h3 id="magic-ring-nethysian_ring_of_minor_spell_storing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/imbue_with_spell_ability">imbue with spell ability</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _ring_of_arcane_mastery = {title: "Ring of Arcane Mastery", jsx: <><h2 id="magic-ring-ring_of_arcane_mastery-ring-of-arcane-mastery">Ring of Arcane Mastery</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 167</Link><br/><strong>Aura</strong> strong abjuration and evocation; <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> -</p>
<p>This ring is a thin but sturdy piece of forged steel crafted to resemble a serpent swallowing its tail, and is magically imbued to reveal the secrets of arcane mastery to its wearer. The ring allows a wearer with an arcane pool to store up to 4 points from his arcane pool in the ring as a swift action. These points remain in the ring until used. A wearer can spend arcane pool points stored in the ring as if they were his own, or can spend them in each of the following ways.</p>
<ul>
<li>As a free action, the wearer can expend 1 arcane pool point stored in the ring to gain a +2 bonus on <Link to="/rule/concentration">concentration</Link> checks for 1 round.</li>
<li>As a standard action, the wearer can expend 1 arcane pool point stored in the ring to use the <Link to="/arcana/pool_strike">pool strike</Link> magus arcana using his own magus level to determine the effect.</li>
<li>As an immediate action, the wearer can expend up to 4 arcane pool points stored in the ring to use the <Link to="/arcana/reflection">reflection</Link> magus arcana.</li>
</ul>
<h3 id="magic-ring-ring_of_arcane_mastery-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/imbue_with_spell_ability">imbue with spell ability</Link>, <Link to="/spell/spell_turning">spell turning</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _ring_of_invisibility = {title: "Ring of Invisibility", jsx: <><h2 id="magic-ring-ring_of_invisibility-ring-of-invisibility">Ring of Invisibility</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 171</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> -</p>
<p>By activating this simple silver ring, the wearer can benefit from <em>invisibility,</em> as the spell.</p>
<h3 id="magic-ring-ring_of_invisibility-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/invisibility">invisibility</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _ring_of_phrenic_prowess = {title: "Ring of Phrenic Prowess", jsx: <><h2 id="magic-ring-ring_of_phrenic_prowess-ring-of-phrenic-prowess">Ring of Phrenic Prowess</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 8</Link><br/><strong>Aura</strong> moderate abjuration and divination; <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> -</p>
<p>This ring is made of rough iron and is set with four amethysts. It allows a wearer with a phrenic pool to store up to 4 points from her phrenic pool in the ring as a swift action. These points remain in the ring until used. A wearer can spend points stored in the ring as if they were in her phrenic pool, in addition to the following uses.</p>
<ul>
<li>As a free action, the wearer can expend 1 point stored in the ring to gain a +2 bonus on <Link to="/rule/concentration">concentration</Link> checks for 1 round.</li>
<li>As a standard action, the wearer can expend 1 point stored in the ring to attempt to flood a target with raw psychic power. The wearer makes a melee touch attack charged with psychic energy. If the touch attack hits, it deals 3d6 points of nonlethal damage and the target is <Link to="/misc/stunned">stunned</Link> for 1 round. If the attack misses, the charge dissipates.</li>
<li>As an immediate action, the wearer can expend up to 4 points stored in the ring to gain the benefit of <em>spell turning</em> for 1 round. The number of spell levels she can turn is equal to the number of points expended.</li>
</ul>
<h3 id="magic-ring-ring_of_phrenic_prowess-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/spell_turning">spell turning</Link>, <Link to="/spell/telepathic_bond">telepathic bond</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _ring_of_plagues = {title: "Ring of Plagues", jsx: <><h2 id="magic-ring-ring_of_plagues-ring-of-plagues">Ring of Plagues</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption pg. 31</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> -</p>
<p>This silver ring is set with a black opal. Once per day, when the wearer is reduced to half or fewer of her maximum hit point total, whoever dealt the activating blow to the wearer is immediately subjected to a <em>major curse</em> with unlimited range. A successful DC 19 Will saving throw is needed to negate the spell. Rather than one of the listed curse effects, the curse imposes a -4 penalty on the victim's saving throws and causes the victim to contract a disease chosen by the wearer from the <em>contagion</em> list without a save. The cursed disease has no onset time, but the attacker is allowed the normal saving throw to avoid its effects. It can be cured only by successfully casting both <Link to="/spell/remove_curse">remove curse</Link> and <Link to="/spell/remove_disease">remove disease</Link> within 1 minute of each other. Those exposed to the cursed attacker thereafter must save against the mundane version of the disease or become infected (though they are not cursed).</p>
<p>Once per day, if the wearer is killed or reduced to negative hit points, a plague of curses is unleashed. The attacker and the attacker's five nearest allies or immediate blood relatives become the targets of the curse described above. If the wearer is restored to at least 1 hit point, these curses end, allowing surviving victims to recover naturally.</p>
<h3 id="magic-ring-ring_of_plagues-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/contagion">contagion</Link>, <Link to="/spell/major_curse">major curse</Link>, <Link to="/spell/spite">spite</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _ring_of_terrible_cost = {title: "Ring of Terrible Cost", jsx: <><h2 id="magic-ring-ring_of_terrible_cost-ring-of-terrible-cost">Ring of Terrible Cost</h2>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils pg. 21</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> -</p>
<p>These rings once displayed the smiling face of King Gaspodar, and were forged in limited quantities to celebrate the end of his reign. After <Link to="/faith/aroden">Aroden's</Link> death, the rings were cast aside or lost. Recently, several resurfaced, but changed by unknown means-Gaspodar's face now bears a sorrowful expression, and flames loom behind him.</p>
<p>As a standard action, you may charge the ring with a +1 profane bonus by sacrificing 2 of your hit points. These hit points remain lost and cannot be healed by any means until the ring's power is expended. You may do this multiple times, up to a maximum of a +5 profane bonus stored in the ring.</p>
<p>As an immediate action, you can add the stored profane bonus to any single attack roll, damage roll, skill check, or saving throw, which expends the charged energy from the ring. You must declare this use after rolling the die but before you learn the result of the roll. You must expend all the ring's power at once. Once the charge is expended, you can heal your lost hit points normally. Expending this charge does not ruin the ring, and you may charge it again by sacrificing more hit points.</p>
<p>The charge in the ring can come from multiple donors, but none of the donors can regain their sacrificed hit points until the ring's charge is spent or the ring is destroyed. For this reason, owners of a ring of terrible cost guard the item carefully.</p>
<h3 id="magic-ring-ring_of_terrible_cost-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/aid">aid</Link>, <Link to="/spell/resistance">resistance</Link>, <Link to="/spell/vampiric_touch">vampiric touch</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _ring_of_wizardry = {title: "Ring of Wizardry", jsx: <><h2 id="magic-ring-ring_of_wizardry-ring-of-wizardry">Ring of Wizardry</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 177</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate (no school); <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 20,000 gp (type I), 40,000 gp (type II), 70,000 gp (type III), 100,000 gp (type IV); <strong>Weight</strong> -</p>
<p>This special ring comes in four varieties, all of them useful only to arcane spellcasters. The wearer's arcane spells per day are doubled for one specific spell level. Type I doubles 1st-level spells, type II doubles 2nd-level spells, type III doubles 3rd-level spells, and type IV doubles 4th-level spells. Bonus spells from high ability scores or school specialization are not doubled.</p>
<h3 id="magic-ring-ring_of_wizardry-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/limited_wish">limited wish</Link>; <strong>Cost</strong> 10,000 gp (type I), 20,000 gp (type II), 35,000 gp (type III), 50,000 gp (type IV)</p>
</>};
const _ring_of_mysticism = {title: "Ring of Mysticism", jsx: <><h2 id="magic-ring-ring_of_mysticism-ring-of-mysticism">Ring of Mysticism</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 8</Link><br/><strong>Aura</strong> moderate (no school); <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 20,000 gp (Type I), 40,000 gp (Type II), 70,000 gp (Type III), 100,000 gp (Type IV); <strong>Weight</strong> -</p>
<p>This ring of bone fused with crystal comes in four varieties, all of them useful only to psychic spellcasters. The wearer's number of psychic spells per day is doubled for one specific spell level. Type I doubles 1st-level spells, type II doubles 2nd-level spells, type III doubles 3rd-level spells, and type IV doubles 4th-level spells. Bonus spells from high ability scores are not doubled.</p>
<h3 id="magic-ring-ring_of_mysticism-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/limited_wish">limited wish</Link>; <strong>Cost</strong> 10,000 gp (Type I), 20,000 gp (Type II), 35,000 gp (Type III), 50,000 gp (Type IV)</p>
</>};
const _ring_of_evasion = {title: "Ring of Evasion", jsx: <><h2 id="magic-ring-ring_of_evasion-ring-of-evasion">Ring of Evasion</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 170</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> -</p>
<p>This ring continually grants the wearer the ability to avoid damage as if she had <Link to="/ability/evasion">evasion</Link>. Whenever she makes a Reflex saving throw to determine whether she takes half damage, a successful save results in no damage.</p>
<h3 id="magic-ring-ring_of_evasion-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/jump">jump</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _ring_of_x_ray_vision = {title: "Ring of X-Ray Vision", jsx: <><h2 id="magic-ring-ring_of_x_ray_vision-ring-of-x-ray-vision">Ring of X-Ray Vision</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 177</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 6th<br/><strong>Slot</strong> ring; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> -</p>
<p>On command, this ring gives its wearer the ability to see into and through solid matter. Vision range is 20 feet, with the viewer seeing as if he were looking at something in normal light even if there is no illumination. X-ray vision can penetrate 1 foot of stone, 1 inch of common metal, or up to 3 feet of wood or dirt. Thicker substances or a thin sheet of lead blocks the vision.</p>
<p>Using the ring is exhausting, causing the wearer 1 point of <Link to="/rule/constitution_damage">Constitution damage</Link> per minute after the first 10 minutes of use in a single day. The ring must be used in 1-minute increments.</p>
<h3 id="magic-ring-ring_of_x_ray_vision-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _witness_hunters_ring = {title: "Witness Hunter's Ring", jsx: <><h2 id="magic-ring-witness_hunters_ring-witness-hunters-ring">Witness Hunter's Ring</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 56</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 25,200 gp; <strong>Weight</strong> -</p>
<p>This ring's deep red stone hides the image of an eye within an eye or the symbol of a secret society, since many secret societies create these rings to protect their most important agents and leaders. By concentrating on the ring as a move action, the wearer learns whether he is being observed and whether it is by one or by more than one creature. Once per day, the wearer can use <em>locate creature</em> on command to target creatures that are currently observing him. In addition, the wearer can cast <em>detect scrying</em> once per day on command.</p>
<h3 id="magic-ring-witness_hunters_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/detect_scrying">detect scrying</Link>, <Link to="/spell/locate_creature">locate creature</Link>; <strong>Cost</strong> 12,600 gp</p>
</>};
const _swarmwalkers_ring = {title: "Swarmwalker's Ring", jsx: <><h2 id="magic-ring-swarmwalkers_ring-swarmwalkers-ring">Swarmwalker's Ring</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 242</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 26,000 gp; <strong>Weight</strong> -</p>
<p>This shining, ash-white ring of bone is crafted to look like countless interlocking rat fangs, set with a dozen dark, garnet eyes like those of albino sewer-hunters. The wearer of this ring can utter a command word to call forth 1d3 <Link to="/monster/rat_swarm">rat swarms</Link> within 40 feet. These swarms each act immediately and vanish after 7 rounds. They are independent and not under the wearer's control, though the wearer is immune to the effects and attacks of any swarm created through use of this ring.</p>
<p>Alternatively, upon command, the ring's wearer can use <em>dimension door.</em> This magical transportation must begin and end in a square that includes a swarm summoned by use of this ring.</p>
<p>This ring's abilities can be used a total of three times per day, in any combination. An <Link to="/arc-druid/urban_druid">urban druid</Link> wearing this ring can gain one additional use per day by expending three daily uses of her wild shape ability.</p>
<h3 id="magic-ring-swarmwalkers_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/dimension_door">dimension door</Link>, <Link to="/spell/summon_swarm">summon swarm</Link>; <strong>Cost</strong> 13,000 gp</p>
</>};
const _ring_of_blinking = {title: "Ring of Blinking", jsx: <><h2 id="magic-ring-ring_of_blinking-ring-of-blinking">Ring of Blinking</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 168</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 27,000 gp; <strong>Weight</strong> -</p>
<p>On command, this ring makes the wearer blink, as the <em>blink</em> spell.</p>
<h3 id="magic-ring-ring_of_blinking-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/blink">blink</Link>; <strong>Cost</strong> 13,500 gp</p>
</>};
const _ring_of_the_ecclesiarch = {title: "Ring of the Ecclesiarch", jsx: <><h2 id="magic-ring-ring_of_the_ecclesiarch-ring-of-the-ecclesiarch">Ring of the Ecclesiarch</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 175</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 5th<br/><strong>Slot</strong> ring; <strong>Price</strong> 28,500 gp; <strong>Weight</strong> -</p>
<p>This ornate ring of sanctified silver is engraved with a golden signet that incorporates the holy symbol of the wearer's deity after being worn for 24 hours. The ring can be used to seal parchments or to mark any surface as the <em>arcane mark</em> spell at will. The wearer is marked as a scholarly leader of the faith and gains a +5 competence bonus on Diplomacy and Knowledge (religion) checks. If the wearer has the <Link to="/feat/leadership">Leadership</Link> feat, she may attract double the normal number of followers, and her followers' zealous devotion grants them a +4 morale bonus on Will saves against enchantment spells and effects.</p>
<p>Once per day, the wearer of the ring can use <em>prayer</em> and <em>enter image,</em> often using the latter power to speak and observe through portraits, statues, and even minted coinage bearing their likeness.</p>
<h3 id="magic-ring-ring_of_the_ecclesiarch-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/arcane_mark">arcane mark</Link>, <Link to="/spell/enter_image">enter image</Link>, <Link to="/spell/enthrall">enthrall</Link>, <Link to="/spell/prayer">prayer</Link>, creator must have 5 ranks of Diplomacy and Knowledge (religion) and the ability to cast divine spells; <strong>Cost</strong> 14,250 gp</p>
</>};
const _elemental_ring = {title: "Elemental Ring", jsx: <><h2 id="magic-ring-elemental_ring-elemental-ring">Elemental Ring</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions pg. 11</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> ring; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This ornate ring has a thick iron band covered in sigils of calling, and is set with a large glowing gemstone that appears to be an elemental gem. The ring serves as a gateway for a specific elder elemental (25% chance each for air, earth, fire, or water) that performs a narrow range of services when called.</p>
<p>When activated with a command word, the <Link to="/family/elemental">elemental</Link> is called (as by <Link to="/spell/greater_planar_ally">greater planar ally</Link>) and demands to know what service it is to perform. It can only be commanded to protect a specific creature or object, attack a specific creature, damage a specific object, or answer questions about its home plane. The wearer of the ring is able to communicate with the elder elemental as if they shared a common language. The elder elemental serves for no more than 24 hours, after which it returns to its home plane and the ring become a valueless hunk of lead.</p>
<h3 id="magic-ring-elemental_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_ally">planar ally</Link>, <Link to="/spell/planar_binding">planar binding</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _planefarers_band = {title: "Planefarer's Band", jsx: <><h2 id="magic-ring-planefarers_band-planefarers-band">Planefarer's Band</h2>
<p><strong>Sources</strong> <Link to="/source/planes_of_power">Planes of Power pg. 9</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> ring; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> -</p>
<p>Once per day, the wearer of this ring can attune it to one of the four Elemental Planes for 24 hours. While on that plane, the ring grants the wearer the corresponding benefits below. Once per day on command, the wearer can gain these benefits even when on a different plane, but the effects last only 10 minutes.</p>
<p><strong className="hl">Plane of Air:</strong> The wearer gains a fly speed of 20 feet (average) and gains a +4 insight bonus on Wisdom checks to change the direction of gravity in an area with the <Link to="/rule/gravity_traits">subjective gravity planar trait</Link>.</p>
<p><strong className="hl">Plane of Earth:</strong> The wearer gains darkvision with a range of 60 feet, and she can walk across rock, metal, and other earthen surfaces as if under the effects of <Link to="/spell/spider_climb">spider climb</Link>.</p>
<p><strong className="hl">Plane of Fire:</strong> The wearer gains fire resistance 20 and is able to walk atop lava, bubbling tar, and other dangerously hot surfaces as if under the effects of <Link to="/spell/water_walk">water walk</Link>.</p>
<p><strong className="hl">Plane of Water</strong>: The wearer can breathe underwater and gains a swim speed of 40 feet.</p>
<h3 id="magic-ring-planefarers_band-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/planar_adaptation">planar adaptation</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _ring_of_transcendent_spells = {title: "Ring of Transcendent Spells", jsx: <><h2 id="magic-ring-ring_of_transcendent_spells-ring-of-transcendent-spells">Ring of Transcendent Spells</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 156</Link><br/><strong>Aura</strong> strong universal; <strong>CL</strong> 13th<br/><strong>Slot</strong> ring; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> -</p>
<p>This jade ring is carved in the shape of an <Link to="/monster/ouroboros">ouroboros</Link>. Three times per day, the wearer can use it to empower a spell she casts. This grants her a +2 bonus on caster level checks to overcome spell resistance, and increases the save DC of the spell (if any) by 2.</p>
<p>While enhancing a spell this way, the caster can expend one use of mythic power plus an additional use per two spell levels (minimum two uses), to instead cast the mythic version of her spell (though not an augmented version of the mythic spell) as if she knew the mythic version of that spell. This has no effect if the spell doesn't have a mythic version. The save DC increase for being a <Link to="/rule/mythic_spells">potent mythic spell</Link> stacks with the save DC increase granted by using the ring's power.</p>
<p>For example, if the wearer enhances <Link to="/spell/fireball">fireball</Link> with this ring, she can expend two uses of mythic power to cast <em>mythic fireball</em> instead (one use plus one use for a 3rd-level spell).</p>
<h3 id="magic-ring-ring_of_transcendent_spells-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/limited_wish">limited wish</Link>, <Link to="/spell/mnemonic_enhancer">mnemonic enhancer</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _rings_of_alien_geometries = {title: "Rings of Alien Geometries", jsx: <><h2 id="magic-ring-rings_of_alien_geometries-rings-of-alien-geometries">Rings of Alien Geometries</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 216</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> ring; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> -</p>
<p>A short silver chain joins these two crystal rings together. When worn on two adjacent fingers of the same hand, the two rings occupy a single ring slot. Once per day as a standard action, the wearer of a pair of rings of alien geometries can create two shimmering portals, each 5 feet in diameter and surrounded by a 4-inch-thick ring of force. Only one side of each portal functions as a gateway; the other side is blocked (as if by a <em>wall of force</em>). Each portal must be oriented vertically and be within 30 feet of the wearer at the time of creation. Medium or smaller creatures can move through either portal as easily as moving to an adjacent square, stepping out of the other portal. Large creatures can squeeze through but can't end movement halfway through a portal. Any creature farther than 5 feet away from a portal has no line of sight or line of effect through it to the other portal, but a creature adjacent to one of the portals can attack through it as though the square directly in front of the other portal were adjacent to the creature.</p>
<p>Both of the portals vanish after 10 rounds. Destroying a portal is possible only with spells or attacks that can destroy a <em>wall of force.</em> Destroying one portal causes the other portal to immediately collapse.</p>
<h3 id="magic-ring-rings_of_alien_geometries-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/dimension_door">dimension door</Link>, <Link to="/spell/wall_of_force">wall of force</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _ring_of_resumption = {title: "Ring of Resumption", jsx: <><h2 id="magic-ring-ring_of_resumption-ring-of-resumption">Ring of Resumption</h2>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook pg. 30</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 30,800 gp; <strong>Weight</strong> -</p>
<p>This <Link to="/eq-material/adamantine">adamantine</Link> ring contains a moving, notched golden circle that whirs with healing energy when activated. Once per day when the wearer takes hit point damage by any means, she can activate the ring as an immediate action. This immediately allows a living wearer to regain 5 hit points per round and recover from an equal amount of nonlethal damage. The wearer regenerates a total number of hit points equal only to the damage taken when the ring was activated, and only a single attack (or another single instance) can activate the ring. If the wearer sustains damage from multiple sources simultaneously, she must pick which source activates the ring. When either all of this damage is healed or the wearer's hit points reach her hit point maximum (whichever comes first), the hit point regeneration ceases.</p>
<p>In addition, the wearer is immune to <Link to="/rule/bleed">bleed</Link> damage while the ring's regeneration is active. If the wearer lost a limb, an organ, or any other body part as a result of the effect she used to activate the ring, the ring regenerates it as per <em>regenerate.</em> As with the spell, if the severed members are not present and touching the creature, this regenerate effect takes 2d10 rounds (this may cause the regenerate effect affecting a lost limb or organ to last longer than the hit point regeneration).</p>
<h3 id="magic-ring-ring_of_resumption-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/regenerate">regenerate</Link>; <strong>Cost</strong> 15,400 gp</p>
</>};
const _ring_of_energy_dampening = {title: "Ring of Energy Dampening", jsx: <><h2 id="magic-ring-ring_of_energy_dampening-ring-of-energy-dampening">Ring of Energy Dampening</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 156</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> ring; <strong>Price</strong> 31,500 gp; <strong>Weight</strong> -</p>
<p>When the wearer is about to take acid, cold, electricity, or fire damage, this band of braided copper and silver writhes like a snake. It provides resistance 5 to acid, cold, electricity, and fire. The wearer can expend one use of mythic power as an immediate action when taking damage of one of these types to upgrade the resistance to immunity for that attack or effect only. Also, once per day when the wearer takes damage of one of these types, the wearer can grant resistance 5 to the energy type damaging him to all allies within 20 feet. This resistance lasts for 1 minute.</p>
<h3 id="magic-ring-ring_of_energy_dampening-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/protection_from_energy">protection from energy</Link>, <Link to="/spell/shield_other">shield other</Link>; <strong>Cost</strong> 15,750 gp</p>
</>};
const _ring_of_refusal = {title: "Ring of Refusal", jsx: <><h2 id="magic-ring-ring_of_refusal-ring-of-refusal">Ring of Refusal</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex pg. 29</Link><br/><strong>Aura</strong> strong conjuration and transmutation; <strong>CL</strong> 13th<br/><strong>Slot</strong> ring; <strong>Price</strong> 32,500 gp; <strong>Weight</strong> -</p>
<p>Powerful <Link to="/race/gillmen">gillmen</Link> who suspect they harbor unwitting allegiance to hidden masters use rings of refusal to resist such bonds. The wearer of a ring of refusal gains a +2 bonus on saving throws against enchantment spells and effects. When the wearer is targeted by <em>break enchantment</em> or a similar effect that ends an enchantment, the caster gains a +2 bonus on caster level checks to resolve the effect.</p>
<p>The wearer can also activate the ring once per day as an immediate action to gain spell resistance 25 against a single enchantment spell or effect.</p>
<h3 id="magic-ring-ring_of_refusal-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/break_enchantment">break enchantment</Link>, <Link to="/spell/spell_resistance">spell resistance</Link>; <strong>Cost</strong> 16,250 gp</p>
</>};
const _sihedron_ring = {title: "Sihedron Ring", jsx: <><h2 id="magic-ring-sihedron_ring-sihedron-ring">Sihedron Ring</h2>
<p><strong>Sources</strong> <Link to="/source/rise_of_the_runelords_anniversary_edition">Rise of the Runelords Anniversary Edition pg. 426</Link>, <Link to="/source/pathfinder_6_spires_of_xin_shalast">Pathfinder #6: Spires of Xin-Shalast pg. 37</Link><br/><strong>Aura</strong> moderate abjuration and illusion; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 35,000 gp; <strong>Weight</strong> -</p>
<p>This otherwise plain ring is adorned with a tiny Sihedron rune. These rings were given to agents and allies of the runelords as badges of office and tokens of appreciation for their work - sometimes, they were given as bribes to those a runelord was attempting to win to his cause. Like the more common <Link to="/magic-wondrous/sihedron_medallion">Sihedron medallion</Link>, runelords have special links to Sihedron rings that aid in scrying and observation of the world around the wearer of the ring.</p>
<p>A Sihedron ring grants a +3 deflection bonus to AC, a +3 resistance bonus on all saving throws, and protects the wearer with a constant <em>endure elements</em> effect. At will, as a standard action, the wearer can use the Sihedron ring to change the appearance of his clothing or armor into any other kind of clothing or armor. The actual clothing and armor worn retain all their properties (including weight) when glamered. Only <Link to="/spell/true_seeing">true seeing</Link> or similar magic reveals the true nature of the adornments.</p>
<h3 id="magic-ring-sihedron_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/resistance">resistance</Link>, <Link to="/spell/shield">shield</Link>; <strong>Cost</strong> 17,500 gp</p>
</>};
const _ring_of_freedom_of_movement = {title: "Ring of Freedom of Movement", jsx: <><h2 id="magic-ring-ring_of_freedom_of_movement-ring-of-freedom-of-movement">Ring of Freedom of Movement</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 171</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 40,000 gp; <strong>Weight</strong> -</p>
<p>This gold ring allows the wearer to act as if continually under the effect of a freedom of movement spell.</p>
<h3 id="magic-ring-ring_of_freedom_of_movement-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/freedom_of_movement">freedom of movement</Link>; <strong>Cost</strong> 20,000 gp</p>
</>};
const _rings_of_bondage_greater = {title: "Greater Rings of Bondage", jsx: <><h2 id="magic-ring-rings_of_bondage_greater-greater-rings-of-bondage">Greater Rings of Bondage</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 242</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 11th<br/><strong>Slot</strong> ring; <strong>Price</strong> 42,000 gp; <strong>Weight</strong> -</p>
<p>These specialized rings function as <Link to="/magic-ring/rings_of_bondage">rings of bondage</Link>, but a command imposed by the wearer of the master ring (including a mutual agreement affecting both wearers) takes 10 minutes to activate, is permanent, and functions as <em>geas/quest,</em> except a DC 16 Will save still negates it.</p>
<p>In addition, the wearer of the master ring gains a continuous <em>sanctuary</em> (DC 16) effect against the wearer of the servant ring, with a save required for every attack the servant makes against the master (including area attacks, but no save is required when directing allies or controlled creatures to attack the wearer); a failed save prevents only that single attack. Each time the servant successfully attacks the master, he must succeed at a second DC 16 Will save or be affected as <em>bestow curse.</em></p>
<h3 id="magic-ring-rings_of_bondage_greater-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>, <Link to="/spell/geas_quest">geas/quest</Link>, <Link to="/spell/sanctuary">sanctuary</Link>, <Link to="/spell/share_language">share language</Link>, <Link to="/spell/status">status</Link>; <strong>Cost</strong> 21,000 gp</p>
</>};
const _ring_of_fear_reflection = {title: "Ring of Fear Reflection", jsx: <><h2 id="magic-ring-ring_of_fear_reflection-ring-of-fear-reflection">Ring of Fear Reflection</h2>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook pg. 31</Link></p>
<p><strong>Aura</strong> moderate abjuration and necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 48,000 gp; <strong>Weight</strong> -</p>
<p>This simple silver ring has a fear rune etched into its hammered apex. The ring provides a morale bonus versus fear effects. This bonus starts at +0 and can advance no higher than +5.</p>
<p>Every time the wearer succeeds at a Will save versus a fear affect, the ring's bonus increases by +1. Should the wearer fail a Will save versus fear, the ring's bonus immediately falls to +0.</p>
<p>If the bonus is +5 and the wearer is affected by a fear effect and succeeds at her Will save, the ring automatically reflects the fear effect back to its source. If the source is a creature not immune to fear, it must succeed at a Will save at the DC made by the ring's wearer or be affected by the fear effect. Only the source of an area fear effect is targeted by such a reflected spell.</p>
<h3 id="magic-ring-ring_of_fear_reflection-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/fear">fear</Link>, <Link to="/spell/remove_fear">remove fear</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 24,000 gp</p>
</>};
const _band_of_triumph = {title: "Band of Triumph", jsx: <><h2 id="magic-ring-band_of_triumph-band-of-triumph">Band of Triumph</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_131_the_reapers_right_hand">Pathfinder #131: The Reaper's Right Hand pg. 35</Link><br/><strong>Aura</strong> strong enchantment and evocation; <strong>CL</strong> 13th<br/><strong>Slot</strong> ring; <strong>Price</strong> 50,000 gp; <strong>Weight</strong> -</p>
<p>This white-gold ring bears the relief image of a roaring lion. Once per day on command, the wearer can point the ring and mentally designate one or more creatures or objects in a 60-foot cone as enemies, after which the ring roars triumphantly. Selected targets in the area are affected by <em>shout</em> (Fortitude DC 20). All other objects in the area are unharmed, and all other creatures in the area receive the benefits of the <Link to="/performance/inspire_courage">inspire courage</Link> bardic performance as performed by a 7th-level bard for 3 rounds. When activating the ring, the wearer can expend 1 round of her bardic performance ability to use her own bard level to calculate the performance's effect.</p>
<p>In addition, the ring grants the wearer a +4 enhancement bonus to Charisma; treat this as a <Link to="/rule/temporary_ability_bonus">temporary ability bonus</Link> for the first 24 hours the ring is worn.</p>
<h3 id="magic-ring-band_of_triumph-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/good_hope">good hope</Link>, <Link to="/spell/shout">shout</Link>; <strong>Cost</strong> 25,000 gp</p>
</>};
const _ring_of_friend_shield = {title: "Ring of Friend Shield", jsx: <><h2 id="magic-ring-ring_of_friend_shield-ring-of-friend-shield">Ring of Friend Shield</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 171</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> ring; <strong>Price</strong> 50,000 gp; <strong>Weight</strong> -</p>
<p>These curious rings always come in pairs. A ring of friend shield without its mate is useless. Either wearer of one of a pair of the rings can, at any time, command his ring to cast a <em>shield other</em> spell with the wearer of the mated ring as the recipient. This effect has no range limitation.</p>
<h3 id="magic-ring-ring_of_friend_shield-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/shield_other">shield other</Link>; <strong>Cost</strong> 25,000 gp</p>
</>};
const _ring_of_psychic_mastery = {title: "Ring of Psychic Mastery", jsx: <><h2 id="magic-ring-ring_of_psychic_mastery-ring-of-psychic-mastery">Ring of Psychic Mastery</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 252</Link><br/><strong>Aura</strong> strong (no school); <strong>CL</strong> 14th<br/><strong>Slot</strong> ring; <strong>Price</strong> 50,000 gp; <strong>Weight</strong> -</p>
<p>The large sapphire that adorns this platinum ring darkens in hue as its wearer depletes her psychic spellcasting potential. The gem turns black when the wearer's daily spells are exhausted or if the wearer has no ability to cast psychic spells. A ring of psychic mastery grants the caster 1 additional psychic spell per day for each spell level from 1st to 4th that she is capable of casting.</p>
<h3 id="magic-ring-ring_of_psychic_mastery-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/limited_wish">limited wish</Link>; <strong>Cost</strong> 25,000 gp</p>
</>};
const _ring_of_shooting_stars = {title: "Ring of Shooting Stars", jsx: <><h2 id="magic-ring-ring_of_shooting_stars-ring-of-shooting-stars">Ring of Shooting Stars</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 173</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 12th<br/><strong>Slot</strong> ring; <strong>Price</strong> 50,000 gp; <strong>Weight</strong> -</p>
<p>This ring has two modes of operation: one for when the wearer is in <Link to="/rule/dim_light">dim light</Link> or outdoors at night, and a second one when the wearer is underground or indoors at night. At night or in areas of shadow or darkness, the ring of shooting stars can perform the following functions on command.</p>
<ul>
<li><Link to="/spell/dancing_lights">Dancing lights</Link> (once per hour)</li>
<li><em>Light</em> (twice per night)</li>
<li>Ball lightning (special, once per night)</li>
<li>Shooting stars (special, three per week)</li>
</ul>
<p>The first special function, ball lightning, releases one to four balls of lightning (ring wearer's choice). These glowing globes resemble <em>dancing lights,</em> and the wearer controls them similarly (see the <em>dancing lights</em> spell description). The spheres have a 120-foot range and a duration of 4 rounds. They can be moved at 120 feet per round. Each sphere is about 3 feet in diameter, and any creature who comes within 5 feet of one causes its charge to dissipate, taking electricity damage in the process according to the number of balls created.</p>
<ScrollContainer id="magic-ring-ring_of_shooting_stars--table-0"><table>
<thead>
<tr>
<th>Number of Balls</th>
<th>Damage per Ball</th>
</tr>
</thead>
<tbody><tr>
<td>1 lightning ball</td>
<td>4d6 points of electricity damage</td>
</tr>
<tr>
<td>2 lightning balls</td>
<td>3d6 points of electricity damage</td>
</tr>
<tr>
<td>3 lightning balls</td>
<td>2d6 points of electricity damage</td>
</tr>
<tr>
<td>4 lightning balls</td>
<td>1d6 points of electricity damage</td>
</tr>
</tbody></table></ScrollContainer>
<p>Once the ball lightning function is activated, the balls can be released at any time before the sun rises. Multiple balls can be released in the same round.</p>
<p>The second special function produces three shooting stars that can be released from the ring each week, simultaneously or one at a time. Upon impact, they deal 12 points of damage and <Link to="/misc/spread">spread</Link> (as a <em>fireball</em>) in a 5-foot-radius sphere that deals 24 points of fire damage.</p>
<p>Any creature struck by a shooting star takes full damage from the impact plus full fire damage from the spread unless it succeeds at a DC 13 Reflex save. Creatures not struck but within the spread ignore the impact damage and take only half damage from the fire spread on a successful DC 13 Reflex save. The range is 70 feet, at the end of which the shooting star explodes unless it strikes a creature or object before that. A shooting star always follows a straight line, and any creature in its path must make a successful DC 13 Reflex save or be hit by the projectile.</p>
<p>Indoors at night, or underground, the ring of shooting stars has the following properties.</p>
<ul>
<li><em>Faerie fire</em> (once per day)</li>
<li>Spark shower (special, once per day)</li>
</ul>
<p>The spark shower is a flying cloud of sizzling purple sparks that fan out from the ring for a distance of 20 feet in an arch 10 feet wide. Creatures within this area take 2d8 points of damage each if not wearing metal armor or carrying metal weapons. Any creature wearing metal armor and/or carrying a metal weapon takes 4d8 points of damage.</p>
<h3 id="magic-ring-ring_of_shooting_stars-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/faerie_fire">faerie fire</Link>, <Link to="/spell/fireball">fireball</Link>, <Link to="/spell/light">light</Link>, <Link to="/spell/lightning_bolt">lightning bolt</Link>; <strong>Cost</strong> 25,000 gp</p>
</>};
const _ring_of_spell_storing = {title: "Ring of Spell Storing", jsx: <><h2 id="magic-ring-ring_of_spell_storing-ring-of-spell-storing">Ring of Spell Storing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 174</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 50,000 gp; <strong>Weight</strong> -</p>
<p>A ring of spell storing contains up to 5 levels of spells (either divine or arcane, or even a mix of both spell types) that the wearer can cast. Each spell has a caster level equal to the minimum level needed to cast that spell. The user need not provide any material components or focus to cast the spell, and there is no arcane spell failure chance for wearing armor (because the ring wearer need not gesture). The activation time for the ring is the same as the casting time for the relevant spell, with a minimum of 1 standard action.</p>
<p>For a randomly generated ring, treat it as a <Link to="/rule/random_scrolls">scroll</Link> to determine what spells are stored in it. If you roll a spell that would put the ring over the five-level limit, ignore that roll; the ring has no more spells in it.</p>
<p>A spellcaster can cast any spells into the ring, so long as the total spell levels do not add up to more than 5. Metamagic versions of spells take up storage space equal to their spell level modified by the metamagic feat. A spellcaster can use a scroll to put a spell into the ring of spell storing.</p>
<p>The ring magically imparts to the wearer the names of all spells currently stored within it.</p>
<h3 id="magic-ring-ring_of_spell_storing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/imbue_with_spell_ability">imbue with spell ability</Link>; <strong>Cost</strong> 25,000 gp</p>
</>};
const _ring_of_continuation = {title: "Ring of Continuation", jsx: <><h2 id="magic-ring-ring_of_continuation-ring-of-continuation">Ring of Continuation</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 168</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 56,000 gp; <strong>Weight</strong> -</p>
<p>This band of braided copper wires throbs ever so slightly in harmony with its wearer's heartbeat. Whenever the wearer of this ring casts a spell with a range of personal and a duration of 10 minutes per level or greater, that spell remains in effect for 24 hours or until the wearer casts another spell with a range of personal (whichever comes first). Spells that usually only affect one specific action (such as making a particular attack) are expended after that action. This does not reduce the duration of spells that normally last longer than 24 hours. Casting a new spell does not eliminate a previous spell if its normal duration is such that it would still be in effect. However, attempts to <Link to="/spell/dispel">dispel</Link> or otherwise eliminate a spell kept active by the ring work normally and, if successful, remove the spell from the ring, causing the wearer to lose all benefits from that spell.</p>
<h3 id="magic-ring-ring_of_continuation-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/mnemonic_enhancer">mnemonic enhancer</Link>; <strong>Cost</strong> 28,000 gp</p>
</>};
const _survivors_ring = {title: "Survivor's Ring", jsx: <><h2 id="magic-ring-survivors_ring-survivors-ring">Survivor's Ring</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 56</Link><br/><strong>Aura</strong> strong illusion; <strong>CL</strong> 18th<br/><strong>Slot</strong> ring; <strong>Price</strong> 56,160 gp; <strong>Weight</strong> -</p>
<p>This ring is shaped like a silver snake with an onyx in its mouth. Once per day, if the wearer would be reduced to 0 or fewer hit points but not be dead, she is instead reduced to 0 hit points and subject to an effect similar to <em>mislead.</em> Her illusory double appears to die or to take on the <Link to="/misc/dying">dying</Link> condition in her place, as appropriate for the negated effect. The wearer cannot control the double. In addition, the wearer can touch the ring's stone as a standard action once per day to use <em>dimension door</em> but only while the ring's <em>mislead</em> effect is active.</p>
<h3 id="magic-ring-survivors_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/death_ward">death ward</Link>, <Link to="/spell/dimension_door">dimension door</Link>, <Link to="/spell/mislead">mislead</Link>; <strong>Cost</strong> 25,080 gp</p>
</>};
const _spiritualist_rings = {title: "Spiritualist Rings", jsx: <><h2 id="magic-ring-spiritualist_rings-spiritualist-rings">Spiritualist Rings</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 177</Link><br/><strong>Aura</strong> strong necromancy; <strong>CL</strong> 12th<br/><strong>Slot</strong> ring; <strong>Price</strong> 70,000 gp; <strong>Weight</strong> -</p>
<p>These four garish and gaudy rings must be worn on one hand, though they take up only a single ring slot. They grant the wearer the ability to commune with and affect the dead in the following ways.</p>
<ul>
<li>The wearer can use <em>speak with dead,</em> as the spell, three times per day. It takes 10 minutes to use this ability.</li>
<li>The wearer can use <em>spectral hand,</em> as the spell, three times per day.</li>
<li>The wearer's weapons gain the <Link to="/magic-enh/ghost_touch">ghost touch</Link> weapon special ability while the wearer is wielding the weapons.</li>
<li>The wearer gains a +4 sacred or profane bonus on saving throws against positive and negative energy effects. The bonus depends on the wearer's alignment: good-aligned wearers gain a sacred bonus, whereas evil-aligned wearers gain a profane bonus. Neutral-aligned wearers pick either a sacred or profane bonus when the ring is first put on, which cannot be changed later.</li>
</ul>
<h3 id="magic-ring-spiritualist_rings-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/speak_with_dead">speak with dead</Link>, <Link to="/spell/spectral_hand">spectral hand</Link>, <Link to="/spell/plane_shift">plane shift</Link>; <strong>Cost</strong> 45,000 gp</p>
</>};
const _ring_of_telekinesis = {title: "Ring of Telekinesis", jsx: <><h2 id="magic-ring-ring_of_telekinesis-ring-of-telekinesis">Ring of Telekinesis</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 175</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 75,000 gp; <strong>Weight</strong> -</p>
<p>This ring, knotted with metallic tendrils encasing a setting of red and amber gemstones, allows the caster to use the spell <em>telekinesis</em> on command, lifting and manipulating objects at a distance using only her mind.</p>
<h3 id="magic-ring-ring_of_telekinesis-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/telekinesis">telekinesis</Link>; <strong>Cost</strong> 37,500 gp</p>
</>};
const _ring_of_regeneration = {title: "Ring of Regeneration", jsx: <><h2 id="magic-ring-ring_of_regeneration-ring-of-regeneration">Ring of Regeneration</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 172</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> ring; <strong>Price</strong> 90,000 gp; <strong>Weight</strong> -</p>
<p>This white gold ring is generally set with a large green sapphire. When worn, the ring continually allows a living wearer to heal 1 point of damage per round and an equal amount of nonlethal damage. In addition, the wearer is immune to <Link to="/rule/bleed">bleed</Link> damage while wearing a ring of regeneration. If the wearer loses a limb, an organ, or any other body part while wearing this ring, the ring regenerates it as the spell <em>regenerate.</em> In either case, only damage taken while wearing the ring is regenerated.</p>
<h3 id="magic-ring-ring_of_regeneration-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/regenerate">regenerate</Link>; <strong>Cost</strong> 45,000 gp</p>
</>};
const _ring_of_spell_turning = {title: "Ring of Spell Turning", jsx: <><h2 id="magic-ring-ring_of_spell_turning-ring-of-spell-turning">Ring of Spell Turning</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 174</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> ring; <strong>Price</strong> 100,000 gp; <strong>Weight</strong> -</p>
<p>Up to three times per day on command, this simple platinum band automatically reflects the next nine levels of spells cast at the wearer, exactly as if <em>spell turning</em> had been cast upon him.</p>
<h3 id="magic-ring-ring_of_spell_turning-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/spell_turning">spell turning</Link>; <strong>Cost</strong> 50,000 gp</p>
</>};
const _ring_of_the_shadow_victim = {title: "Ring of the Shadow Victim", jsx: <><h2 id="magic-ring-ring_of_the_shadow_victim-ring-of-the-shadow-victim">Ring of the Shadow Victim</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 241</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 101,000 gp; <strong>Weight</strong> -</p>
<p>This smooth, lusterless gray ring is crafted of dark glass and has the image of a body carved into its band. Once per day, the wearer of this ring can perform a complex mental and verbal ritual, repeatedly whispering the ring's command word, while touching any humanoid corpse that has been dead for less than 1 week. The creature must have had 7 Hit Dice or fewer in life. This ritual can be as short as 1 round or could last up to 24 hours. It requires both total focus and constant contact between the ring, the wearer, and the target corpse. Interruption of any kind spoils the ritual, requiring the wearer to begin anew. The wearer of the ring chooses how long this ritual will last, but that decision must be made before she begins the ritual.</p>
<p>On the ritual's completion, an illusory duplicate of the creature touched - partially real and formed of animate ice cloaked in magical shadow - springs into existence. This functions as <em>lesser simulacrum</em> in all ways unless stated otherwise. The wearer of this ring gains a +10 bonus on the Disguise check when performing this ritual. The shadow creature appears in all ways to be hearty and full of life, equipped with all of the gear and clothing that was carried or worn by the corpse throughout the ritual. At the same moment the shadow creature is completed, the targeted corpse and all of its attendant equipment vanishes, melting away like snow.</p>
<p>The false creature brought into existence by the ring of the shadow victim has the same base ability scores, type, and subtype as the targeted corpse. It appears in all ways to be the same individual as the corpse touched, and it retains the general personality, attitude, abilities, and intellect of that creature. However, this duplicate doesn't possess any memories that the wearer of the ring doesn't also possess, has no spell-like or supernatural abilities, can't use activated extraordinary abilities, can't gain the benefits of healing, can't gain levels or increase its abilities, and can't have more than 3 Hit Dice.</p>
<p>This false creature behaves much like the target did in life, except it has a starting attitude of helpful toward the ring's wearer and is generally willing to assist the wearer in any endeavor. The shadow creature will take nearly any action to aid the wearer of the ring, including dangerous, foolish or suicidal actions. This semi-illusory creature remains in existence for a duration equal to 7 &times; the length of the initial ritual that created it, until the wearer removes the ring of the shadow victim, until the wearer activates the ring again, or until the creature is destroyed by violence, whichever comes first. At that time, the duplicate vanishes and the original corpse, unchanged from when the initial ritual was completed, appears in its place.</p>
<h3 id="magic-ring-ring_of_the_shadow_victim-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/alter_self">alter self</Link>, <Link to="/spell/gentle_repose">gentle repose</Link>, <Link to="/spell/lesser_simulacrum">lesser simulacrum</Link>; <strong>Cost</strong> 50,500 gp</p>
</>};
const _ring_of_three_wishes = {title: "Ring of Three Wishes", jsx: <><h2 id="magic-ring-ring_of_three_wishes-ring-of-three-wishes">Ring of Three Wishes</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 176</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> strong universal; <strong>CL</strong> 20th<br/><strong>Slot</strong> ring; <strong>Price</strong> 120,000 gp; <strong>Weight</strong> -</p>
<p>This ring is set with three rubies. Each ruby stores a <em>wish</em> spell, activated by the ring. When a <em>wish</em> is used, that ruby disappears. For a randomly generated ring, roll 1d3 to determine the remaining number of rubies. When all the <em>wishes</em> are used, the ring becomes a nonmagical item.</p>
<h3 id="magic-ring-ring_of_three_wishes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/miracle">miracle</Link> or <Link to="/spell/wish">wish</Link>; <strong>Cost</strong> 97,500 gp</p>
</>};
const _ring_of_djinni_calling = {title: "Ring of Djinni Calling", jsx: <><h2 id="magic-ring-ring_of_djinni_calling-ring-of-djinni-calling">Ring of Djinni Calling</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 169</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 17th<br/><strong>Slot</strong> ring; <strong>Price</strong> 125,000 gp; <strong>Weight</strong> -</p>
<p>This "genie" ring serves as a special gate by means of which a specific <Link to="/monster/djinni">djinni</Link> can be called from the Plane of Air. When the ring is rubbed (a standard action), the call goes out, and the djinni appears on the next round. The djinni faithfully obeys and serves the wearer of the ring, but never for more than 1 hour per day. If the djinni of the ring is ever killed, the ring becomes nonmagical and worthless.</p>
<h3 id="magic-ring-ring_of_djinni_calling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/gate">gate</Link>; <strong>Cost</strong> 62,500 gp</p>
</>};
const _ring_of_the_recalled_soul = {title: "Ring of the Recalled Soul", jsx: <><h2 id="magic-ring-ring_of_the_recalled_soul-ring-of-the-recalled-soul">Ring of the Recalled Soul</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_132_the_six_legend_soul">Pathfinder #132: The Six-Legend Soul pg. 28</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 18th<br/><strong>Slot</strong> ring; <strong>Price</strong> 150,000 gp; <strong>Weight</strong> -</p>
<p>The ring of the recalled soul allows the wearer to open a door into a nearby mindscape they are aware of as if using the spell <em>mindscape door,</em> but the targeted creature cannot resist this effect with a Will save. If the ring's wearer connects to the mindscape, he can designate up to 10 other creatures to be able to see and pass through the door as though it were a normal doorway. The ring grants no ability to detect mindscapes, so the wearer must already be aware of its existence via interactions, hearsay, or the <Link to="/spell/detect_mindscape">detect mindscape</Link> spell.</p>
<p>Once the ring's wearer has connected to the mindscape, he can open the door to that particular mindscape from anywhere on the same plane, so long as the mindscape still exists. Physical distance poses no barrier to the mindscape. Each time the ring's wearer opens the door to a mindscape he has previously visited, he can alter the designated creatures allowed to pass through the door as if he were opening the door for the first time.</p>
<p>The ring's wearer cannot prevent creatures within the mindscape from exiting to the real world so long as the door is open. The ring's wearer can close the door to the mindscape at any time as long as he is not within the mindscape.</p>
<h3 id="magic-ring-ring_of_the_recalled_soul-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/mindscape_door">mindscape door</Link>; <strong>Cost</strong> 75,000 gp</p>
</>};
const _ring_of_the_hidden_psyche = {title: "Ring of the Hidden Psyche", jsx: <><h2 id="magic-ring-ring_of_the_hidden_psyche-ring-of-the-hidden-psyche">Ring of the Hidden Psyche</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 252</Link><br/><strong>Aura</strong> strong (no school); <strong>CL</strong> 18th<br/><strong>Slot</strong> ring; <strong>Price</strong> 160,000 gp; <strong>Weight</strong> -</p>
<p>This ring resembles a <Link to="/magic-ring/ring_of_psychic_mastery">ring of psychic mastery</Link>, but its flawless sapphire serves as a vessel for the wearer's soul. It possesses all the abilities of a ring of psychic mastery in addition to the following effects.</p>
<p>The wearer's soul instantly enters the ring upon the wearer's death, even if her body is utterly destroyed. This counts as an <em>object possession</em> spell, except that the possessing soul cannot animate the ring and must instead wait for someone to wear it. From inside the ring, she can attempt a <em>greater possession</em> on anyone who voluntarily wears the ring (Will DC 23 negates). A successful save against the <em>greater possession</em> effect renders the new wearer immune to further such attempts for 24 hours. Dispelling the <em>object possession</em> effect on the ring banishes the soul from the ring to its appropriate afterlife. Otherwise, a soul can remain in the ring indefinitely. While in the ring, the soul knows when a creature has put on the ring. The soul can't otherwise sense the area around it or take actions other than attempting the <em>greater possession</em> effect.</p>
<p>A ring of the hidden psyche resists attempts to discern its true nature. <Link to="/spell/detect_magic">Detect magic</Link> reveals only the properties of a ring of psychic mastery, though <Link to="/spell/identify">identify</Link> or stronger magic can reveal the ring's full powers if the caster succeeds at a DC 23 Will save.</p>
<h3 id="magic-ring-ring_of_the_hidden_psyche-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/greater_possession">greater possession</Link>, <Link to="/spell/magic_aura">magic aura</Link>, <Link to="/spell/object_possession">object possession</Link>, <Link to="/spell/wish">wish</Link>; <strong>Cost</strong> 80,000 gp</p>
</>};
const _ring_of_splendid_security = {title: "Ring of Splendid Security", jsx: <><h2 id="magic-ring-ring_of_splendid_security-ring-of-splendid-security">Ring of Splendid Security</h2>
<p><strong>Sources</strong> <Link to="/source/curse_of_the_crimson_throne">Curse of the Crimson Throne pg. 435</Link>, <Link to="/source/pathfinder_12_crown_of_fangs">Pathfinder #12: Crown of Fangs pg. 60</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 16th<br/><strong>Slot</strong> ring; <strong>Price</strong> 180,000 gp; <strong>Weight</strong> -</p>
<p>This extravagant ring is heavy with precious jewels. As fashions change (or as the wearer's fancy shifts), the wearer can alter the appearance of her armor, clothing, and even weaponry at will as a standard action; this change is illusory and doesn't affect the actual abilities of gear or weapons (although drastic changes in size are beyond the scope of this ability). A ring of splendid security's primary purpose, though, is to grant the wearer protection from harm. As long as it is worn, the ring grants the wearer a +5 deflection bonus to her AC, a +5 resistance bonus on saving throws, and spell resistance 22.</p>
<h3 id="magic-ring-ring_of_splendid_security-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/minor_image">minor image</Link>, <Link to="/spell/resistance">resistance</Link>, <Link to="/spell/shield">shield</Link> or <Link to="/spell/shield_of_faith">shield of faith</Link>; <strong>Cost</strong> 90,000 gp</p>
</>};
const _ring_of_elemental_command = {hasJL:true,title: "Ring of Elemental Command", jsx: <><div className="jumpList" id="magic-ring-ring_of_elemental_command-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="magic-ring-ring_of_elemental_command-ring-of-elemental-command-air">Ring of Elemental Command (Air)</InnerLink></li><li><InnerLink toTop to="magic-ring-ring_of_elemental_command-ring-of-elemental-command-earth">Ring of Elemental Command (Earth)</InnerLink></li><li><InnerLink toTop to="magic-ring-ring_of_elemental_command-ring-of-elemental-command-fire">Ring of Elemental Command (Fire)</InnerLink></li><li><InnerLink toTop to="magic-ring-ring_of_elemental_command-ring-of-elemental-command-water">Ring of Elemental Command (Water)</InnerLink></li><li><InnerLink toTop to="magic-ring-ring_of_elemental_command-construction">Construction</InnerLink></li></ul></div><h2 id="magic-ring-ring_of_elemental_command-ring-of-elemental-command">Ring of Elemental Command</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 169</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> ring; <strong>Price</strong> 200,000 gp; <strong>Weight</strong> -</p>
<p>All four kinds of rings of elemental command are very powerful. Each appears to be nothing more than a lesser magic ring until fully activated (by meeting a special condition, such as single-handedly slaying an elemental of the appropriate type or exposure to a sacred material of the appropriate element), but each has certain other powers as well as the following common properties.</p>
<p>Elementals of the plane to which the ring is attuned can't attack the wearer, or even approach within 5 feet of her. If the wearer desires, she may forgo this protection and instead attempt to charm the elemental (as <Link to="/spell/charm_monster">charm monster</Link>, Will DC 17 negates). If the charm attempt fails, however, absolute protection is lost and no further attempt at charming can be made.</p>
<p>Creatures from the plane to which the ring is attuned that attack the wearer take a -1 penalty on their attack rolls. The ring wearer makes applicable saving throws against the extraplanar creature's attacks with a +2 resistance bonus. She gains a +4 morale bonus on all attack rolls against such creatures. Any weapons he uses bypasses the damage reduction of such creatures, regardless of any qualities the weapon may or may not have.</p>
<p>The wearer of the ring is able to converse with creatures from the plane to which her ring is attuned. These creatures recognize that she wears the ring, and show a healthy respect for the wearer if their alignments are similar. If alignments are opposed, creatures fear the wearer if she is strong. If she is weak, they hate and desire to slay her.</p>
<p>The possessor of a ring of elemental command takes a saving throw penalty as follows.</p>
<ScrollContainer id="magic-ring-ring_of_elemental_command--table-0"><table>
<thead>
<tr>
<th>Element</th>
<th>Saving Throw Penalty</th>
</tr>
</thead>
<tbody><tr>
<td>Air</td>
<td>-2 against earth-based effects</td>
</tr>
<tr>
<td>Earth</td>
<td>-2 against air- or electricity-based effects</td>
</tr>
<tr>
<td>Fire</td>
<td>-2 against water- or cold-based effects</td>
</tr>
<tr>
<td>Water</td>
<td>-2 against fire-based effects</td>
</tr>
</tbody></table></ScrollContainer>
<p>In addition to the powers described above, each specific ring gives its wearer the following abilities according to its kind.</p>
<h3 id="magic-ring-ring_of_elemental_command-ring-of-elemental-command-air" data-hash-target>Ring of Elemental Command (Air)</h3>
<ul>
<li><Link to="/spell/wind_wall">Wind wall</Link> (unlimited use)</li>
<li><Link to="/spell/feather_fall">Feather fall</Link> (unlimited use, wearer only)</li>
<li><Link to="/spell/resist_energy">Resist energy</Link> (electricity) (unlimited use, wearer only)</li>
<li><Link to="/spell/gust_of_wind">Gust of wind</Link> (twice per day)</li>
<li><Link to="/spell/air_walk">Air walk</Link> (once per day, wearer only)</li>
<li><Link to="/spell/chain_lightning">Chain lightning</Link> (once per week)</li>
</ul>
<p>This ring appears to be a <Link to="/magic-ring/ring_of_feather_falling">ring of feather falling</Link> until a certain condition is met to activate its full potential. It must be reactivated each time a new wearer acquires it.</p>
<h3 id="magic-ring-ring_of_elemental_command-ring-of-elemental-command-earth" data-hash-target>Ring of Elemental Command (Earth)</h3>
<ul>
<li><Link to="/spell/soften_earth_and_stone">Soften earth and stone</Link> (unlimited use)</li>
<li><Link to="/spell/meld_into_stone">Meld into stone</Link> (unlimited use, wearer only)</li>
<li><Link to="/spell/stone_shape">Stone shape</Link> (twice per day)</li>
<li><Link to="/spell/wall_of_stone">Wall of stone</Link> (once per day)</li>
<li><Link to="/spell/stoneskin">Stoneskin</Link> (once per week, wearer only)</li>
<li><Link to="/spell/passwall">Passwall</Link> (twice per week)</li>
</ul>
<p>This ring appears to be a <em>ring of meld into stone</em> (allowing the wearer to cast <em>meld into stone</em> at will) until the established condition is met.</p>
<h3 id="magic-ring-ring_of_elemental_command-ring-of-elemental-command-fire" data-hash-target>Ring of Elemental Command (Fire)</h3>
<ul>
<li><Link to="/spell/resist_energy">Resist energy</Link> (fire) (as a <Link to="/magic-ring/major_ring_of_energy_resistance">major ring of energy resistance [fire]</Link>)</li>
<li><Link to="/spell/burning_hands">Burning hands</Link> (unlimited use)</li>
<li><Link to="/spell/flaming_sphere">Flaming sphere</Link> (twice per day)</li>
<li><Link to="/spell/pyrotechnics">Pyrotechnics</Link> (twice per day)</li>
<li><Link to="/spell/wall_of_fire">Wall of fire</Link> (once per day)</li>
<li><Link to="/spell/flame_strike">Flame strike</Link> (twice per week)</li>
</ul>
<p>This ring appears to be a major ring of energy resistance (fire) until the established condition is met.</p>
<h3 id="magic-ring-ring_of_elemental_command-ring-of-elemental-command-water" data-hash-target>Ring of Elemental Command (Water)</h3>
<ul>
<li><Link to="/spell/create_water">Create water</Link> (unlimited use)</li>
<li><Link to="/spell/water_breathing">Water breathing</Link> (unlimited use)</li>
<li><Link to="/spell/water_walk">Water walk</Link> (unlimited use)</li>
<li><Link to="/spell/wall_of_ice">Wall of ice</Link> (once per day)</li>
<li><Link to="/spell/ice_storm">Ice storm</Link> (twice per week)</li>
<li><Link to="/spell/control_water">Control water</Link> (twice per week)</li>
</ul>
<p>This ring appears to be a <Link to="/magic-ring/ring_of_water_walking">ring of water walking</Link> until the established condition is met.</p>
<h3 id="magic-ring-ring_of_elemental_command-construction" data-hash-target>Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/summon_monster_vi">summon monster VI</Link>, all appropriate spells; <strong>Cost</strong> 100,000 gp</p>
</>};
const _ring_of_spell_storing_major = {title: "Ring of Spell Storing (major)", jsx: <><h2 id="magic-ring-ring_of_spell_storing_major-ring-of-spell-storing-major">Ring of Spell Storing (major)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 174</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 479</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 17th<br/><strong>Slot</strong> ring; <strong>Price</strong> 200,000 gp; <strong>Weight</strong> -</p>
<p>As the <Link to="/magic-ring/ring_of_spell_storing">ring of spell storing</Link>, except it holds up to 10 levels of spells.</p>
<h3 id="magic-ring-ring_of_spell_storing_major-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/imbue_with_spell_ability">imbue with spell ability</Link>; <strong>Cost</strong> 100,000 gp</p>
</>};
const _wary_ring = {title: "Wary Ring", jsx: <><h2 id="magic-ring-wary_ring-wary-ring">Wary Ring</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 17</Link><br/><strong>Aura</strong> n/a; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Price</strong> 14,600 gp</p>
<p>This relatively plain brass <Link to="/magic-ring/ring_of_mind_shielding">ring of mind shielding</Link> can read script in any language. The personality within the ring is distrustful of everyone, and it pesters its wearer with increasingly elaborate conspiracy theories. Because of its unrelenting paranoia, the ring provides its wearer with occasional well-timed guidance and can use <em>timely inspiration</em> up to three times per day on the wearer.</p>
<h3 id="magic-ring-wary_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/nondetection">nondetection</Link>, <Link to="/spell/read_magic">read magic</Link>, <Link to="/spell/timely_inspiration">timely inspiration</Link>; <strong>Price</strong> 7,300 gp</p>
<h3 id="magic-ring-wary_ring-statistics">Statistics</h3>
<p><strong>Alignment</strong> lawful good; <strong>Ego</strong> 7<br/><strong>Senses</strong> 60 ft.<br/><strong>Int</strong> 12, <strong>Wis</strong> 15, <strong>Cha</strong> 12<br/><strong>Communication</strong> empathy</p>
</>};
const _ring_of_the_weary_sky = {title: "Ring of the Weary Sky", jsx: <><h2 id="magic-ring-ring_of_the_weary_sky-ring-of-the-weary-sky">Ring of the Weary Sky</h2>
<p><strong>Sources</strong> <Link to="/source/lost_treasures">Lost Treasures pg. 49</Link><br/><strong>Aura</strong> moderate abjuration and enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> ring; <strong>Price</strong> 14,800 gp</p>
<p>This ancient silver ring provides a measure of control over elemental creatures. The spirit of an ancient Jistkan elementalist still echoes within the ring, issuing a sense of smug arrogance. The Ring of the Weary Sky's <Link to="/rule/special_purpose_items">special purpose</Link> is controlling or defeating elementals, and once per day the wearer can attempt to charm a creature with the elemental subtype (as <em>charm monster,</em> Will DC 15 negates).</p>
<p>Once per day, the ring can affect its wearer with <em>resist energy.</em> The ring uses this ability only when the wearer faces a hostile creature with the elemental subtype, making an educated guess about the most applicable energy type against which to ward its wearer. The ring is quick to provide this protection when the wearer tries but fails to charm an elemental creature, exuding a clear impression of patronizing disappointment.</p>
<h3 id="magic-ring-ring_of_the_weary_sky-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/charm_monster">charm monster</Link>, <Link to="/spell/resist_energy">resist energy</Link>; <strong>Price</strong> 7,400 gp</p>
<h3 id="magic-ring-ring_of_the_weary_sky-statistics">Statistics</h3>
<p><strong>Alignment</strong> neutral; <strong>Ego</strong> 7<br/><strong>Senses</strong> 30 ft.<br/><strong>Int</strong> 12, <strong>Wis</strong> 10, <strong>Cha</strong> 11<br/><strong>Communication</strong> empathy</p>
</>};
const _obsession_ring = {title: "Obsession Ring", jsx: <><h2 id="magic-ring-obsession_ring-obsession-ring">Obsession Ring</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 359</Link></p>
<p><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 116,500 gp</p>
<p>These <Link to="/magic-ring/ring_of_protection_3">rings of protection +3</Link> are extremely varied in form. They can be of any alignment and each has its own unique personality and proclivities. Each ring has a specific obsession. To determine a particular obsession ring's obsession, roll on <Link to="/rule/special_purpose_items">Table 15-25: Intelligent Item Purpose</Link>. When the ring is in pursuit of its purpose, its Ego is 10 points higher than normal.</p>
<p><Link to="/race/gnome">Gnomes</Link> with the obsession racial trait have a unique understanding of the ring's mentality and gain a +5 bonus on Will saving throws to resist the obsession ring's attempts to dominate the wearer.</p>
<p>When an obsession ring is engaged in action directly related to its obsession, it grants its wearer the following powers, but can choose to withhold such powers if it does not believe their uses would further its obsession.</p>
<ul>
<li>The ring functions as a <Link to="/magic-ring/ring_of_protection_5">ring of protection +5</Link>.</li>
<li>The ring grants its wearer a +2 luck bonus on attack rolls against creatures its obsession is sworn to defeat.</li>
<li>Three times per day, the ring can allow its wearer to reroll any saving throw. The wearer gains a +4 luck bonus on the saving throw reroll.</li>
</ul>
<p>These rings are typically quite emphatic on their desire to fulfill their obsessions, and frequently communicate with their wielder to encourage pursuit of this goal.</p>
<h3 id="magic-ring-obsession_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/forge_ring">Forge Ring</Link>, <Link to="/spell/shield_of_faith">shield of faith</Link>, creator must be 15th level (or 9th level if the creator is a gnome); <strong>Price</strong> 58,250 gp</p>
<h3 id="magic-ring-obsession_ring-statistics">Statistics</h3>
<p><strong>Alignment</strong> varies; <strong>Ego</strong> 11<br/><strong>Senses</strong> 30 ft.<br/><strong>Int</strong> 17, <strong>Wis</strong> 10, <strong>Cha</strong> 13<br/><strong>Communication</strong> telepathy (Common and seven other languages)</p>
</>};
const _cannibal_ring = {title: "Cannibal Ring", jsx: <><h2 id="magic-ring-cannibal_ring-cannibal-ring">Cannibal Ring</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 344</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 310</Link></p>
<p><strong>Aura</strong> strong transmutation; <strong>CL</strong> 16th<br/><strong>Slot</strong> ring; <strong>Weight</strong> -</p>
<p>This simple and unadorned copper ring appears slightly tarnished, but seemingly wards off the effects of hunger or other sorts of deprivation; all tests reveal it to be a ring of sustenance. However, after wearing it for 7 days, its owner instead comes to suffer from almost constant hunger and thirst, which, if not sated, ultimately drives him mad enough to become a cannibal. The wearer must eat and drink a full day's worth of food and water each hour to avoid making a starvation or thirst check. Once the wearer starts to take lethal damage instead of nonlethal damage due to failed checks, he begins to experience ever more powerful cravings for the flesh of intelligent creatures (any living creature with an Intelligence of 3 or higher).</p>
<p>Once the wearer feasts in such a manner, he recovers all nonlethal damage sustained from hunger and thirst, though he continues to suffer lethal damage on failed starvation and thirst checks. The next time he is in a situation in which he could eat part of an intelligent being, he must make a DC 15 Will save or dine on the forbidden meat. If the wearer succumbs to this urge again, he recovers all lethal damage from failed starvation and thirst checks, and realizes cannibalism is the key to avoiding the increased hunger and thirst - on any day he eats at least one meal of flesh from an intelligent creature, he does not have to make hourly starvation and thirst checks, and recovers any accumulated damage from failing these checks. Once its curse activates, the ring cannot be removed until the curse is broken.</p>
<h3 id="magic-ring-cannibal_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-ring/ring_of_sustenance">ring of sustenance</Link>; <strong>Cost</strong> -</p>
</>};
const _chatter_ring = {title: "Chatter Ring", jsx: <><h2 id="magic-ring-chatter_ring-chatter-ring">Chatter Ring</h2>
<p><strong>Sources</strong> <Link to="/source/antiheros_handbook">Antihero's Handbook pg. 31</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> ring; <strong>Weight</strong> -</p>
<p>This ring appears as a normal ring of eloquence, with four different languages (usually Common, Dwarven, Elven, and Gnome) etched around the inside of a silver band, and the wearer of a chatter ring gains the ability to speak the four languages inscribed in the ring. However, the difference between a chatter ring and a normal ring of eloquence quickly becomes apparent when the wearer speaks, as he becomes overwhelmingly talkative. The wearer takes a -2 penalty on Bluff, Diplomacy, Disguise, Perform (oratory), and Stealth checks. The ring can be removed only after the wearer benefits from a <Link to="/spell/remove_curse">remove curse</Link> spell or similar effect.</p>
<h3 id="magic-ring-chatter_ring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-ring/ring_of_eloquence">ring of eloquence</Link>; <strong>Cost</strong> -</p>
</>};
const _ring_of_clumsiness = {title: "Ring of Clumsiness", jsx: <><h2 id="magic-ring-ring_of_clumsiness-ring-of-clumsiness">Ring of Clumsiness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 349</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 542</Link></p>
<p><strong>Aura</strong> strong transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> ring; <strong>Weight</strong> -</p>
<p>This ring operates exactly like a ring of feather falling. However, it also makes the wearer clumsy. She takes a -4 penalty to Dexterity and has a 20% chance of spell failure when trying to cast any arcane spell that has a somatic component. (This chance of spell failure stacks with other arcane spell failure chances.)</p>
<h3 id="magic-ring-ring_of_clumsiness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-ring/ring_of_feather_falling">ring of feather falling</Link>; <strong>Cost</strong> -</p>
</>};
const _ring_of_lifebleed = {title: "Ring of Lifebleed", jsx: <><h2 id="magic-ring-ring_of_lifebleed-ring-of-lifebleed">Ring of Lifebleed</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 349</Link></p>
<p><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 10th<br/><strong>Slot</strong> ring; <strong>Weight</strong> -</p>
<p>Before being worn, this ring appears to be a ring of regeneration. Once it is worn in combat, however, the true nature of the ring becomes apparent. Each time the wearer is hit with a melee or ranged weapon attack, he takes an additional 1d4 points of damage. This ring cannot be removed until the wearer dies or by way of a <Link to="/spell/remove_curse">remove curse</Link>, <Link to="/spell/wish">wish</Link>, or <Link to="/spell/miracle">miracle</Link> spell.</p>
<h3 id="magic-ring-ring_of_lifebleed-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-ring/ring_of_regeneration">ring of regeneration</Link>; <strong>Cost</strong> -</p>
</>};
const _ring_of_spell_devouring = {title: "Ring of Spell Devouring", jsx: <><h2 id="magic-ring-ring_of_spell_devouring-ring-of-spell-devouring">Ring of Spell Devouring</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 349</Link></p>
<p><strong>Aura</strong> strong abjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> ring; <strong>Weight</strong> -</p>
<p>This delicate ring appears to be a ring of spell storing or a ring of spell turning, but instead of aiding casting or counterspelling, the ring hinders such efforts. Each time the wearer casts an arcane spell, he suffers a 25% spell failure chance. Furthermore, the wearer of the ring takes a -4 penalty on <Link to="/skill/spellcraft">Spellcraft</Link> checks to identify a spell when attempting to <Link to="/rule/counterspells">counterspell</Link>. The ring can only be removed by a <Link to="/spell/remove_curse">remove curse</Link> spell or a similar effect.</p>
<h3 id="magic-ring-ring_of_spell_devouring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-ring/ring_of_spell_storing">ring of spell storing (any)</Link> or a <Link to="/magic-ring/ring_of_spell_turning">ring of spell turning</Link>; <strong>Cost</strong> -</p>
</>};
const _ring_of_truth = {title: "Ring of Truth", jsx: <><h2 id="magic-ring-ring_of_truth-ring-of-truth">Ring of Truth</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 349</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 310</Link></p>
<p><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 9th<br/><strong>Slot</strong> ring; <strong>Weight</strong> -</p>
<p>Deceptively pleasant-looking, a ring of truth bears images of childlike angels and broadly smiling divine creatures holding onto links of a heavy chain. The wearer of this cursed ring is rendered unable to tell a deliberate lie, in either speech or writing. The wearer may simply omit the truth or choose not to communicate, but even then must succeed at a DC 20 Will saving throw to avoid answering a direct question truthfully. The wearer cannot remove the ring unless the magic of the curse is negated.</p>
<h3 id="magic-ring-ring_of_truth-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-ring/ring_of_mind_shielding">ring of mind shielding</Link>, <Link to="/magic-ring/ring_of_x_ray_vision">ring of x-ray vision</Link>; <strong>Cost</strong> -</p>
</>};
